{
  "name": "IntelBoard",
  "description": "A professional investigation storyboard tool for connecting events, people, and evidence with AI-assisted analysis."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum NodeType {
  EVENT = 'eventNode',
  PERSON = 'personNode',
}

export interface NodeData {
  label: string;
  date?: string;
  evidenceSource?: string;
  notes?: string;
  details?: string;
}

export interface AnalysisResult {
  summary: string;
  gaps: string[];
  connections: string[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { Node, Edge } from '@xyflow/react';

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeBoard = async (nodes: Node[], edges: Edge[]) => {
  try {
    const boardData = {
      nodes: nodes.map(n => ({
        type: n.type,
        data: n.data,
        id: n.id
      })),
      edges: edges.map(e => ({
        source: e.source,
        target: e.target,
        label: e.label || 'related to'
      }))
    };

    const prompt = `
      Act as a senior lead detective or intelligence analyst. 
      Analyze the following investigation board data (nodes represent people or events, edges represent connections).

      Provide a structured analysis containing:
      1. A brief executive summary of the timeline/network.
      2. Identification of missing intelligence or gaps (what questions should we ask next?).
      3. Key inferred connections that might not be explicitly drawn but are implied by the data.

      Data: ${JSON.stringify(boardData)}
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING },
            gaps: { 
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
            connections: { 
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          }
        }
      }
    });

    const text = response.text;
    if (!text) return null;
    return JSON.parse(text);

  } catch (error) {
    console.error("Analysis failed:", error);
    throw error;
  }
};

