  ReactFlow,
  ReactFlowProvider,
  addEdge,
  useNodesState,
  useEdgesState,
  Controls,
  Background,
  Connection,
  Edge,
  Node,
  BackgroundVariant,
  useReactFlow,
  Panel,
} from '@xyflow/react';

import { Sidebar } from './components/Sidebar';
import { EditorPanel } from './components/EditorPanel';
import { EventNode, PersonNode } from './components/CustomNodes';
import { NodeType, AnalysisResult } from './types';
import { analyzeBoard } from './services/geminiService';
import { BrainCircuit, Loader2, Sparkles, AlertTriangle, Link2 } from 'lucide-react';

// Define custom node types outside component to prevent re-creation
const nodeTypes = {
  [NodeType.EVENT]: EventNode,
  [NodeType.PERSON]: PersonNode,
};

let id = 100;
const getId = () => `dndnode_${id++}`;

const InvestigationCanvas = () => {
  const reactFlowWrapper = useRef<HTMLDivElement>(null);
  const [nodes, setNodes, onNodesChange] = useNodesState([
    {
      id: '1',
      type: NodeType.EVENT,
      position: { x: 400, y: 100 },
      data: { label: 'Harbor Incident', date: '2023-11-04 23:00', evidenceSource: 'Police Report #9921' },
    },
    {
      id: '2',
      type: NodeType.PERSON,
      position: { x: 700, y: 300 },
      data: { label: 'Alex "The Rook" Mercer', date: '2023-11-05', evidenceSource: 'Informant Tip' },
    },
    {
      id: '3',
      type: NodeType.EVENT,
      position: { x: 400, y: 450 },
      data: { label: 'Safehouse Raid', date: '2023-11-06 04:00', evidenceSource: 'Tactical Team Log' },
    },
  ]);
  const [edges, setEdges, onEdgesChange] = useEdgesState([
    { id: 'e1-2', source: '1', target: '2', label: 'Suspect spotted', animated: true, style: { stroke: '#64748b', strokeWidth: 2 } },
    { id: 'e2-3', source: '2', target: '3', label: 'Fled to', animated: true, style: { stroke: '#64748b', strokeWidth: 2 } },
  ]);
  const { screenToFlowPosition } = useReactFlow();

  const [selectedNode, setSelectedNode] = useState<Node | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);

  const onConnect = useCallback(
    (params: Connection) => setEdges((eds) => addEdge({ ...params, type: 'default', animated: true, style: { stroke: '#64748b', strokeWidth: 2 } }, eds)),
    [setEdges],
  );

  const onDragOver = useCallback((event: React.DragEvent) => {
    event.preventDefault();
    event.dataTransfer.dropEffect = 'move';
  }, []);

  const onDrop = useCallback(
    (event: React.DragEvent) => {
      event.preventDefault();

      const type = event.dataTransfer.getData('application/reactflow') as NodeType;
      if (typeof type === 'undefined' || !type) {
        return;
      }

      const position = screenToFlowPosition({
        x: event.clientX,
        y: event.clientY,
      });

      const newNode: Node = {
        id: getId(),
        type,
        position,
        data: { label: `New ${type === NodeType.EVENT ? 'Event' : 'Person'}`, date: '', evidenceSource: '' },
      };

      setNodes((nds) => nds.concat(newNode));

      // Auto-select new node
      setSelectedNode(newNode);
    },
    [screenToFlowPosition, setNodes],
  );

  const onNodeClick = useCallback((_: React.MouseEvent, node: Node) => {
    setSelectedNode(node);
  }, []);

  const onPaneClick = useCallback(() => {
    setSelectedNode(null);
  }, []);

  const handleDeleteNode = useCallback((id: string) => {
    setNodes((nds) => nds.filter((n) => n.id !== id));
    setEdges((eds) => eds.filter((e) => e.source !== id && e.target !== id));
    setSelectedNode(null);
  }, [setNodes, setEdges]);

  const handleAnalysis = async () => {
    if (nodes.length === 0) return;
    setIsAnalyzing(true);
    setAnalysis(null);
    try {
      const result = await analyzeBoard(nodes, edges);
      setAnalysis(result);
    } catch (e) {
      console.error(e);
      alert("Analysis failed. Please check your API configuration.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div className="flex h-screen w-full bg-slate-950 text-slate-200 font-sans selection:bg-amber-500/30">
      <Sidebar />

      <div className="flex-1 h-full relative" ref={reactFlowWrapper}>
        <ReactFlow
          nodes={nodes}
          edges={edges}
          onNodesChange={onNodesChange}
          onEdgesChange={onEdgesChange}
          onConnect={onConnect}
          onDrop={onDrop}
          onDragOver={onDragOver}
          onNodeClick={onNodeClick}
          onPaneClick={onPaneClick}
          nodeTypes={nodeTypes}
          fitView
          className="bg-slate-950"
        >
          <Controls className="!bg-slate-800 !border-slate-700 !fill-slate-400 [&>button]:!border-slate-700 hover:[&>button]:!bg-slate-700" />
          <Background color="#1e293b" gap={20} variant={BackgroundVariant.Dots} />

          <Panel position="top-right" className="flex flex-col gap-4">
            <button 
              onClick={handleAnalysis}
              disabled={isAnalyzing || nodes.length === 0}
              className={`
                flex items-center gap-2 px-4 py-2 rounded-lg font-medium text-sm shadow-lg transition-all
                ${isAnalyzing 
                  ? 'bg-slate-800 text-slate-400 cursor-wait' 
                  : 'bg-amber-600 hover:bg-amber-500 text-white hover:scale-105 active:scale-95'}
              `}
            >
              {isAnalyzing ? (
                <><Loader2 className="w-4 h-4 animate-spin" /> Processing Intel...</>
              ) : (
                <><BrainCircuit className="w-4 h-4" /> Analyze Case</>
              )}
            </button>
          </Panel>
        </ReactFlow>

        <EditorPanel 
          selectedNode={selectedNode} 
          setNodes={setNodes} 
          onClose={() => setSelectedNode(null)}
          deleteNode={handleDeleteNode}
        />

        {/* Analysis Result Overlay */}
        {analysis && !isAnalyzing && (
          <div className="absolute bottom-6 left-6 right-6 md:left-20 md:right-auto md:w-[500px] bg-slate-900/95 backdrop-blur border border-amber-500/30 rounded-xl shadow-2xl p-6 animate-slide-in-bottom z-50 max-h-[40vh] overflow-y-auto">
            <div className="flex justify-between items-start mb-4">
              <h3 className="text-lg font-bold text-amber-500 flex items-center gap-2">
                <Sparkles className="w-5 h-5" /> Intelligence Summary
              </h3>
              <button 
                onClick={() => setAnalysis(null)}
                className="text-slate-500 hover:text-slate-300"
              >
                <span className="sr-only">Close</span>
                ✕
              </button>
            </div>

            <div className="space-y-4 text-sm text-slate-300">
              <div className="bg-slate-800/50 p-3 rounded border border-slate-700">
                <p className="leading-relaxed">{analysis.summary}</p>
              </div>

              {analysis.gaps.length > 0 && (
                <div>
                  <h4 className="font-semibold text-slate-200 mb-2 flex items-center gap-2">
                    <AlertTriangle className="w-4 h-4 text-red-400" /> Missing Intel / Gaps
                  </h4>
                  <ul className="list-disc pl-5 space-y-1 text-slate-400">
                    {analysis.gaps.map((gap, i) => (
                      <li key={i}>{gap}</li>
                    ))}
                  </ul>
                </div>
              )}

              {analysis.connections.length > 0 && (
                <div>
                  <h4 className="font-semibold text-slate-200 mb-2 flex items-center gap-2">
                    <Link2 className="w-4 h-4 text-blue-400" /> Inferred Connections
                  </h4>
                  <ul className="list-disc pl-5 space-y-1 text-slate-400">
                    {analysis.connections.map((conn, i) => (
                      <li key={i}>{conn}</li>
                    ))}
                  </ul>
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

// Wrap in Provider to access ReactFlow hooks
export default function App() {
  return (
    <ReactFlowProvider>
      <InvestigationCanvas />
    </ReactFlowProvider>
  );
}

import React, { useEffect, useState } from 'react';
import { Node } from '@xyflow/react';
import { NodeData } from '../types';
import { X, Save, Trash2 } from 'lucide-react';

interface EditorPanelProps {
  selectedNode: Node | null;
  setNodes: (updater: (nodes: Node[]) => Node[]) => void;
  onClose: () => void;
  deleteNode: (id: string) => void;
}

export const EditorPanel: React.FC<EditorPanelProps> = ({ selectedNode, setNodes, onClose, deleteNode }) => {
  const [formData, setFormData] = useState<NodeData>({
    label: '',
    date: '',
    evidenceSource: '',
  });

  useEffect(() => {
    if (selectedNode) {
      setFormData({
        label: selectedNode.data.label as string || '',
        date: (selectedNode.data.date as string) || '',
        evidenceSource: (selectedNode.data.evidenceSource as string) || '',
      });
    }
  }, [selectedNode]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));

    // Live update the node
    setNodes((nds) => 
      nds.map((node) => {
        if (node.id === selectedNode?.id) {
          return {
            ...node,
            data: {
              ...node.data,
              [name]: value,
            },
          };
        }
        return node;
      })
    );
  };

  if (!selectedNode) return null;

  return (
    <div className="absolute right-4 top-4 w-80 bg-slate-900 border border-slate-700 rounded-xl shadow-2xl overflow-hidden flex flex-col animate-slide-in-right z-50">
      <div className="p-4 border-b border-slate-800 flex justify-between items-center bg-slate-800/50">
        <h2 className="font-semibold text-slate-100 flex items-center gap-2">
          Details: <span className="text-amber-500 uppercase text-xs border border-amber-500/30 px-1.5 py-0.5 rounded">{selectedNode.type}</span>
        </h2>
        <button onClick={onClose} className="text-slate-400 hover:text-white transition-colors">
          <X className="w-5 h-5" />
        </button>
      </div>

      <div className="p-4 space-y-4">
        <div>
          <label className="block text-xs font-medium text-slate-400 mb-1.5 uppercase tracking-wide">Title / Name</label>
          <input
            type="text"
            name="label"
            value={formData.label}
            onChange={handleChange}
            className="w-full bg-slate-950 border border-slate-700 rounded-md px-3 py-2 text-sm text-slate-100 focus:outline-none focus:border-amber-500 transition-colors placeholder:text-slate-600"
            placeholder="e.g. Incident at Wharf"
          />
        </div>

        <div>
          <label className="block text-xs font-medium text-slate-400 mb-1.5 uppercase tracking-wide">Date & Time</label>
          <input
            type="text"
            name="date"
            value={formData.date}
            onChange={handleChange}
            className="w-full bg-slate-950 border border-slate-700 rounded-md px-3 py-2 text-sm text-slate-100 focus:outline-none focus:border-amber-500 transition-colors placeholder:text-slate-600"
            placeholder="YYYY-MM-DD HH:MM"
          />
        </div>

        <div>
          <label className="block text-xs font-medium text-slate-400 mb-1.5 uppercase tracking-wide">Evidence Source</label>
          <textarea
            name="evidenceSource"
            value={formData.evidenceSource}
            onChange={handleChange}
            rows={3}
            className="w-full bg-slate-950 border border-slate-700 rounded-md px-3 py-2 text-sm text-slate-100 focus:outline-none focus:border-amber-500 transition-colors placeholder:text-slate-600 resize-none"
            placeholder="e.g. Witness Testimony #402, CCTV Footage"
          />
        </div>

        <div className="pt-4 mt-2 border-t border-slate-800 flex justify-between">
           <button 
             onClick={() => deleteNode(selectedNode.id)}
             className="flex items-center gap-2 px-3 py-2 rounded-md bg-red-900/20 text-red-400 text-sm hover:bg-red-900/40 transition-colors border border-red-900/50"
           >
            <Trash2 className="w-4 h-4" />
            Delete
           </button>

           <button 
             onClick={onClose}
             className="flex items-center gap-2 px-4 py-2 rounded-md bg-slate-800 text-slate-200 text-sm hover:bg-slate-700 transition-colors"
           >
            <Save className="w-4 h-4" />
            Done
           </button>
        </div>
      </div>
    </div>
  );
};

