Can we add these?

Excellent progress! You're now moving from "AI-assisted analysis" to "deterministic investigative logic" - this is exactly what makes professional investigative software reliable and court-admissible.

Let me show you how to integrate your local analysis engine into the existing canvas so you get real-time investigative insights without any API calls.

## 1. First, Let's Create the Local Analysis Service

**File: `services/localAnalysis.ts`**

```typescript
import { Node, Edge } from '@xyflow/react';
import { NodeType } from '../types';

export interface LocalAnalysisResult {
  redFlags: RedFlag[];
  ringleader?: {
    id: string;
    label: string;
    connectionCount: number;
  };
  timelineGaps: TimelineGap[];
  financialPatterns: FinancialPattern[];
  geographicalClusters: GeographicalCluster[];
}

export interface RedFlag {
  type: 'DUPLICATE_ID' | 'TIMELINE_ANOMALY' | 'ISOLATED_SUBJECT' | 
        'FINANCIAL_SUSPICIOUS' | 'GEOGRAPHICAL_IMPLAUSIBLE';
  severity: 'HIGH' | 'MEDIUM' | 'LOW';
  message: string;
  affectedNodeIds: string[];
  evidence?: string;
}

export interface TimelineGap {
  nodeId: string;
  message: string;
  suggestion: string;
}

export interface FinancialPattern {
  type: 'LARGE_TRANSACTION' | 'FREQUENT_TRANSFERS' | 'SUSPECT_AMOUNT';
  description: string;
  amount?: number;
  nodeIds: string[];
}

export interface GeographicalCluster {
  location: string;
  nodes: string[];
  suggestion: string;
}

// Main analysis function
export const runLocalAnalysis = (nodes: Node[], edges: Edge[]): LocalAnalysisResult => {
  const result: LocalAnalysisResult = {
    redFlags: [],
    timelineGaps: [],
    financialPatterns: [],
    geographicalClusters: []
  };

  // Create lookup maps
  const identifierMap = new Map<string, string[]>(); // BVN/NIN/Phone -> Node IDs
  const locationMap = new Map<string, string[]>();   // Location -> Node IDs
  const nodeById = new Map<string, Node>();

  nodes.forEach(node => {
    nodeById.set(node.id, node);
    const data = node.data;

    // RULE 1: Duplicate Identifiers (Critical for Nigeria - BVN/NIN Fraud)
    if (data.identifier) {
      const existing = identifierMap.get(data.identifier) || [];
      if (existing.length > 0) {
        result.redFlags.push({
          type: 'DUPLICATE_ID',
          severity: 'HIGH',
          message: `Identity Fraud Alert: ${existing.length + 1} entities share identifier ${data.identifier}`,
          affectedNodeIds: [...existing, node.id],
          evidence: `Possible identity theft or shell company. Check CAC registration for ${data.identifier}`
        });
      }
      identifierMap.set(data.identifier, [...existing, node.id]);
    }

    // RULE 2: Timeline Analysis
    if (node.type === NodeType.EVENT && !data.date) {
      result.timelineGaps.push({
        nodeId: node.id,
        message: `Event "${data.label}" has no timestamp`,
        suggestion: "Check CCTV metadata or witness statements for exact time"
      });
    }

    // RULE 3: Financial Pattern Detection (EFCC-style)
    if (data.amount) {
      const amount = parseFloat(data.amount.toString());
      if (amount > 5000000) { // ₦5M threshold
        result.financialPatterns.push({
          type: 'LARGE_TRANSACTION',
          description: `Large transaction: ₦${amount.toLocaleString('en-NG')}`,
          amount: amount,
          nodeIds: [node.id]
        });
      }

      // Suspicious amount patterns (common in Nigerian fraud)
      if ([1000000, 5000000, 10000000].includes(amount)) {
        result.redFlags.push({
          type: 'FINANCIAL_SUSPICIOUS',
          severity: 'MEDIUM',
          message: `Round-figure transaction (₦${amount.toLocaleString('en-NG')}) - common in bribery schemes`,
          affectedNodeIds: [node.id]
        });
      }
    }

    // RULE 4: Location Analysis
    if (data.location) {
      const locNodes = locationMap.get(data.location) || [];
      locationMap.set(data.location, [...locNodes, node.id]);
    }
  });

  // RULE 5: Geographical Analysis - Nigerian context
  locationMap.forEach((nodeIds, location) => {
    if (nodeIds.length >= 2) {
      result.geographicalClusters.push({
        location,
        nodes: nodeIds,
        suggestion: `${nodeIds.length} events in ${location}. Check for local accomplices or safe houses.`
      });
    }
  });

  // RULE 6: Isolated Subjects (Dead-end in investigation)
  nodes.filter(n => n.type === NodeType.PERSON).forEach(person => {
    const hasLinks = edges.some(e => e.source === person.id || e.target === person.id);
    if (!hasLinks) {
      result.redFlags.push({
        type: 'ISOLATED_SUBJECT',
        severity: 'MEDIUM',
        message: `Investigation Gap: ${person.data.label} has no recorded connections`,
        affectedNodeIds: [person.id],
        evidence: "Interview subject or check alternative contact methods"
      });
    }
  });

  // RULE 7: Calculate Ringleader (Network Centrality)
  if (nodes.length > 0) {
    const connections = new Map<string, number>();
    nodes.forEach(node => {
      const count = edges.filter(e => e.source === node.id || e.target === node.id).length;
      connections.set(node.id, count);
    });

    const sorted = [...connections.entries()].sort((a, b) => b[1] - a[1]);
    if (sorted[0] && sorted[0][1] > 0) {
      const ringleaderNode = nodeById.get(sorted[0][0]);
      if (ringleaderNode) {
        result.ringleader = {
          id: ringleaderNode.id,
          label: ringleaderNode.data.label,
          connectionCount: sorted[0][1]
        };
      }
    }
  }

  // RULE 8: Travel Time Impossibility (Nigeria-specific)
  const events = nodes.filter(n => n.type === NodeType.EVENT);
  for (let i = 0; i < events.length; i++) {
    for (let j = i + 1; j < events.length; j++) {
      const e1 = events[i];
      const e2 = events[j];

      if (e1.data.date && e2.data.date && 
          e1.data.location && e2.data.location &&
          e1.data.location !== e2.data.location) {

        const date1 = new Date(e1.data.date);
        const date2 = new Date(e2.data.date);
        const timeDiff = Math.abs(date2.getTime() - date1.getTime()) / (1000 * 60); // minutes

        if (timeDiff < 120) { // Less than 2 hours between events
          // Check if locations are far apart (e.g., Lagos to Abuja)
          const isLongDistance = isLongDistanceTravel(e1.data.location, e2.data.location);
          if (isLongDistance) {
            result.redFlags.push({
              type: 'GEOGRAPHICAL_IMPLAUSIBLE',
              severity: 'HIGH',
              message: `Impossible travel: ${e1.data.location} to ${e2.data.location} in ${timeDiff.toFixed(0)} minutes`,
              affectedNodeIds: [e1.id, e2.id],
              evidence: "Check flight records or verify alibi"
            });
          }
        }
      }
    }
  }

  return result;
};

// Helper function for Nigerian geography
const isLongDistanceTravel = (loc1: string, loc2: string): boolean => {
  const longDistancePairs = [
    ['Lagos', 'Abuja'], ['Port Harcourt', 'Kano'], ['Ibadan', 'Maiduguri'],
    ['Enugu', 'Sokoto'], ['Benin', 'Jos']
  ];

  return longDistancePairs.some(pair => 
    (pair.includes(loc1) && pair.includes(loc2)) ||
    (pair.includes(loc2) && pair.includes(loc1))
  );
};
```

## 2. Now Let's Integrate It Into Your InvestigationCanvas

**Update your `App.tsx` or `InvestigationCanvas.tsx`:**

```typescript
// Add these imports
import { runLocalAnalysis, LocalAnalysisResult } from './services/localAnalysis';

// Add this state variable
const [localAnalysis, setLocalAnalysis] = useState<LocalAnalysisResult | null>(null);

// Add this effect to run analysis automatically when board changes
useEffect(() => {
  if (nodes.length > 0) {
    const analysis = runLocalAnalysis(nodes, edges);
    setLocalAnalysis(analysis);
  }
}, [nodes, edges]); // Runs whenever nodes or edges change

// Add a new panel for local analysis
{localAnalysis && (
  <div className="absolute top-20 right-4 w-80 bg-slate-900/95 border border-slate-700 rounded-lg p-4 shadow-xl z-40">
    <div className="flex items-center gap-2 mb-3">
      <ShieldAlert className="w-5 h-5 text-amber-500" />
      <h3 className="font-bold text-slate-200">Local Intelligence</h3>
      <span className="ml-auto text-xs bg-slate-800 px-2 py-1 rounded">
        {localAnalysis.redFlags.filter(f => f.severity === 'HIGH').length} 🔴
      </span>
    </div>

    {/* Ringleader */}
    {localAnalysis.ringleader && (
      <div className="mb-3 p-3 bg-slate-800/50 rounded border border-blue-500/30">
        <div className="flex items-center gap-2 text-blue-400 text-sm font-semibold mb-1">
          <Crown className="w-4 h-4" />
          Key Person of Interest
        </div>
        <div className="text-slate-300">
          <div className="font-medium">{localAnalysis.ringleader.label}</div>
          <div className="text-xs text-slate-400">
            Connected to {localAnalysis.ringleader.connectionCount} entities
          </div>
        </div>
      </div>
    )}

    {/* Red Flags */}
    {localAnalysis.redFlags.slice(0, 3).map((flag, idx) => (
      <div key={idx} className={`mb-2 p-2 rounded border text-sm ${
