                </div>
                <div className="text-xs text-slate-500 mt-2">{cluster.suggestion}</div>
              </div>
            ))}
          </div>
        </section>
      )}

      {/* Timeline Gaps */}
      {localAnalysis.timelineGaps.length > 0 && (
        <section>
          <h3 className="text-lg font-semibold text-slate-200 mb-3">
            Timeline Gaps ({localAnalysis.timelineGaps.length})
          </h3>
          <div className="space-y-2">
            {localAnalysis.timelineGaps.map((gap, idx) => {
              const node = nodes.find(n => n.id === gap.nodeId);
              return (
                <div key={idx} className="p-3 bg-slate-800/30 rounded">
                  <div className="text-slate-300">{gap.message}</div>
                  <div className="text-sm text-slate-500 mt-1">
                    <span className="text-slate-400">Suggestion:</span> {gap.suggestion}
                  </div>
                </div>
              );
            })}
          </div>
        </section>
      )}
    </div>
  </div>
)}
