export interface FinancialPattern {
  type: 'LARGE_TRANSACTION' | 'FREQUENT_TRANSFERS' | 'SUSPECT_AMOUNT';
  description: string;
  amount?: number;
  nodeIds: string[];
}

export interface GeographicalCluster {
  location: string;
  nodes: string[];
  suggestion: string;
}

// Main analysis function
export const runLocalAnalysis = (nodes: Node[], edges: Edge[]): LocalAnalysisResult => {
  const result: LocalAnalysisResult = {
    redFlags: [],
    timelineGaps: [],
    financialPatterns: [],
    geographicalClusters: []
  };

  // Create lookup maps
  const identifierMap = new Map<string, string[]>(); // BVN/NIN/Phone -> Node IDs
  const locationMap = new Map<string, string[]>();   // Location -> Node IDs
  const nodeById = new Map<string, Node>();

  nodes.forEach(node => {
    nodeById.set(node.id, node);
    const data = node.data;

    // RULE 1: Duplicate Identifiers (Critical for Nigeria - BVN/NIN Fraud)
    if (data.identifier) {
      const existing = identifierMap.get(data.identifier as string) || [];
      if (existing.length > 0) {
        result.redFlags.push({
          type: 'DUPLICATE_ID',
          severity: 'HIGH',
          message: `Identity Fraud Alert: ${existing.length + 1} entities share identifier ${data.identifier}`,
          affectedNodeIds: [...existing, node.id],
          evidence: `Possible identity theft or shell company. Check CAC registration for ${data.identifier}`
        });
      }
      identifierMap.set(data.identifier as string, [...existing, node.id]);
    }

    // RULE 2: Timeline Analysis
    if (node.type === NodeType.EVENT && !data.date) {
      result.timelineGaps.push({
        nodeId: node.id,
        message: `Event "${data.label}" has no timestamp`,
        suggestion: "Check CCTV metadata or witness statements for exact time"
      });
    }

    // RULE 3: Financial Pattern Detection (EFCC-style)
    if (data.amount) {
      const amount = parseFloat(data.amount.toString());
      if (amount > 5000000) { // ₦5M threshold
        result.financialPatterns.push({
          type: 'LARGE_TRANSACTION',
          description: `Large transaction: ₦${amount.toLocaleString('en-NG')}`,
          amount: amount,
          nodeIds: [node.id]
        });
      }

      // Suspicious amount patterns (common in Nigerian fraud)
      if ([1000000, 5000000, 10000000].includes(amount)) {
        result.redFlags.push({
          type: 'FINANCIAL_SUSPICIOUS',
          severity: 'MEDIUM',
          message: `Round-figure transaction (₦${amount.toLocaleString('en-NG')}) - common in bribery schemes`,
          affectedNodeIds: [node.id]
        });
      }
    }

    // RULE 4: Location Analysis
    if (data.location) {
      const existing = locationMap.get(data.location as string) || [];
      locationMap.set(data.location as string, [...existing, node.id]);
    }
  });

  // RULE 5: Geographical Analysis - Nigerian context
  locationMap.forEach((nodeIds, location) => {
    if (nodeIds.length >= 2) {
      result.geographicalClusters.push({
        location,
        nodes: nodeIds,
        suggestion: `${nodeIds.length} events in ${location}. Check for local accomplices or safe houses.`
      });
    }
  });

  // RULE 6: Isolated Subjects (Dead-end in investigation)
  nodes.filter(n => n.type === NodeType.PERSON).forEach(person => {
    const hasLinks = edges.some(e => e.source === person.id || e.target === person.id);
    if (!hasLinks) {
      result.redFlags.push({
        type: 'ISOLATED_SUBJECT',
        severity: 'MEDIUM',
        message: `Investigation Gap: ${person.data.label} has no recorded connections`,
        affectedNodeIds: [person.id],
        evidence: "Interview subject or check alternative contact methods"
      });
    }
  });

  // RULE 7: Calculate Ringleader (Network Centrality)
  if (nodes.length > 0) {
    const connections = new Map<string, number>();
    nodes.forEach(node => {
      const count = edges.filter(e => e.source === node.id || e.target === node.id).length;
      connections.set(node.id, count);
    });

    const sorted = [...connections.entries()].sort((a, b) => b[1] - a[1]);
    if (sorted[0] && sorted[0][1] > 0) {
      const ringleaderNode = nodeById.get(sorted[0][0]);
      if (ringleaderNode) {
        result.ringleader = {
          id: ringleaderNode.id,
          label: ringleaderNode.data.label as string,
          connectionCount: sorted[0][1]
        };
      }
    }
  }

  // RULE 8: Travel Time Impossibility (Nigeria-specific)
  const events = nodes.filter(n => n.type === NodeType.EVENT);
  for (let i = 0; i < events.length; i++) {
    for (let j = i + 1; j < events.length; j++) {
      const e1 = events[i];
      const e2 = events[j];

      if (e1.data.date && e2.data.date && 
          e1.data.location && e2.data.location &&
          e1.data.location !== e2.data.location) {

        const date1 = new Date(e1.data.date as string);
        const date2 = new Date(e2.data.date as string);
        const timeDiff = Math.abs(date2.getTime() - date1.getTime()) / (1000 * 60); // minutes

        if (timeDiff < 120) { // Less than 2 hours between events
          // Check if locations are far apart (e.g., Lagos to Abuja)
          const isLongDistance = isLongDistanceTravel(e1.data.location as string, e2.data.location as string);
          if (isLongDistance) {
            result.redFlags.push({
              type: 'GEOGRAPHICAL_IMPLAUSIBLE',
              severity: 'HIGH',
              message: `Impossible travel: ${e1.data.location} to ${e2.data.location} in ${timeDiff.toFixed(0)} minutes`,
              affectedNodeIds: [e1.id, e2.id],
              evidence: "Check flight records or verify alibi"
            });
          }
        }
      }
    }
  }

  // RULE 9: Kidnapping Specific Red Flags
  if (isKidnappingCase(nodes)) {
    const kidnapFlags = analyzeKidnapRedFlags(nodes);
    result.redFlags.push(...kidnapFlags);

    // Add emergency contact protocol
    result.redFlags.push({
      type: 'EMERGENCY_PROTOCOL',
      severity: 'HIGH',
      message: 'KIDNAP CASE DETECTED - Activate emergency response protocol',
      affectedNodeIds: nodes.filter(n => n.data.role === 'victim').map(n => n.id),
      evidence: 'Immediate notification required: Police IRT, DSS, State Security'
    });
  }

  return result;
};

// Helper function for Nigerian geography
const isLongDistanceTravel = (loc1: string, loc2: string): boolean => {
  const longDistancePairs = [
    ['Lagos', 'Abuja'], ['Port Harcourt', 'Kano'], ['Ibadan', 'Maiduguri'],
    ['Enugu', 'Sokoto'], ['Benin', 'Jos']
  ];

  return longDistancePairs.some(pair => 
    (pair.includes(loc1) && pair.includes(loc2)) ||
    (pair.includes(loc2) && pair.includes(loc1))
  );
};

function isKidnappingCase(nodes: Node[]): boolean {
  return nodes.some(n => 
    n.data.role === 'victim' || 
    n.data.type === 'kidnapping' ||
    n.data.description?.toLowerCase().includes('abduct') ||
    n.data.description?.toLowerCase().includes('ransom')
  );
}

function analyzeKidnapRedFlags(nodes: Node[]): RedFlag[] {
  const flags: RedFlag[] = [];
  const victims = nodes.filter(n => n.data.role === 'victim');

  victims.forEach(victim => {
    // Check if victim has medical conditions
    if (victim.data.medicalCondition) {
      flags.push({
        type: 'MEDICAL_EMERGENCY',
        severity: 'HIGH',
        message: `Victim has medical condition: ${victim.data.medicalCondition}`,
        affectedNodeIds: [victim.id],
        evidence: 'Prioritize medical access in negotiations'
      });
    }

    // Check time since abduction
    if (victim.data.abductionTime) {
      const hoursMissing = calculateHoursMissing(victim.data.abductionTime as string);
      if (hoursMissing > 48) {
        flags.push({
          type: 'TIME_SENSITIVE',
          severity: 'HIGH',
          message: `Victim missing for ${hoursMissing.toFixed(0)} hours - Critical phase`,
          affectedNodeIds: [victim.id],
          evidence: 'First 72 hours most critical for recovery'
        });
      }
    }
  });

  return flags;
}

function calculateHoursMissing(dateStr: string): number {
  const date = new Date(dateStr);
  const now = new Date();
  return (now.getTime() - date.getTime()) / (1000 * 60 * 60);
}

