interface EditorPanelProps {
  selectedNode: Node | null;
  selectedEdge: Edge | null;
  setNodes: React.Dispatch<React.SetStateAction<Node[]>>;
  setEdges: React.Dispatch<React.SetStateAction<Edge[]>>;
  onClose: () => void;
  deleteNode: (id: string) => void;
  deleteEdge: (id: string) => void;
}

export const EditorPanel: React.FC<EditorPanelProps> = ({ 
  selectedNode, 
  selectedEdge, 
  setNodes, 
  setEdges, 
  onClose, 
  deleteNode, 
  deleteEdge 
}) => {
  // Form state for Nodes
  const [nodeFormData, setNodeFormData] = useState<NodeData>({
    label: '',
    date: '',
    evidenceSource: '',
  });

  // Form state for Edges
  const [edgeFormData, setEdgeFormData] = useState({
    label: '',
    color: '#64748b'
  });

  // Sync state when selection changes
  useEffect(() => {
    if (selectedNode) {
      setNodeFormData({
        label: selectedNode.data.label as string || '',
        date: (selectedNode.data.date as string) || '',
        evidenceSource: (selectedNode.data.evidenceSource as string) || '',
      });
    }
  }, [selectedNode]);

  useEffect(() => {
    if (selectedEdge) {
      setEdgeFormData({
        label: (selectedEdge.label as string) || '',
        color: selectedEdge.style?.stroke as string || '#64748b',
      });
    }
  }, [selectedEdge]);

  // Handler for Node updates
  const handleNodeChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setNodeFormData(prev => ({ ...prev, [name]: value }));

    setNodes((nds) => 
      nds.map((node) => {
        if (node.id === selectedNode?.id) {
          return {
            ...node,
            data: { ...node.data, [name]: value },
          };
        }
        return node;
      })
    );
  };

  // Handler for Edge updates
  const handleEdgeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;

    if (name === 'label') {
      setEdgeFormData(prev => ({ ...prev, label: value }));
      setEdges((eds) => 
        eds.map((edge) => {
          if (edge.id === selectedEdge?.id) {
            return { ...edge, label: value };
          }
          return edge;
        })
      );
    }
  };

  const handleColorChange = (color: string) => {
    setEdgeFormData(prev => ({ ...prev, color }));
    setEdges((eds) => 
      eds.map((edge) => {
        if (edge.id === selectedEdge?.id) {
          return { 
            ...edge, 
            style: { ...edge.style, stroke: color, strokeWidth: 2 },
            animated: true
          };
        }
        return edge;
      })
    );
  };

  const colors = [
    { label: 'Neutral', value: '#64748b', bg: 'bg-slate-500' }, // Slate
    { label: 'Hostile', value: '#ef4444', bg: 'bg-red-500' },   // Red
    { label: 'Related', value: '#3b82f6', bg: 'bg-blue-500' },  // Blue
    { label: 'Key Link', value: '#eab308', bg: 'bg-yellow-500' }, // Yellow
    { label: 'Verified', value: '#10b981', bg: 'bg-emerald-500' }, // Green
  ];

  if (!selectedNode && !selectedEdge) return null;

  return (
    <div className="absolute right-4 top-4 w-80 bg-slate-900 border border-slate-700 rounded-xl shadow-2xl overflow-hidden flex flex-col animate-slide-in-right z-50">
      <div className="p-4 border-b border-slate-800 flex justify-between items-center bg-slate-800/50">
        <h2 className="font-semibold text-slate-100 flex items-center gap-2">
          {selectedNode ? (
            <>Details: <span className="text-amber-500 uppercase text-xs border border-amber-500/30 px-1.5 py-0.5 rounded">{selectedNode.type}</span></>
          ) : (
            <>Connection Details</>
          )}
        </h2>
        <button onClick={onClose} className="text-slate-400 hover:text-white transition-colors">
          <X className="w-5 h-5" />
        </button>
      </div>

      <div className="p-4 space-y-4">
        {/* --- NODE EDITOR --- */}
        {selectedNode && (
          <>
            <div>
              <label className="block text-xs font-medium text-slate-400 mb-1.5 uppercase tracking-wide">Title / Name</label>
              <input
                type="text"
                name="label"
                value={nodeFormData.label}
                onChange={handleNodeChange}
                className="w-full bg-slate-950 border border-slate-700 rounded-md px-3 py-2 text-sm text-slate-100 focus:outline-none focus:border-amber-500 transition-colors placeholder:text-slate-600"
                placeholder="e.g. Incident at Wharf"
              />
            </div>

            <div>
              <label className="block text-xs font-medium text-slate-400 mb-1.5 uppercase tracking-wide">Date & Time</label>
              <input
                type="text"
                name="date"
                value={nodeFormData.date}
                onChange={handleNodeChange}
                className="w-full bg-slate-950 border border-slate-700 rounded-md px-3 py-2 text-sm text-slate-100 focus:outline-none focus:border-amber-500 transition-colors placeholder:text-slate-600"
                placeholder="YYYY-MM-DD HH:MM"
              />
            </div>

            <div>
              <label className="block text-xs font-medium text-slate-400 mb-1.5 uppercase tracking-wide">Evidence Source</label>
              <textarea
                name="evidenceSource"
