  const [manualMode, setManualMode] = useState<InvestigationType | 'AUTO'>('AUTO');
  const [investigationType, setInvestigationType] = useState<InvestigationType>(InvestigationType.GENERAL);

  const [kidnapAnalysis, setKidnapAnalysis] = useState<KidnappingAnalysis | null>(null);
  const [showFullAnalysis, setShowFullAnalysis] = useState(false);

  // Simulation / Toast State
  const [simulationToast, setSimulationToast] = useState<{message: string, type: 'info' | 'success'} | null>(null);

  // --- HISTORY MANAGEMENT ---
  const [past, setPast] = useState<HistoryState[]>([]);
  const [future, setFuture] = useState<HistoryState[]>([]);

  // Function to take a snapshot of the current state BEFORE an action
  const takeSnapshot = useCallback(() => {
    setPast((prev) => {
      // Limit history to 20 steps to prevent memory bloat
      const newPast = [...prev, { nodes, edges }];
      return newPast.length > 20 ? newPast.slice(1) : newPast;
    });
    setFuture([]);
  }, [nodes, edges]);

  const undo = useCallback(() => {
    if (past.length === 0) return;

    const previous = past[past.length - 1];
    const newPast = past.slice(0, past.length - 1);

    setFuture((prev) => [{ nodes, edges }, ...prev]);
    setNodes(previous.nodes);
    setEdges(previous.edges);
    setPast(newPast);
    setSelectedNode(null); // Clear selection
    setSelectedEdge(null);
  }, [past, nodes, edges, setNodes, setEdges]);

  const redo = useCallback(() => {
    if (future.length === 0) return;

    const next = future[0];
    const newFuture = future.slice(1);

    setPast((prev) => [...prev, { nodes, edges }]);
    setNodes(next.nodes);
    setEdges(next.edges);
    setFuture(newFuture);
    setSelectedNode(null);
    setSelectedEdge(null);
  }, [future, nodes, edges, setNodes, setEdges]);

  // Keyboard Shortcuts for Undo/Redo
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Check if user is typing in an input field
      if (['INPUT', 'TEXTAREA'].includes((e.target as HTMLElement).tagName)) return;

      if ((e.metaKey || e.ctrlKey) && e.key === 'z') {
        e.preventDefault();
        if (e.shiftKey) {
          redo();
        } else {
          undo();
        }
      }
      if ((e.metaKey || e.ctrlKey) && (e.key === 'y')) {
        e.preventDefault();
        redo();
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [undo, redo]);

  // --- ANALYSIS EFFECTS ---
  useEffect(() => {
    if (nodes.length > 0) {
      // 1. Run Local Analysis
      const localResults = runLocalAnalysis(nodes, edges);
      setLocalAnalysis(localResults);

      // 2. Check for Kidnapping Context Keywords
      const hasKidnapKeywords = nodes.some(n => {
        const data = n.data as NodeData;
        return data.role === 'victim' || 
        data.type === 'kidnapping' ||
        data.description?.toLowerCase().includes('abduct') ||
        data.label?.toLowerCase().includes('kidnap') ||
        data.label?.toLowerCase().includes('ransom');
      });

      // 3. Determine Mode (Manual Override > Auto Detection)
      let activeType = InvestigationType.GENERAL;

      if (manualMode !== 'AUTO') {
        activeType = manualMode;
      } else if (hasKidnapKeywords) {
        activeType = InvestigationType.KIDNAPPING;
      }

      setInvestigationType(activeType);

      // 4. Run Specific Analyzers based on type
      if (activeType === InvestigationType.KIDNAPPING) {
        const kAnalysis = analyzeKidnapCase(nodes, edges);
        setKidnapAnalysis(kAnalysis);
      } else {
        setKidnapAnalysis(null);
      }
    } else {
        // Even with no nodes, if manual mode is kidnapping, show empty dashboard? 
        // Better to allow it so tools palette appears.
        if (manualMode === InvestigationType.KIDNAPPING) {
            setInvestigationType(InvestigationType.KIDNAPPING);
            const kAnalysis = analyzeKidnapCase(nodes, edges); // Will return defaults
            setKidnapAnalysis(kAnalysis);
        } else {
            setInvestigationType(InvestigationType.GENERAL);
            setKidnapAnalysis(null);
        }
    }
  }, [nodes, edges, manualMode]);

  // --- HANDLERS ---

  const handleActionSimulation = (action: string) => {
    let message = '';
    let type: 'info' | 'success' = 'info';

    switch (action) {
      case 'activate_irt':
        message = 'Dispatching Intelligence Response Team (IRT)...';
        break;
      case 'track_phones':
        message = 'Triangulating GSM Signals...';
        break;
      case 'setup_roadblocks':
        message = 'Alerting State Commands & Highway Patrol...';
        break;
      case 'contact_family':
        message = 'Initiating Secure Line with Family Liaison...';
        break;
      default:
        message = 'Processing Action...';
    }

    // Step 1: Show Processing
    setSimulationToast({ message, type: 'info' });

    // Step 2: Show Success after delay
    setTimeout(() => {
      let successMsg = '';
      switch (action) {
        case 'activate_irt': successMsg = 'IRT Units Deployed & Active'; break;
        case 'track_phones': successMsg = 'Signal Locked: Cell ID #4922 (Approximation)'; break;
        case 'setup_roadblocks': successMsg = 'Gridlock Protocol Active in 3 Zones'; break;
        case 'contact_family': successMsg = 'Secure Channel Established'; break;
        default: successMsg = 'Action Completed';
      }
      setSimulationToast({ message: successMsg, type: 'success' });

      // Clear after delay
      setTimeout(() => setSimulationToast(null), 3000);
    }, 1500);
  };

  const onConnect = useCallback(
    (params: Connection) => {
      takeSnapshot(); // Snapshot before connecting
      setEdges((eds) => addEdge({ ...params, type: 'default', animated: true, style: { stroke: '#64748b', strokeWidth: 2 } } as Edge, eds));
    },
    [setEdges, takeSnapshot],
  );

  const onDragOver = useCallback((event: React.DragEvent) => {
    event.preventDefault();
    event.dataTransfer.dropEffect = 'move';
  }, []);

  const onDrop = useCallback(
    (event: React.DragEvent) => {
      event.preventDefault();
      takeSnapshot(); // Snapshot before dropping

      const typeStr = event.dataTransfer.getData('application/reactflow');
      const isKidnapTool = event.dataTransfer.getData('kidnap') === 'true';

      let nodeType: NodeType | undefined = undefined;

      if (Object.values(NodeType).includes(typeStr as NodeType)) {
        nodeType = typeStr as NodeType;
      }

      if (!nodeType && !isKidnapTool) {
          if (['location', 'evidence'].includes(typeStr)) {
             nodeType = NodeType.EVENT;
          } else if (typeStr === 'organization') {
             nodeType = NodeType.PERSON;
          } else {
             nodeType = NodeType.EVENT;
          }
      }

      const position = screenToFlowPosition({
        x: event.clientX,
        y: event.clientY,
      });

      let initialData: any = { label: 'New Node' };

      if (isKidnapTool) {
         const toolType = typeStr; 
         if (toolType === 'victim') {
             nodeType = NodeType.PERSON;
             initialData = { label: 'Victim', role: 'victim', medicalCondition: '', abductionTime: new Date().toISOString() };
         } else if (toolType === 'ransom') {
             nodeType = NodeType.EVENT;
             initialData = { label: 'Ransom Demand', type: 'communication', amount: 5000000 };
         } else {
             nodeType = NodeType.EVENT;
             initialData = { label: toolType.charAt(0).toUpperCase() + toolType.slice(1), role: toolType };
         }
      } else {
          if (typeStr === 'location') {
              initialData = { label: 'New Location', location: 'Unknown Location', type: 'location' };
          } else if (typeStr === 'evidence') {
              initialData = { label: 'New Evidence', evidenceSource: 'TBD', type: 'evidence' };
          } else if (typeStr === 'organization') {
              initialData = { label: 'New Organization', type: 'organization' };
          } else {
             initialData = { label: `New ${nodeType === NodeType.EVENT ? 'Event' : 'Person'}`, date: '', evidenceSource: '' };
          }
      }

      const newNode: Node = {
        id: getId(),
        type: nodeType,
        position,
        data: initialData,
      };

      setNodes((nds) => nds.concat(newNode));
      setSelectedNode(newNode);
      setSelectedEdge(null);
    },
    [screenToFlowPosition, setNodes, takeSnapshot],
  );

  const onNodeDragStart = useCallback(() => {
    // We snapshot on drag start to save position before move
    takeSnapshot();
  }, [takeSnapshot]);

  const onNodeClick = useCallback((_: React.MouseEvent, node: Node) => {
    setSelectedNode(node);
    setSelectedEdge(null);
  }, []);

  const onEdgeClick = useCallback((_: React.MouseEvent, edge: Edge) => {
    setSelectedEdge(edge);
    setSelectedNode(null);
  }, []);

  const onPaneClick = useCallback(() => {
    setSelectedNode(null);
    setSelectedEdge(null);
  }, []);

  const handleDeleteNode = useCallback((id: string) => {
    takeSnapshot(); // Snapshot before delete
    setNodes((nds) => nds.filter((n) => n.id !== id));
    setEdges((eds) => eds.filter((e) => e.source !== id && e.target !== id));
    setSelectedNode(null);
  }, [setNodes, setEdges, takeSnapshot]);

  const handleDeleteEdge = useCallback((id: string) => {
    takeSnapshot();
    setEdges((eds) => eds.filter((e) => e.id !== id));
    setSelectedEdge(null);
  }, [setEdges, takeSnapshot]);

  const handleAnalysis = async () => {
    if (nodes.length === 0) return;
    setIsAnalyzing(true);
    setAnalysis(null);
    try {
      const result = await analyzeBoard(nodes, edges);
      setAnalysis(result);
    } catch (e) {
      console.error(e);
      alert("Analysis failed. Please check your API configuration.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const kidnappingSidebarItems = [
    { type: 'victim', label: '👤 Victim' },
    { type: 'ransom', label: '💰 Ransom' },
    { type: 'hideout', label: '🏚️ Hideout' },
    { type: 'vehicle', label: '🚗 Vehicle' },
    { type: 'accomplice', label: '👥 Accomplice' },
    { type: 'communication', label: '📞 Comms' },
  ];

  return (
    <div className="flex h-screen w-full bg-slate-950 text-slate-200 font-sans selection:bg-amber-500/30">
      <Sidebar />

      <div className="flex-1 h-full relative" ref={reactFlowWrapper}>
        <ReactFlow
          nodes={nodes}
          edges={edges}
          onNodesChange={onNodesChange}
          onEdgesChange={onEdgesChange}
          onConnect={onConnect}
          onDrop={onDrop}
          onDragOver={onDragOver}
          onNodeDragStart={onNodeDragStart}
          onNodeClick={onNodeClick}
          onEdgeClick={onEdgeClick}
          onPaneClick={onPaneClick}
          nodeTypes={nodeTypes}
          fitView
          className="bg-slate-950"
        >
          <Controls className="!bg-slate-800 !border-slate-700 !fill-slate-400 [&>button]:!border-slate-700 hover:[&>button]:!bg-slate-700" />
          <Background color="#1e293b" gap={20} variant={BackgroundVariant.Dots} />

          <Panel position="top-right" className="flex flex-col gap-4 mt-20 md:mt-0 items-end">
            <div className="flex gap-2">
               {/* Mode Selector */}
               <div className="flex items-center bg-slate-800 rounded-lg p-1 border border-slate-700 shadow-lg px-2 gap-2">
                 <Briefcase className={`w-4 h-4 ${investigationType === InvestigationType.KIDNAPPING ? 'text-red-500' : 'text-slate-400'}`} />
                 <select 
                    value={manualMode}
                    onChange={(e) => setManualMode(e.target.value as any)}
                    className="bg-transparent text-sm font-medium text-slate-200 focus:outline-none cursor-pointer"
                 >
                   <option value="AUTO">Auto Detect</option>
                   <option value={InvestigationType.GENERAL}>General Case</option>
                   <option value={InvestigationType.KIDNAPPING}>Kidnapping</option>
                 </select>
               </div>

              {/* Undo/Redo */}
              <div className="flex bg-slate-800 rounded-lg p-1 border border-slate-700 shadow-lg">
                <button
                  onClick={undo}
                  disabled={past.length === 0}
                  className={`p-2 rounded hover:bg-slate-700 transition-colors ${past.length === 0 ? 'opacity-30 cursor-not-allowed' : 'text-slate-200'}`}
                  title="Undo (Ctrl+Z)"
                >
                  <Undo2 className="w-4 h-4" />
                </button>
                <div className="w-px bg-slate-700 my-1 mx-1" />
                <button
                  onClick={redo}
                  disabled={future.length === 0}
                  className={`p-2 rounded hover:bg-slate-700 transition-colors ${future.length === 0 ? 'opacity-30 cursor-not-allowed' : 'text-slate-200'}`}
                  title="Redo (Ctrl+Y)"
                >
                  <Redo2 className="w-4 h-4" />
                </button>
              </div>

              {/* Gemini Analysis Button */}
              <button 
                onClick={handleAnalysis}
                disabled={isAnalyzing || nodes.length === 0}
                className={`
                  flex items-center gap-2 px-4 py-2 rounded-lg font-medium text-sm shadow-lg transition-all
                  ${isAnalyzing 
                    ? 'bg-slate-800 text-slate-400 cursor-wait' 
                    : 'bg-amber-600 hover:bg-amber-500 text-white hover:scale-105 active:scale-95'}
                `}
              >
                {isAnalyzing ? (
                  <><Loader2 className="w-4 h-4 animate-spin" /> Analyzing...</>
                ) : (
                  <><BrainCircuit className="w-4 h-4" /> Analyze Case</>
                )}
              </button>
            </div>
          </Panel>

           {/* SIMULATION TOAST */}
          {simulationToast && (
             <div className="absolute top-20 left-1/2 -translate-x-1/2 z-50 animate-slide-in-bottom">
                <div className={`
                  flex items-center gap-3 px-4 py-3 rounded-lg shadow-2xl border backdrop-blur-md
                  ${simulationToast.type === 'success' 
                    ? 'bg-emerald-900/80 border-emerald-500/50 text-emerald-100' 
                    : 'bg-blue-900/80 border-blue-500/50 text-blue-100'}
                `}>
                  {simulationToast.type === 'success' ? (
                     <CheckCircle2 className="w-5 h-5 text-emerald-400" />
                  ) : (
                     <Radio className="w-5 h-5 text-blue-400 animate-pulse" />
                  )}
                  <div className="font-medium text-sm">{simulationToast.message}</div>
                </div>
             </div>
          )}

        </ReactFlow>

        {/* Local Analysis Widget */}
        {localAnalysis && (localAnalysis.redFlags.length > 0 || localAnalysis.ringleader) && (
          <div className="absolute top-20 right-4 w-80 bg-slate-900/95 border border-slate-700 rounded-lg p-4 shadow-xl z-40 animate-slide-in-right">
            <div className="flex items-center gap-2 mb-3">
              <ShieldAlert className="w-5 h-5 text-amber-500" />
              <h3 className="font-bold text-slate-200">Local Intelligence</h3>
              <span className="ml-auto text-xs bg-slate-800 px-2 py-1 rounded">
                {localAnalysis.redFlags.filter(f => f.severity === 'HIGH').length} 🔴
              </span>
            </div>

            {/* Ringleader */}
            {localAnalysis.ringleader && (
              <div className="mb-3 p-3 bg-slate-800/50 rounded border border-blue-500/30">
                <div className="flex items-center gap-2 text-blue-400 text-sm font-semibold mb-1">
                  <Crown className="w-4 h-4" />
                  Key Person of Interest
                </div>
                <div className="text-slate-300">
                  <div className="font-medium">{localAnalysis.ringleader.label}</div>
                  <div className="text-xs text-slate-400">
                    Connected to {localAnalysis.ringleader.connectionCount} entities
                  </div>
                </div>
              </div>
            )}

            {/* Red Flags Preview */}
            {localAnalysis.redFlags.slice(0, 3).map((flag, idx) => (
              <div key={idx} className={`mb-2 p-2 rounded border text-sm ${
                flag.severity === 'HIGH' 
                  ? 'bg-red-900/20 border-red-500/40' 
                  : 'bg-amber-900/20 border-amber-500/40'
              }`}>
                <div className="flex items-start gap-2">
                  <div className={`w-2 h-2 rounded-full mt-1.5 shrink-0 ${
                    flag.severity === 'HIGH' ? 'bg-red-500' : 'bg-amber-500'
                  }`} />
                  <div>
                    <div className="text-slate-300 leading-tight">{flag.message}</div>
                  </div>
                </div>
              </div>
            ))}

            <button 
              className="w-full text-xs text-center text-slate-400 hover:text-slate-200 py-1 bg-slate-800/50 rounded mt-1"
              onClick={() => setShowFullAnalysis(true)}
            >
              View Full Report {localAnalysis.redFlags.length > 3 ? `(+${localAnalysis.redFlags.length - 3} more)` : ''}
            </button>
          </div>
        )}

        {/* Kidnapping Dashboard Overlay - Only visible in Kidnapping Mode */}
        {investigationType === InvestigationType.KIDNAPPING && kidnapAnalysis && (
          <KidnappingDashboard 
            analysis={kidnapAnalysis}
            onAction={handleActionSimulation}
          />
        )}

        {/* Kidnapping Tools Palette - Only visible in Kidnapping Mode */}
        {investigationType === InvestigationType.KIDNAPPING && (
          <div className="absolute bottom-4 left-4 w-48 bg-red-900/80 backdrop-blur border border-red-500/50 rounded-lg p-3 z-40 animate-slide-in-bottom shadow-lg">
            <div className="text-xs text-red-200 font-bold mb-2 uppercase tracking-wider flex items-center gap-2">
               <AlertTriangle className="w-3 h-3" /> Kidnap Tools
            </div>
            <div className="grid grid-cols-2 gap-2">
              {kidnappingSidebarItems.map((item, idx) => (
                <div
                  key={idx}
                  draggable
                  onDragStart={(e) => {
                    e.dataTransfer.setData('application/reactflow', item.type);
                    e.dataTransfer.setData('kidnap', 'true');
                  }}
                  className="p-2 bg-slate-900/60 hover:bg-red-700/60 rounded text-center cursor-grab text-xs border border-red-500/30 text-slate-200 transition-colors"
                >
                  {item.label}
                </div>
              ))}
            </div>
          </div>
        )}

        <EditorPanel 
          selectedNode={selectedNode}
          selectedEdge={selectedEdge}
          setNodes={(newNodesOrUpdater) => {
             // Simplified update for nodes
             setNodes(newNodesOrUpdater);
          }}
          setEdges={(newEdgesOrUpdater) => {
            setEdges(newEdgesOrUpdater);
          }}
          onClose={() => {
            setSelectedNode(null);
            setSelectedEdge(null);
          }}
          deleteNode={handleDeleteNode}
          deleteEdge={handleDeleteEdge}
        />

        {/* Full Local Analysis Modal */}
        {showFullAnalysis && localAnalysis && (
          <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
            <div className="bg-slate-900 border border-slate-700 rounded-xl w-full max-w-4xl max-h-[85vh] overflow-y-auto p-6 shadow-2xl animate-in fade-in zoom-in-95 duration-200">
              <div className="flex justify-between items-center mb-6">
                <h2 className="text-xl font-bold text-slate-200 flex items-center gap-2">
                  <ShieldAlert className="w-6 h-6 text-amber-500" />
                  Complete Analysis Report
                </h2>
                <button 
                  onClick={() => setShowFullAnalysis(false)}
                  className="text-slate-500 hover:text-white transition-colors p-1"
                >
                  ✕
                </button>
              </div>

              {/* Ringleader Section */}
              {localAnalysis.ringleader && (
                <section className="mb-8 p-4 bg-slate-800/50 rounded-lg border border-slate-700">
                  <h3 className="text-sm font-semibold text-blue-400 mb-3 uppercase tracking-wide">Key Subject</h3>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <div className="text-sm text-slate-400">Primary Person of Interest</div>
                      <div className="text-xl font-bold text-slate-200">{localAnalysis.ringleader.label}</div>
                    </div>
                    <div>
                      <div className="text-sm text-slate-400">Network Connections</div>
                      <div className="text-xl font-bold text-slate-200">
                        {localAnalysis.ringleader.connectionCount} direct links
                      </div>
                    </div>
                  </div>
                </section>
              )}

              {/* Red Flags */}
              <section className="mb-8">
                <h3 className="text-lg font-semibold text-slate-200 mb-3 flex items-center gap-2">
                  <AlertTriangle className="w-5 h-5 text-amber-500" />
                  Investigation Alerts ({localAnalysis.redFlags.length})
                </h3>
                <div className="space-y-3">
                  {localAnalysis.redFlags.map((flag, idx) => {
                    const affectedNodeNames = flag.affectedNodeIds.map(id => {
                      const node = nodes.find(n => n.id === id);
                      return node ? (node.data as NodeData).label || id : id;
                    }).join(', ');

                    return (
                    <div key={idx} className={`p-4 rounded-lg border ${
                      flag.severity === 'HIGH' 
                        ? 'border-red-500/30 bg-red-900/10' 
                        : 'border-amber-500/30 bg-amber-900/10'
                    }`}>
                      <div className="flex items-center gap-3 mb-2">
                        <div className={`w-3 h-3 rounded-full ${
                          flag.severity === 'HIGH' ? 'bg-red-500' : 'bg-amber-500'
                        }`} />
                        <span className="font-medium text-slate-200">{flag.type.replace('_', ' ')}</span>
                        <span className={`px-2 py-0.5 rounded text-[10px] uppercase font-bold tracking-wider ${
                          flag.severity === 'HIGH' 
                            ? 'bg-red-500/20 text-red-300' 
                            : 'bg-amber-500/20 text-amber-300'
                        }`}>
                          {flag.severity}
                        </span>
                      </div>
                      <p className="text-slate-300 mb-2">{flag.message}</p>
                      {flag.evidence && (
                        <p className="text-sm text-slate-500 italic">Suggested: {flag.evidence}</p>
                      )}
                      <div className="text-xs text-slate-400 mt-2 pt-2 border-t border-slate-700/50">
                        Affects: {affectedNodeNames}
                      </div>
                    </div>
                  )})}
                </div>
              </section>

              {/* Financial Patterns */}
              {localAnalysis.financialPatterns.length > 0 && (
                <section className="mb-8">
                  <h3 className="text-lg font-semibold text-slate-200 mb-3">
                    Financial Patterns ({localAnalysis.financialPatterns.length})
                  </h3>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                    {localAnalysis.financialPatterns.map((pattern, idx) => (
                      <div key={idx} className="p-3 bg-slate-800/30 rounded border border-slate-700">
                        <div className="text-xs text-slate-400 mb-1">{pattern.type.replace('_', ' ')}</div>
                        <div className="text-slate-200 font-medium">{pattern.description}</div>
                        {pattern.amount && (
                          <div className="text-xs text-emerald-400 mt-1">
                            ₦{pattern.amount.toLocaleString('en-NG')}
                          </div>
                        )}
                      </div>
                    ))}
                  </div>
                </section>
              )}

              {/* Geographical Clusters */}
              {localAnalysis.geographicalClusters.length > 0 && (
                <section className="mb-8">
                  <h3 className="text-lg font-semibold text-slate-200 mb-3 flex items-center gap-2">
                    <MapPin className="w-5 h-5 text-blue-500" />
                    Geographical Analysis
                  </h3>
                  <div className="space-y-3">
                    {localAnalysis.geographicalClusters.map((cluster, idx) => (
                      <div key={idx} className="p-3 bg-slate-800/30 rounded border border-slate-700">
                        <div className="flex justify-between items-center">
                          <div>
                            <div className="text-slate-200 font-medium">{cluster.location}</div>
                            <div className="text-sm text-slate-400">{cluster.nodes.length} related events</div>
                          </div>
                        </div>
                        <div className="text-xs text-slate-500 mt-2 bg-slate-900/50 p-2 rounded">
                            Strategy: {cluster.suggestion}
                        </div>
                      </div>
                    ))}
                  </div>
                </section>
              )}

              {/* Timeline Gaps */}
              {localAnalysis.timelineGaps.length > 0 && (
                <section>
                  <h3 className="text-lg font-semibold text-slate-200 mb-3">
                    Timeline Gaps ({localAnalysis.timelineGaps.length})
                  </h3>
                  <div className="space-y-2">
                    {localAnalysis.timelineGaps.map((gap, idx) => {
                      return (
                        <div key={idx} className="p-3 bg-slate-800/30 rounded border border-slate-800">
                          <div className="text-slate-300 text-sm">{gap.message}</div>
                          <div className="text-sm text-slate-500 mt-1">
                            <span className="text-slate-400">Suggestion:</span> {gap.suggestion}
                          </div>
                        </div>
                      );
                    })}
                  </div>
                </section>
              )}
            </div>
          </div>
        )}

        {/* AI Analysis Result Overlay (Gemini) */}
        {analysis && !isAnalyzing && (
          <div className="absolute bottom-6 left-6 right-6 md:left-20 md:right-auto md:w-[500px] bg-slate-900/95 backdrop-blur border border-amber-500/30 rounded-xl shadow-2xl p-6 animate-slide-in-bottom z-50 max-h-[40vh] overflow-y-auto">
            <div className="flex justify-between items-start mb-4">
              <h3 className="text-lg font-bold text-amber-500 flex items-center gap-2">
                <Sparkles className="w-5 h-5" /> Gemini Intelligence Summary
              </h3>
              <button 
                onClick={() => setAnalysis(null)}
                className="text-slate-500 hover:text-slate-300"
              >
                <span className="sr-only">Close</span>
                ✕
              </button>
            </div>

            <div className="space-y-4 text-sm text-slate-300">
              <div className="bg-slate-800/50 p-3 rounded border border-slate-700">
                <p className="leading-relaxed">{analysis.summary}</p>
              </div>

              {analysis.gaps.length > 0 && (
                <div>
                  <h4 className="font-semibold text-slate-200 mb-2 flex items-center gap-2">
                    <AlertTriangle className="w-4 h-4 text-red-400" /> Missing Intel / Gaps
                  </h4>
                  <ul className="list-disc pl-5 space-y-1 text-slate-400">
                    {analysis.gaps.map((gap, i) => (
                      <li key={i}>{gap}</li>
                    ))}
                  </ul>
                </div>
              )}

              {analysis.connections.length > 0 && (
                <div>
                  <h4 className="font-semibold text-slate-200 mb-2 flex items-center gap-2">
                    <Link2 className="w-4 h-4 text-blue-400" /> Inferred Connections
                  </h4>
                  <ul className="list-disc pl-5 space-y-1 text-slate-400">
                    {analysis.connections.map((conn, i) => (
                      <li key={i}>{conn}</li>
                    ))}
                  </ul>
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useCallback, useRef, useState, useEffect } from 'react';
import {
  ReactFlow,
  ReactFlowProvider,
  addEdge,
  useNodesState,
  useEdgesState,
  Controls,
  Background,
  Connection,
  Edge,
  Node,
  BackgroundVariant,
  useReactFlow,
  Panel,
  NodeChange,
  EdgeChange,
} from '@xyflow/react';

import { Sidebar } from './components/Sidebar';
import { EditorPanel } from './components/EditorPanel';
import { EventNode, PersonNode } from './components/CustomNodes';
import { NodeType, AnalysisResult, InvestigationType, NodeData } from './types';
import { analyzeBoard } from './services/geminiService';
import { analyzeKidnappingCase, KidnappingAnalysis } from './services/kidnappingAnalysis';
import { runLocalAnalysis, LocalAnalysisResult } from './services/localAnalysis';
import { KidnappingDashboard } from './components/KidnappingDashboard';
import { 
  BrainCircuit, 
  Loader2, 
  Sparkles, 
  AlertTriangle, 
  Link2,
  ShieldAlert, 
  Crown, 
  MapPin,
  Undo2,
  Redo2,
  History,
  Briefcase,
  CheckCircle2,
  Radio
} from 'lucide-react';

// Define custom node types outside component to prevent re-creation
const nodeTypes = {
  [NodeType.EVENT]: EventNode,
  [NodeType.PERSON]: PersonNode,
};

let id = 100;
const getId = () => `dndnode_${id++}`;

// Interface for History
interface HistoryState {
  nodes: Node[];
  edges: Edge[];
}

const App = () => {
  const reactFlowWrapper = useRef<HTMLDivElement>(null);

  // INITIAL STATE: Preset kidnapping scenario
  const [nodes, setNodes, onNodesChange] = useNodesState<Node>([
    {
      id: '1',
      type: NodeType.PERSON,
      position: { x: 400, y: 100 },
      data: { 
        label: 'Dr. Amara Okeke', 
        role: 'victim',
        age: 45,
        occupation: 'Oil Executive',
        medicalCondition: 'Hypertension',
        abductionTime: new Date(Date.now() - 1000 * 60 * 60 * 24).toISOString(), // 24 hours ago
        evidenceSource: 'Family Report',
      },
    },
    {
      id: '2',
      type: NodeType.EVENT,
      position: { x: 400, y: 300 },
      data: { 
        label: 'Abduction at Lekki', 
        date: new Date(Date.now() - 1000 * 60 * 60 * 24).toISOString(),
        location: 'Lekki Phase 1',
        evidenceSource: 'CCTV Footage'
      },
    },
    {
      id: '3',
      type: NodeType.EVENT,
      position: { x: 700, y: 300 },
      data: { 
        label: 'Ransom Call', 
        type: 'communication',
        date: new Date(Date.now() - 1000 * 60 * 60 * 2).toISOString(), // 2 hours ago
        amount: 50000000,
        deadline: new Date(Date.now() + 1000 * 60 * 60 * 48).toISOString(), // 48 hours from now
        evidenceSource: 'Recorded Call #001'
      },
    },
  ]);
  const [edges, setEdges, onEdgesChange] = useEdgesState<Edge>([
    { id: 'e1-2', source: '1', target: '2', label: 'Abducted at', animated: true, style: { stroke: '#ef4444', strokeWidth: 2 } },
    { id: 'e1-3', source: '1', target: '3', label: 'Subject of', animated: true, style: { stroke: '#eab308', strokeWidth: 2 } },
  ]);

  const { screenToFlowPosition } = useReactFlow();

  const [selectedNode, setSelectedNode] = useState<Node | null>(null);
  const [selectedEdge, setSelectedEdge] = useState<Edge | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [localAnalysis, setLocalAnalysis] = useState<LocalAnalysisResult | null>(null);

  // Investigation Mode State
  const [manualMode, setManualMode] = useState<InvestigationType | 'AUTO'>('AUTO');
  const [investigationType, setInvestigationType] = useState<InvestigationType>(InvestigationType.GENERAL);

  const [kidnapAnalysis, setKidnapAnalysis] = useState<KidnappingAnalysis | null>(null);
  const [showFullAnalysis, setShowFullAnalysis] = useState(false);

  // Simulation / Toast State
  const [simulationToast, setSimulationToast] = useState<{message: string, type: 'info' | 'success'} | null>(null);

  // --- HISTORY MANAGEMENT ---
  const [past, setPast] = useState<HistoryState[]>([]);
  const [future, setFuture] = useState<HistoryState[]>([]);

  // Function to take a snapshot of the current state BEFORE an action
  const takeSnapshot = useCallback(() => {
    setPast((prev) => {
      // Limit history to 20 steps to prevent memory bloat
      const newPast = [...prev, { nodes, edges }];
      return newPast.length > 20 ? newPast.slice(1) : newPast;
    });
    setFuture([]);
  }, [nodes, edges]);

  const undo = useCallback(() => {
    if (past.length === 0) return;

    const previous = past[past.length - 1];
    const newPast = past.slice(0, past.length - 1);

    setFuture((prev) => [{ nodes, edges }, ...prev]);
    setNodes(previous.nodes);
    setEdges(previous.edges);
    setPast(newPast);
    setSelectedNode(null); // Clear selection
    setSelectedEdge(null);
  }, [past, nodes, edges, setNodes, setEdges]);

  const redo = useCallback(() => {
    if (future.length === 0) return;

    const next = future[0];
    const newFuture = future.slice(1);

    setPast((prev) => [...prev, { nodes, edges }]);
    setNodes(next.nodes);
    setEdges(next.edges);
    setFuture(newFuture);
    setSelectedNode(null);
    setSelectedEdge(null);
  }, [future, nodes, edges, setNodes, setEdges]);

  // Keyboard Shortcuts for Undo/Redo
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Check if user is typing in an input field
      if (['INPUT', 'TEXTAREA'].includes((e.target as HTMLElement).tagName)) return;

      if ((e.metaKey || e.ctrlKey) && e.key === 'z') {
        e.preventDefault();
        if (e.shiftKey) {
          redo();
        } else {
          undo();
        }
      }
      if ((e.metaKey || e.ctrlKey) && (e.key === 'y')) {
        e.preventDefault();
        redo();
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [undo, redo]);

  // --- ANALYSIS EFFECTS ---
  useEffect(() => {
    if (nodes.length > 0) {
      // 1. Run Local Analysis
      const localResults = runLocalAnalysis(nodes, edges);
      setLocalAnalysis(localResults);

      // 2. Check for Kidnapping Context Keywords
      const hasKidnapKeywords = nodes.some(n => {
        const data = n.data as NodeData;
        return data.role === 'victim' || 
        data.type === 'kidnapping' ||
        data.description?.toLowerCase().includes('abduct') ||
        data.label?.toLowerCase().includes('kidnap') ||
        data.label?.toLowerCase().includes('ransom');
      });

      // 3. Determine Mode (Manual Override > Auto Detection)
      let activeType = InvestigationType.GENERAL;

      if (manualMode !== 'AUTO') {
        activeType = manualMode;
      } else if (hasKidnapKeywords) {
        activeType = InvestigationType.KIDNAPPING;
      }

      setInvestigationType(activeType);

      // 4. Run Specific Analyzers based on type
      if (activeType === InvestigationType.KIDNAPPING) {
        const kAnalysis = analyzeKidnappingCase(nodes, edges);
        setKidnapAnalysis(kAnalysis);
      } else {
        setKidnapAnalysis(null);
      }
    } else {
        // Even with no nodes, if manual mode is kidnapping, show empty dashboard? 
        // Better to allow it so tools palette appears.
        if (manualMode === InvestigationType.KIDNAPPING) {
            setInvestigationType(InvestigationType.KIDNAPPING);
            const kAnalysis = analyzeKidnappingCase(nodes, edges); // Will return defaults
            setKidnapAnalysis(kAnalysis);
        } else {
            setInvestigationType(InvestigationType.GENERAL);
            setKidnapAnalysis(null);
        }
    }
  }, [nodes, edges, manualMode]);

  // --- HANDLERS ---

  const handleActionSimulation = (action: string) => {
    let message = '';
    let type: 'info' | 'success' = 'info';

    switch (action) {
      case 'activate_irt':
        message = 'Dispatching Intelligence Response Team (IRT)...';
        break;
      case 'track_phones':
        message = 'Triangulating GSM Signals...';
        break;
      case 'setup_roadblocks':
        message = 'Alerting State Commands & Highway Patrol...';
        break;
      case 'contact_family':
        message = 'Initiating Secure Line with Family Liaison...';
        break;
      default:
        message = 'Processing Action...';
    }

    // Step 1: Show Processing
    setSimulationToast({ message, type: 'info' });

    // Step 2: Show Success after delay
    setTimeout(() => {
      let successMsg = '';
      switch (action) {
        case 'activate_irt': successMsg = 'IRT Units Deployed & Active'; break;
        case 'track_phones': successMsg = 'Signal Locked: Cell ID #4922 (Approximation)'; break;
        case 'setup_roadblocks': successMsg = 'Gridlock Protocol Active in 3 Zones'; break;
        case 'contact_family': successMsg = 'Secure Channel Established'; break;
        default: successMsg = 'Action Completed';
      }
      setSimulationToast({ message: successMsg, type: 'success' });

      // Clear after delay
      setTimeout(() => setSimulationToast(null), 3000);
    }, 1500);
  };

  const onConnect = useCallback(
    (params: Connection) => {
      takeSnapshot(); // Snapshot before connecting
      setEdges((eds) => addEdge({ ...params, type: 'default', animated: true, style: { stroke: '#64748b', strokeWidth: 2 } } as Edge, eds));
    },
    [setEdges, takeSnapshot],
  );

  const onDragOver = useCallback((event: React.DragEvent) => {
    event.preventDefault();
    event.dataTransfer.dropEffect = 'move';
  }, []);

  const onDrop = useCallback(
    (event: React.DragEvent) => {
      event.preventDefault();
      takeSnapshot(); // Snapshot before dropping

      const typeStr = event.dataTransfer.getData('application/reactflow');
      const isKidnapTool = event.dataTransfer.getData('kidnap') === 'true';

      let nodeType: NodeType | undefined = undefined;

      if (Object.values(NodeType).includes(typeStr as NodeType)) {
        nodeType = typeStr as NodeType;
      }

      if (!nodeType && !isKidnapTool) {
          if (['location', 'evidence'].includes(typeStr)) {
             nodeType = NodeType.EVENT;
          } else if (typeStr === 'organization') {
             nodeType = NodeType.PERSON;
          } else {
             nodeType = NodeType.EVENT;
          }
      }

      const position = screenToFlowPosition({
        x: event.clientX,
        y: event.clientY,
      });

      let initialData: any = { label: 'New Node' };

      if (isKidnapTool) {
         const toolType = typeStr; 
         if (toolType === 'victim') {
             nodeType = NodeType.PERSON;
             initialData = { label: 'Victim', role: 'victim', medicalCondition: '', abductionTime: new Date().toISOString() };
         } else if (toolType === 'ransom') {
             nodeType = NodeType.EVENT;
             initialData = { label: 'Ransom Demand', type: 'communication', amount: 5000000 };
         } else {
             nodeType = NodeType.EVENT;
             initialData = { label: toolType.charAt(0).toUpperCase() + toolType.slice(1), role: toolType };
         }
      } else {
          if (typeStr === 'location') {
              initialData = { label: 'New Location', location: 'Unknown Location', type: 'location' };
          } else if (typeStr === 'evidence') {
              initialData = { label: 'New Evidence', evidenceSource: 'TBD', type: 'evidence' };
          } else if (typeStr === 'organization') {
              initialData = { label: 'New Organization', type: 'organization' };
          } else {
             initialData = { label: `New ${nodeType === NodeType.EVENT ? 'Event' : 'Person'}`, date: '', evidenceSource: '' };
          }
      }

      const newNode: Node = {
        id: getId(),
        type: nodeType,
        position,
        data: initialData,
      };

      setNodes((nds) => nds.concat(newNode));
      setSelectedNode(newNode);
      setSelectedEdge(null);
    },
    [screenToFlowPosition, setNodes, takeSnapshot],
  );

  const onNodeDragStart = useCallback(() => {
    // We snapshot on drag start to save position before move
    takeSnapshot();
  }, [takeSnapshot]);

  const onNodeClick = useCallback((_: React.MouseEvent, node: Node) => {
    setSelectedNode(node);
    setSelectedEdge(null);
  }, []);

  const onEdgeClick = useCallback((_: React.MouseEvent, edge: Edge) => {
    setSelectedEdge(edge);
    setSelectedNode(null);
  }, []);

  const onPaneClick = useCallback(() => {
    setSelectedNode(null);
    setSelectedEdge(null);
  }, []);

  const handleDeleteNode = useCallback((id: string) => {
    takeSnapshot(); // Snapshot before delete
    setNodes((nds) => nds.filter((n) => n.id !== id));
    setEdges((eds) => eds.filter((e) => e.source !== id && e.target !== id));
    setSelectedNode(null);
  }, [setNodes, setEdges, takeSnapshot]);

  const handleDeleteEdge = useCallback((id: string) => {
    takeSnapshot();
    setEdges((eds) => eds.filter((e) => e.id !== id));
    setSelectedEdge(null);
  }, [setEdges, takeSnapshot]);

  const handleAnalysis = async () => {
    if (nodes.length === 0) return;
    setIsAnalyzing(true);
    setAnalysis(null);
    try {
      const result = await analyzeBoard(nodes, edges);
      setAnalysis(result);
    } catch (e) {
      console.error(e);
      alert("Analysis failed. Please check your API configuration.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const kidnappingSidebarItems = [
    { type: 'victim', label: '👤 Victim' },
    { type: 'ransom', label: '💰 Ransom' },
    { type: 'hideout', label: '🏚️ Hideout' },
    { type: 'vehicle', label: '🚗 Vehicle' },
    { type: 'accomplice', label: '👥 Accomplice' },
    { type: 'communication', label: '📞 Comms' },
  ];

  return (
    <div className="flex h-screen w-full bg-slate-950 text-slate-200 font-sans selection:bg-amber-500/30">
      <Sidebar />

      <div className="flex-1 h-full relative" ref={reactFlowWrapper}>
        <ReactFlow
          nodes={nodes}
          edges={edges}
          onNodesChange={onNodesChange}
          onEdgesChange={onEdgesChange}
          onConnect={onConnect}
          onDrop={onDrop}
          onDragOver={onDragOver}
          onNodeDragStart={onNodeDragStart}
          onNodeClick={onNodeClick}
          onEdgeClick={onEdgeClick}
          onPaneClick={onPaneClick}
          nodeTypes={nodeTypes}
          fitView
          className="bg-slate-950"
        >
          <Controls className="!bg-slate-800 !border-slate-700 !fill-slate-400 [&>button]:!border-slate-700 hover:[&>button]:!bg-slate-700" />
          <Background color="#1e293b" gap={20} variant={BackgroundVariant.Dots} />

          <Panel position="top-right" className="flex flex-col gap-4 mt-20 md:mt-0 items-end">
            <div className="flex gap-2">
               {/* Mode Selector */}
               <div className="flex items-center bg-slate-800 rounded-lg p-1 border border-slate-700 shadow-lg px-2 gap-2">
                 <Briefcase className={`w-4 h-4 ${investigationType === InvestigationType.KIDNAPPING ? 'text-red-500' : 'text-slate-400'}`} />
                 <select 
                    value={manualMode}
                    onChange={(e) => setManualMode(e.target.value as any)}
                    className="bg-transparent text-sm font-medium text-slate-200 focus:outline-none cursor-pointer"
                 >
                   <option value="AUTO">Auto Detect</option>
                   <option value={InvestigationType.GENERAL}>General Case</option>
                   <option value={InvestigationType.KIDNAPPING}>Kidnapping</option>
                 </select>
               </div>

              {/* Undo/Redo */}
              <div className="flex bg-slate-800 rounded-lg p-1 border border-slate-700 shadow-lg">
                <button
                  onClick={undo}
                  disabled={past.length === 0}
                  className={`p-2 rounded hover:bg-slate-700 transition-colors ${past.length === 0 ? 'opacity-30 cursor-not-allowed' : 'text-slate-200'}`}
                  title="Undo (Ctrl+Z)"
                >
                  <Undo2 className="w-4 h-4" />
                </button>
                <div className="w-px bg-slate-700 my-1 mx-1" />
                <button
                  onClick={redo}
                  disabled={future.length === 0}
                  className={`p-2 rounded hover:bg-slate-700 transition-colors ${future.length === 0 ? 'opacity-30 cursor-not-allowed' : 'text-slate-200'}`}
                  title="Redo (Ctrl+Y)"
                >
                  <Redo2 className="w-4 h-4" />
                </button>
              </div>

              {/* Gemini Analysis Button */}
              <button 
                onClick={handleAnalysis}
                disabled={isAnalyzing || nodes.length === 0}
                className={`
                  flex items-center gap-2 px-4 py-2 rounded-lg font-medium text-sm shadow-lg transition-all
                  ${isAnalyzing 
                    ? 'bg-slate-800 text-slate-400 cursor-wait' 
                    : 'bg-amber-600 hover:bg-amber-500 text-white hover:scale-105 active:scale-95'}
                `}
              >
                {isAnalyzing ? (
                  <><Loader2 className="w-4 h-4 animate-spin" /> Analyzing...</>
                ) : (
                  <><BrainCircuit className="w-4 h-4" /> Analyze Case</>
                )}
              </button>
            </div>
          </Panel>

           {/* SIMULATION TOAST */}
          {simulationToast && (
             <div className="absolute top-20 left-1/2 -translate-x-1/2 z-50 animate-slide-in-bottom">
                <div className={`
                  flex items-center gap-3 px-4 py-3 rounded-lg shadow-2xl border backdrop-blur-md
                  ${simulationToast.type === 'success' 
                    ? 'bg-emerald-900/80 border-emerald-500/50 text-emerald-100' 
                    : 'bg-blue-900/80 border-blue-500/50 text-blue-100'}
                `}>
                  {simulationToast.type === 'success' ? (
                     <CheckCircle2 className="w-5 h-5 text-emerald-400" />
                  ) : (
                     <Radio className="w-5 h-5 text-blue-400 animate-pulse" />
                  )}
                  <div className="font-medium text-sm">{simulationToast.message}</div>
                </div>
             </div>
          )}

        </ReactFlow>

        {/* Local Analysis Widget */}
        {localAnalysis && (localAnalysis.redFlags.length > 0 || localAnalysis.ringleader) && (
          <div className="absolute top-20 right-4 w-80 bg-slate-900/95 border border-slate-700 rounded-lg p-4 shadow-xl z-40 animate-slide-in-right">
            <div className="flex items-center gap-2 mb-3">
              <ShieldAlert className="w-5 h-5 text-amber-500" />
              <h3 className="font-bold text-slate-200">Local Intelligence</h3>
              <span className="ml-auto text-xs bg-slate-800 px-2 py-1 rounded">
                {localAnalysis.redFlags.filter(f => f.severity === 'HIGH').length} 🔴
              </span>
            </div>

            {/* Ringleader */}
            {localAnalysis.ringleader && (
              <div className="mb-3 p-3 bg-slate-800/50 rounded border border-blue-500/30">
                <div className="flex items-center gap-2 text-blue-400 text-sm font-semibold mb-1">
                  <Crown className="w-4 h-4" />
                  Key Person of Interest
                </div>
                <div className="text-slate-300">
                  <div className="font-medium">{localAnalysis.ringleader.label}</div>
                  <div className="text-xs text-slate-400">
                    Connected to {localAnalysis.ringleader.connectionCount} entities
                  </div>
                </div>
              </div>
            )}

            {/* Red Flags Preview */}
            {localAnalysis.redFlags.slice(0, 3).map((flag, idx) => (
              <div key={idx} className={`mb-2 p-2 rounded border text-sm ${
                flag.severity === 'HIGH' 
                  ? 'bg-red-900/20 border-red-500/40' 
                  : 'bg-amber-900/20 border-amber-500/40'
              }`}>
                <div className="flex items-start gap-2">
                  <div className={`w-2 h-2 rounded-full mt-1.5 shrink-0 ${
                    flag.severity === 'HIGH' ? 'bg-red-500' : 'bg-amber-500'
                  }`} />
                  <div>
                    <div className="text-slate-300 leading-tight">{flag.message}</div>
                  </div>
                </div>
              </div>
            ))}

            <button 
              className="w-full text-xs text-center text-slate-400 hover:text-slate-200 py-1 bg-slate-800/50 rounded mt-1"
              onClick={() => setShowFullAnalysis(true)}
            >
              View Full Report {localAnalysis.redFlags.length > 3 ? `(+${localAnalysis.redFlags.length - 3} more)` : ''}
            </button>
          </div>
        )}

        {/* Kidnapping Dashboard Overlay - Only visible in Kidnapping Mode */}
        {investigationType === InvestigationType.KIDNAPPING && kidnapAnalysis && (
          <KidnappingDashboard 
            analysis={kidnapAnalysis}
            onAction={handleActionSimulation}
          />
        )}

        {/* Kidnapping Tools Palette - Only visible in Kidnapping Mode */}
        {investigationType === InvestigationType.KIDNAPPING && (
          <div className="absolute bottom-4 left-4 w-48 bg-red-900/80 backdrop-blur border border-red-500/50 rounded-lg p-3 z-40 animate-slide-in-bottom shadow-lg">
            <div className="text-xs text-red-200 font-bold mb-2 uppercase tracking-wider flex items-center gap-2">
               <AlertTriangle className="w-3 h-3" /> Kidnap Tools
            </div>
            <div className="grid grid-cols-2 gap-2">
              {kidnappingSidebarItems.map((item, idx) => (
                <div
                  key={idx}
                  draggable
                  onDragStart={(e) => {
                    e.dataTransfer.setData('application/reactflow', item.type);
                    e.dataTransfer.setData('kidnap', 'true');
                  }}
                  className="p-2 bg-slate-900/60 hover:bg-red-700/60 rounded text-center cursor-grab text-xs border border-red-500/30 text-slate-200 transition-colors"
                >
                  {item.label}
                </div>
              ))}
            </div>
          </div>
        )}

        <EditorPanel 
          selectedNode={selectedNode}
          selectedEdge={selectedEdge}
          setNodes={(newNodesOrUpdater) => {
             // Simplified update for nodes
             setNodes(newNodesOrUpdater);
          }}
          setEdges={(newEdgesOrUpdater) => {
            setEdges(newEdgesOrUpdater);
          }}
          onClose={() => {
            setSelectedNode(null);
            setSelectedEdge(null);
          }}
          deleteNode={handleDeleteNode}
          deleteEdge={handleDeleteEdge}
        />

        {/* Full Local Analysis Modal */}
        {showFullAnalysis && localAnalysis && (
          <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
            <div className="bg-slate-900 border border-slate-700 rounded-xl w-full max-w-4xl max-h-[85vh] overflow-y-auto p-6 shadow-2xl animate-in fade-in zoom-in-95 duration-200">
              <div className="flex justify-between items-center mb-6">
                <h2 className="text-xl font-bold text-slate-200 flex items-center gap-2">
                  <ShieldAlert className="w-6 h-6 text-amber-500" />
                  Complete Analysis Report
                </h2>
                <button 
                  onClick={() => setShowFullAnalysis(false)}
                  className="text-slate-500 hover:text-white transition-colors p-1"
                >
                  ✕
                </button>
              </div>

              {/* Ringleader Section */}
              {localAnalysis.ringleader && (
                <section className="mb-8 p-4 bg-slate-800/50 rounded-lg border border-slate-700">
                  <h3 className="text-sm font-semibold text-blue-400 mb-3 uppercase tracking-wide">Key Subject</h3>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <div className="text-sm text-slate-400">Primary Person of Interest</div>
                      <div className="text-xl font-bold text-slate-200">{localAnalysis.ringleader.label}</div>
                    </div>
                    <div>
                      <div className="text-sm text-slate-400">Network Connections</div>
                      <div className="text-xl font-bold text-slate-200">
                        {localAnalysis.ringleader.connectionCount} direct links
                      </div>
                    </div>
                  </div>
                </section>
              )}

              {/* Red Flags */}
              <section className="mb-8">
                <h3 className="text-lg font-semibold text-slate-200 mb-3 flex items-center gap-2">
                  <AlertTriangle className="w-5 h-5 text-amber-500" />
                  Investigation Alerts ({localAnalysis.redFlags.length})
                </h3>
                <div className="space-y-3">
                  {localAnalysis.redFlags.map((flag, idx) => {
                    const affectedNodeNames = flag.affectedNodeIds.map(id => {
                      const node = nodes.find(n => n.id === id);
                      return node ? (node.data as NodeData).label || id : id;
                    }).join(', ');

                    return (
                    <div key={idx} className={`p-4 rounded-lg border ${
                      flag.severity === 'HIGH' 
                        ? 'border-red-500/30 bg-red-900/10' 
                        : 'border-amber-500/30 bg-amber-900/10'
                    }`}>
                      <div className="flex items-center gap-3 mb-2">
                        <div className={`w-3 h-3 rounded-full ${
                          flag.severity === 'HIGH' ? 'bg-red-500' : 'bg-amber-500'
                        }`} />
                        <span className="font-medium text-slate-200">{flag.type.replace('_', ' ')}</span>
                        <span className={`px-2 py-0.5 rounded text-[10px] uppercase font-bold tracking-wider ${
                          flag.severity === 'HIGH' 
                            ? 'bg-red-500/20 text-red-300' 
                            : 'bg-amber-500/20 text-amber-300'
                        }`}>
                          {flag.severity}
                        </span>
                      </div>
                      <p className="text-slate-300 mb-2">{flag.message}</p>
                      {flag.evidence && (
                        <p className="text-sm text-slate-500 italic">Suggested: {flag.evidence}</p>
                      )}
                      <div className="text-xs text-slate-400 mt-2 pt-2 border-t border-slate-700/50">
                        Affects: {affectedNodeNames}
                      </div>
                    </div>
                  )})}
                </div>
              </section>

              {/* Financial Patterns */}
              {localAnalysis.financialPatterns.length > 0 && (
                <section className="mb-8">
                  <h3 className="text-lg font-semibold text-slate-200 mb-3">
                    Financial Patterns ({localAnalysis.financialPatterns.length})
                  </h3>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                    {localAnalysis.financialPatterns.map((pattern, idx) => (
                      <div key={idx} className="p-3 bg-slate-800/30 rounded border border-slate-700">
                        <div className="text-xs text-slate-400 mb-1">{pattern.type.replace('_', ' ')}</div>
                        <div className="text-slate-200 font-medium">{pattern.description}</div>
                        {pattern.amount && (
                          <div className="text-xs text-emerald-400 mt-1">
                            ₦{pattern.amount.toLocaleString('en-NG')}
                          </div>
                        )}
                      </div>
                    ))}
                  </div>
                </section>
              )}

              {/* Geographical Clusters */}
              {localAnalysis.geographicalClusters.length > 0 && (
                <section className="mb-8">
                  <h3 className="text-lg font-semibold text-slate-200 mb-3 flex items-center gap-2">
                    <MapPin className="w-5 h-5 text-blue-500" />
                    Geographical Analysis
                  </h3>
                  <div className="space-y-3">
                    {localAnalysis.geographicalClusters.map((cluster, idx) => (
                      <div key={idx} className="p-3 bg-slate-800/30 rounded border border-slate-700">
                        <div className="flex justify-between items-center">
                          <div>
                            <div className="text-slate-200 font-medium">{cluster.location}</div>
                            <div className="text-sm text-slate-400">{cluster.nodes.length} related events</div>
                          </div>
                        </div>
                        <div className="text-xs text-slate-500 mt-2 bg-slate-900/50 p-2 rounded">
                            Strategy: {cluster.suggestion}
                        </div>
                      </div>
                    ))}
                  </div>
                </section>
              )}

              {/* Timeline Gaps */}
              {localAnalysis.timelineGaps.length > 0 && (
                <section>
                  <h3 className="text-lg font-semibold text-slate-200 mb-3">
                    Timeline Gaps ({localAnalysis.timelineGaps.length})
                  </h3>
                  <div className="space-y-2">
                    {localAnalysis.timelineGaps.map((gap, idx) => {
                      return (
                        <div key={idx} className="p-3 bg-slate-800/30 rounded border border-slate-800">
                          <div className="text-slate-300 text-sm">{gap.message}</div>
                          <div className="text-sm text-slate-500 mt-1">
                            <span className="text-slate-400">Suggestion:</span> {gap.suggestion}
                          </div>
                        </div>
                      );
                    })}
                  </div>
                </section>
              )}
            </div>
          </div>
        )}

        {/* AI Analysis Result Overlay (Gemini) */}
        {analysis && !isAnalyzing && (
          <div className="absolute bottom-6 left-6 right-6 md:left-20 md:right-auto md:w-[500px] bg-slate-900/95 backdrop-blur border border-amber-500/30 rounded-xl shadow-2xl p-6 animate-slide-in-bottom z-50 max-h-[40vh] overflow-y-auto">
            <div className="flex justify-between items-start mb-4">
              <h3 className="text-lg font-bold text-amber-500 flex items-center gap-2">
                <Sparkles className="w-5 h-5" /> Gemini Intelligence Summary
              </h3>
              <button 
                onClick={() => setAnalysis(null)}
                className="text-slate-500 hover:text-slate-300"
              >
                <span className="sr-only">Close</span>
                ✕
              </button>
            </div>

            <div className="space-y-4 text-sm text-slate-300">
              <div className="bg-slate-800/50 p-3 rounded border border-slate-700">
                <p className="leading-relaxed">{analysis.summary}</p>
              </div>

              {analysis.gaps.length > 0 && (
                <div>
                  <h4 className="font-semibold text-slate-200 mb-2 flex items-center gap-2">
                    <AlertTriangle className="w-4 h-4 text-red-400" /> Missing Intel / Gaps
                  </h4>
                  <ul className="list-disc pl-5 space-y-1 text-slate-400">
                    {analysis.gaps.map((gap, i) => (
                      <li key={i}>{gap}</li>
                    ))}
                  </ul>
                </div>
              )}

              {analysis.connections.length > 0 && (
                <div>
                  <h4 className="font-semibold text-slate-200 mb-2 flex items-center gap-2">
                    <Link2 className="w-4 h-4 text-blue-400" /> Inferred Connections
                  </h4>
                  <ul className="list-disc pl-5 space-y-1 text-slate-400">
                    {analysis.connections.map((conn, i) => (
                      <li key={i}>{conn}</li>
                    ))}
                  </ul>
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useCallback, useRef, useState, useEffect } from 'react';
import {
  ReactFlow,
  ReactFlowProvider,
  addEdge,
  useNodesState,
  useEdgesState,
  Controls,
  Background,
  Connection,
  Edge,
  Node,
  BackgroundVariant,
  useReactFlow,
  Panel,
  NodeChange,
  EdgeChange,
} from '@xyflow/react';

import { Sidebar } from './components/Sidebar';
import { EditorPanel } from './components/EditorPanel';
import { EventNode, PersonNode } from './components/CustomNodes';
import { NodeType, AnalysisResult, InvestigationType, NodeData } from './types';
import { analyzeBoard } from './services/geminiService';
import { analyzeKidnappingCase, KidnappingAnalysis } from './services/kidnappingAnalysis';
import { runLocalAnalysis, LocalAnalysisResult } from './services/localAnalysis';
import { KidnappingDashboard } from './components/KidnappingDashboard';
import { 
  BrainCircuit, 
  Loader2, 
  Sparkles, 
  AlertTriangle, 
  Link2,
  ShieldAlert, 
  Crown, 
  MapPin,
  Undo2,
  Redo2,
  History,
  Briefcase,
  CheckCircle2,
  Radio
} from 'lucide-react';

// Define custom node types outside component to prevent re-creation
const nodeTypes = {
  [NodeType.EVENT]: EventNode,
  [NodeType.PERSON]: PersonNode,
};

let id = 100;
const getId = () => `dndnode_${id++}`;

// Interface for History
interface HistoryState {
  nodes: Node[];
  edges: Edge[];
}

const InvestigationCanvas = () => {
  const reactFlowWrapper = useRef<HTMLDivElement>(null);

  // INITIAL STATE: Preset kidnapping scenario
  const [nodes, setNodes, onNodesChange] = useNodesState<Node>([
    {
      id: '1',
      type: NodeType.PERSON,
      position: { x: 400, y: 100 },
      data: { 
        label: 'Dr. Amara Okeke', 
        role: 'victim',
        age: 45,
        occupation: 'Oil Executive',
        medicalCondition: 'Hypertension',
        abductionTime: new Date(Date.now() - 1000 * 60 * 60 * 24).toISOString(), // 24 hours ago
        evidenceSource: 'Family Report',
      },
    },
    {
      id: '2',
      type: NodeType.EVENT,
      position: { x: 400, y: 300 },
      data: { 
        label: 'Abduction at Lekki', 
        date: new Date(Date.now() - 1000 * 60 * 60 * 24).toISOString(),
        location: 'Lekki Phase 1',
        evidenceSource: 'CCTV Footage'
      },
    },
    {
      id: '3',
      type: NodeType.EVENT,
      position: { x: 700, y: 300 },
      data: { 
        label: 'Ransom Call', 
        type: 'communication',
        date: new Date(Date.now() - 1000 * 60 * 60 * 2).toISOString(), // 2 hours ago
        amount: 50000000,
        deadline: new Date(Date.now() + 1000 * 60 * 60 * 48).toISOString(), // 48 hours from now
        evidenceSource: 'Recorded Call #001'
      },
    },
  ]);
  const [edges, setEdges, onEdgesChange] = useEdgesState<Edge>([
    { id: 'e1-2', source: '1', target: '2', label: 'Abducted at', animated: true, style: { stroke: '#ef4444', strokeWidth: 2 } },
    { id: 'e1-3', source: '1', target: '3', label: 'Subject of', animated: true, style: { stroke: '#eab308', strokeWidth: 2 } },
  ]);

  const { screenToFlowPosition } = useReactFlow();

  const [selectedNode, setSelectedNode] = useState<Node | null>(null);
  const [selectedEdge, setSelectedEdge] = useState<Edge | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [localAnalysis, setLocalAnalysis] = useState<LocalAnalysisResult | null>(null);

  // Investigation Mode State
  const [manualMode, setManualMode] = useState<InvestigationType | 'AUTO'>('AUTO');
  const [investigationType, setInvestigationType] = useState<InvestigationType>(InvestigationType.GENERAL);

  const [kidnapAnalysis, setKidnapAnalysis] = useState<KidnappingAnalysis | null>(null);
  const [showFullAnalysis, setShowFullAnalysis] = useState(false);

  // Simulation / Toast State
  const [simulationToast, setSimulationToast] = useState<{message: string, type: 'info' | 'success'} | null>(null);

  // --- HISTORY MANAGEMENT ---
  const [past, setPast] = useState<HistoryState[]>([]);
  const [future, setFuture] = useState<HistoryState[]>([]);

  // Function to take a snapshot of the current state BEFORE an action
  const takeSnapshot = useCallback(() => {
    setPast((prev) => {
      // Limit history to 20 steps to prevent memory bloat
      const newPast = [...prev, { nodes, edges }];
      return newPast.length > 20 ? newPast.slice(1) : newPast;
    });
    setFuture([]);
  }, [nodes, edges]);

  const undo = useCallback(() => {
    if (past.length === 0) return;

    const previous = past[past.length - 1];
    const newPast = past.slice(0, past.length - 1);

    setFuture((prev) => [{ nodes, edges }, ...prev]);
    setNodes(previous.nodes);
    setEdges(previous.edges);
    setPast(newPast);
    setSelectedNode(null); // Clear selection
    setSelectedEdge(null);
  }, [past, nodes, edges, setNodes, setEdges]);

  const redo = useCallback(() => {
    if (future.length === 0) return;

    const next = future[0];
    const newFuture = future.slice(1);

    setPast((prev) => [...prev, { nodes, edges }]);
    setNodes(next.nodes);
    setEdges(next.edges);
    setFuture(newFuture);
    setSelectedNode(null);
    setSelectedEdge(null);
  }, [future, nodes, edges, setNodes, setEdges]);

  // Keyboard Shortcuts for Undo/Redo
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Check if user is typing in an input field
      if (['INPUT', 'TEXTAREA'].includes((e.target as HTMLElement).tagName)) return;

      if ((e.metaKey || e.ctrlKey) && e.key === 'z') {
        e.preventDefault();
        if (e.shiftKey) {
          redo();
        } else {
          undo();
        }
      }
      if ((e.metaKey || e.ctrlKey) && (e.key === 'y')) {
        e.preventDefault();
        redo();
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [undo, redo]);

  // --- ANALYSIS EFFECTS ---
  useEffect(() => {
    if (nodes.length > 0) {
      // 1. Run Local Analysis
      const localResults = runLocalAnalysis(nodes, edges);
      setLocalAnalysis(localResults);

      // 2. Check for Kidnapping Context Keywords
      const hasKidnapKeywords = nodes.some(n => {
        const data = n.data as NodeData;
        return data.role === 'victim' || 
        data.type === 'kidnapping' ||
        data.description?.toLowerCase().includes('abduct') ||
        data.label?.toLowerCase().includes('kidnap') ||
        data.label?.toLowerCase().includes('ransom');
      });

      // 3. Determine Mode (Manual Override > Auto Detection)
      let activeType = InvestigationType.GENERAL;

      if (manualMode !== 'AUTO') {
        activeType = manualMode;
      } else if (hasKidnapKeywords) {
        activeType = InvestigationType.KIDNAPPING;
      }

      setInvestigationType(activeType);

      // 4. Run Specific Analyzers based on type
      if (activeType === InvestigationType.KIDNAPPING) {
        const kAnalysis = analyzeKidnappingCase(nodes, edges);
        setKidnapAnalysis(kAnalysis);
      } else {
        setKidnapAnalysis(null);
      }
    } else {
        // Even with no nodes, if manual mode is kidnapping, show empty dashboard? 
        // Better to allow it so tools palette appears.
        if (manualMode === InvestigationType.KIDNAPPING) {
            setInvestigationType(InvestigationType.KIDNAPPING);
            const kAnalysis = analyzeKidnappingCase(nodes, edges); // Will return defaults
            setKidnapAnalysis(kAnalysis);
        } else {
            setInvestigationType(InvestigationType.GENERAL);
            setKidnapAnalysis(null);
        }
    }
  }, [nodes, edges, manualMode]);

  // --- HANDLERS ---

  const handleActionSimulation = (action: string) => {
    let message = '';
    let type: 'info' | 'success' = 'info';

    switch (action) {
      case 'activate_irt':
        message = 'Dispatching Intelligence Response Team (IRT)...';
        break;
      case 'track_phones':
        message = 'Triangulating GSM Signals...';
        break;
      case 'setup_roadblocks':
        message = 'Alerting State Commands & Highway Patrol...';
        break;
      case 'contact_family':
        message = 'Initiating Secure Line with Family Liaison...';
        break;
      default:
        message = 'Processing Action...';
    }

    // Step 1: Show Processing
    setSimulationToast({ message, type: 'info' });

    // Step 2: Show Success after delay
    setTimeout(() => {
      let successMsg = '';
      switch (action) {
        case 'activate_irt': successMsg = 'IRT Units Deployed & Active'; break;
        case 'track_phones': successMsg = 'Signal Locked: Cell ID #4922 (Approximation)'; break;
        case 'setup_roadblocks': successMsg = 'Gridlock Protocol Active in 3 Zones'; break;
        case 'contact_family': successMsg = 'Secure Channel Established'; break;
        default: successMsg = 'Action Completed';
      }
      setSimulationToast({ message: successMsg, type: 'success' });

      // Clear after delay
      setTimeout(() => setSimulationToast(null), 3000);
    }, 1500);
  };

  const onConnect = useCallback(
    (params: Connection) => {
      takeSnapshot(); // Snapshot before connecting
      setEdges((eds) => addEdge({ ...params, type: 'default', animated: true, style: { stroke: '#64748b', strokeWidth: 2 } } as Edge, eds));
    },
    [setEdges, takeSnapshot],
  );

  const onDragOver = useCallback((event: React.DragEvent) => {
    event.preventDefault();
    event.dataTransfer.dropEffect = 'move';
  }, []);

  const onDrop = useCallback(
    (event: React.DragEvent) => {
      event.preventDefault();
      takeSnapshot(); // Snapshot before dropping

      const typeStr = event.dataTransfer.getData('application/reactflow');
      const isKidnapTool = event.dataTransfer.getData('kidnap') === 'true';

      let nodeType: NodeType | undefined = undefined;

      if (Object.values(NodeType).includes(typeStr as NodeType)) {
        nodeType = typeStr as NodeType;
      }

      if (!nodeType && !isKidnapTool) {
          if (['location', 'evidence'].includes(typeStr)) {
             nodeType = NodeType.EVENT;
          } else if (typeStr === 'organization') {
             nodeType = NodeType.PERSON;
          } else {
             nodeType = NodeType.EVENT;
          }
      }

      const position = screenToFlowPosition({
        x: event.clientX,
        y: event.clientY,
      });

      let initialData: any = { label: 'New Node' };

      if (isKidnapTool) {
         const toolType = typeStr; 
         if (toolType === 'victim') {
             nodeType = NodeType.PERSON;
             initialData = { label: 'Victim', role: 'victim', medicalCondition: '', abductionTime: new Date().toISOString() };
         } else if (toolType === 'ransom') {
             nodeType = NodeType.EVENT;
             initialData = { label: 'Ransom Demand', type: 'communication', amount: 5000000 };
         } else {
             nodeType = NodeType.EVENT;
             initialData = { label: toolType.charAt(0).toUpperCase() + toolType.slice(1), role: toolType };
         }
      } else {
          if (typeStr === 'location') {
              initialData = { label: 'New Location', location: 'Unknown Location', type: 'location' };
          } else if (typeStr === 'evidence') {
              initialData = { label: 'New Evidence', evidenceSource: 'TBD', type: 'evidence' };
          } else if (typeStr === 'organization') {
              initialData = { label: 'New Organization', type: 'organization' };
          } else {
             initialData = { label: `New ${nodeType === NodeType.EVENT ? 'Event' : 'Person'}`, date: '', evidenceSource: '' };
          }
      }

      const newNode: Node = {
        id: getId(),
        type: nodeType,
        position,
        data: initialData,
      };

      setNodes((nds) => nds.concat(newNode));
      setSelectedNode(newNode);
      setSelectedEdge(null);
    },
    [screenToFlowPosition, setNodes, takeSnapshot],
  );

  const onNodeDragStart = useCallback(() => {
    // We snapshot on drag start to save position before move
    takeSnapshot();
  }, [takeSnapshot]);

  const onNodeClick = useCallback((_: React.MouseEvent, node: Node) => {
    setSelectedNode(node);
    setSelectedEdge(null);
  }, []);

  const onEdgeClick = useCallback((_: React.MouseEvent, edge: Edge) => {
    setSelectedEdge(edge);
    setSelectedNode(null);
  }, []);

  const onPaneClick = useCallback(() => {
    setSelectedNode(null);
    setSelectedEdge(null);
  }, []);

  const handleDeleteNode = useCallback((id: string) => {
    takeSnapshot(); // Snapshot before delete
    setNodes((nds) => nds.filter((n) => n.id !== id));
    setEdges((eds) => eds.filter((e) => e.source !== id && e.target !== id));
    setSelectedNode(null);
  }, [setNodes, setEdges, takeSnapshot]);

  const handleDeleteEdge = useCallback((id: string) => {
    takeSnapshot();
    setEdges((eds) => eds.filter((e) => e.id !== id));
    setSelectedEdge(null);
  }, [setEdges, takeSnapshot]);

  const handleAnalysis = async () => {
    if (nodes.length === 0) return;
    setIsAnalyzing(true);
    setAnalysis(null);
    try {
      const result = await analyzeBoard(nodes, edges);
      setAnalysis(result);
    } catch (e) {
      console.error(e);
      alert("Analysis failed. Please check your API configuration.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const kidnappingSidebarItems = [
    { type: 'victim', label: '👤 Victim' },
    { type: 'ransom', label: '💰 Ransom' },
    { type: 'hideout', label: '🏚️ Hideout' },
    { type: 'vehicle', label: '🚗 Vehicle' },
    { type: 'accomplice', label: '👥 Accomplice' },
    { type: 'communication', label: '📞 Comms' },
  ];

  return (
    <div className="flex h-screen w-full bg-slate-950 text-slate-200 font-sans selection:bg-amber-500/30">
      <Sidebar />

      <div className="flex-1 h-full relative" ref={reactFlowWrapper}>
        <ReactFlow
          nodes={nodes}
          edges={edges}
          onNodesChange={onNodesChange}
          onEdgesChange={onEdgesChange}
          onConnect={onConnect}
          onDrop={onDrop}
          onDragOver={onDragOver}
          onNodeDragStart={onNodeDragStart}
          onNodeClick={onNodeClick}
          onEdgeClick={onEdgeClick}
          onPaneClick={onPaneClick}
          nodeTypes={nodeTypes}
          fitView
          className="bg-slate-950"
        >
          <Controls className="!bg-slate-800 !border-slate-700 !fill-slate-400 [&>button]:!border-slate-700 hover:[&>button]:!bg-slate-700" />
          <Background color="#1e293b" gap={20} variant={BackgroundVariant.Dots} />

          <Panel position="top-right" className="flex flex-col gap-4 mt-20 md:mt-0 items-end">
            <div className="flex gap-2">
               {/* Mode Selector */}
               <div className="flex items-center bg-slate-800 rounded-lg p-1 border border-slate-700 shadow-lg px-2 gap-2">
                 <Briefcase className={`w-4 h-4 ${investigationType === InvestigationType.KIDNAPPING ? 'text-red-500' : 'text-slate-400'}`} />
                 <select 
                    value={manualMode}
                    onChange={(e) => setManualMode(e.target.value as any)}
                    className="bg-transparent text-sm font-medium text-slate-200 focus:outline-none cursor-pointer"
                 >
                   <option value="AUTO">Auto Detect</option>
                   <option value={InvestigationType.GENERAL}>General Case</option>
                   <option value={InvestigationType.KIDNAPPING}>Kidnapping</option>
                 </select>
               </div>

              {/* Undo/Redo */}
              <div className="flex bg-slate-800 rounded-lg p-1 border border-slate-700 shadow-lg">
                <button
                  onClick={undo}
                  disabled={past.length === 0}
                  className={`p-2 rounded hover:bg-slate-700 transition-colors ${past.length === 0 ? 'opacity-30 cursor-not-allowed' : 'text-slate-200'}`}
                  title="Undo (Ctrl+Z)"
                >
                  <Undo2 className="w-4 h-4" />
                </button>
                <div className="w-px bg-slate-700 my-1 mx-1" />
                <button
                  onClick={redo}
                  disabled={future.length === 0}
                  className={`p-2 rounded hover:bg-slate-700 transition-colors ${future.length === 0 ? 'opacity-30 cursor-not-allowed' : 'text-slate-200'}`}
                  title="Redo (Ctrl+Y)"
                >
                  <Redo2 className="w-4 h-4" />
                </button>
              </div>

              {/* Gemini Analysis Button */}
              <button 
                onClick={handleAnalysis}
                disabled={isAnalyzing || nodes.length === 0}
                className={`
                  flex items-center gap-2 px-4 py-2 rounded-lg font-medium text-sm shadow-lg transition-all
                  ${isAnalyzing 
                    ? 'bg-slate-800 text-slate-400 cursor-wait' 
                    : 'bg-amber-600 hover:bg-amber-500 text-white hover:scale-105 active:scale-95'}
                `}
              >
                {isAnalyzing ? (
                  <><Loader2 className="w-4 h-4 animate-spin" /> Analyzing...</>
                ) : (
                  <><BrainCircuit className="w-4 h-4" /> Analyze Case</>
                )}
              </button>
            </div>
          </Panel>

           {/* SIMULATION TOAST */}
          {simulationToast && (
             <div className="absolute top-20 left-1/2 -translate-x-1/2 z-50 animate-slide-in-bottom">
                <div className={`
                  flex items-center gap-3 px-4 py-3 rounded-lg shadow-2xl border backdrop-blur-md
                  ${simulationToast.type === 'success' 
                    ? 'bg-emerald-900/80 border-emerald-500/50 text-emerald-100' 
                    : 'bg-blue-900/80 border-blue-500/50 text-blue-100'}
                `}>
                  {simulationToast.type === 'success' ? (
                     <CheckCircle2 className="w-5 h-5 text-emerald-400" />
                  ) : (
                     <Radio className="w-5 h-5 text-blue-400 animate-pulse" />
                  )}
                  <div className="font-medium text-sm">{simulationToast.message}</div>
                </div>
             </div>
          )}

        </ReactFlow>

        {/* Local Analysis Widget */}
        {localAnalysis && (localAnalysis.redFlags.length > 0 || localAnalysis.ringleader) && (
          <div className="absolute top-20 right-4 w-80 bg-slate-900/95 border border-slate-700 rounded-lg p-4 shadow-xl z-40 animate-slide-in-right">
            <div className="flex items-center gap-2 mb-3">
              <ShieldAlert className="w-5 h-5 text-amber-500" />
              <h3 className="font-bold text-slate-200">Local Intelligence</h3>
              <span className="ml-auto text-xs bg-slate-800 px-2 py-1 rounded">
                {localAnalysis.redFlags.filter(f => f.severity === 'HIGH').length} 🔴
              </span>
            </div>

            {/* Ringleader */}
            {localAnalysis.ringleader && (
              <div className="mb-3 p-3 bg-slate-800/50 rounded border border-blue-500/30">
                <div className="flex items-center gap-2 text-blue-400 text-sm font-semibold mb-1">
                  <Crown className="w-4 h-4" />
                  Key Person of Interest
                </div>
                <div className="text-slate-300">
                  <div className="font-medium">{localAnalysis.ringleader.label}</div>
                  <div className="text-xs text-slate-400">
                    Connected to {localAnalysis.ringleader.connectionCount} entities
                  </div>
                </div>
              </div>
            )}

            {/* Red Flags Preview */}
            {localAnalysis.redFlags.slice(0, 3).map((flag, idx) => (
              <div key={idx} className={`mb-2 p-2 rounded border text-sm ${
                flag.severity === 'HIGH' 
                  ? 'bg-red-900/20 border-red-500/40' 
                  : 'bg-amber-900/20 border-amber-500/40'
              }`}>
                <div className="flex items-start gap-2">
                  <div className={`w-2 h-2 rounded-full mt-1.5 shrink-0 ${
                    flag.severity === 'HIGH' ? 'bg-red-500' : 'bg-amber-500'
