let id = 100;
const getId = () => `dndnode_${id++}`;

// Interface for History
interface HistoryState {
  nodes: Node[];
  edges: Edge[];
}

const InvestigationCanvas = () => {
  const reactFlowWrapper = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // INITIAL STATE: Preset kidnapping scenario
  const [nodes, setNodes, onNodesChange] = useNodesState<Node>([
    {
      id: '1',
      type: NodeType.PERSON,
      position: { x: 400, y: 100 },
      data: { 
        label: 'Dr. Amara Okeke', 
        role: 'victim',
        age: 45,
        occupation: 'Oil Executive',
        medicalCondition: 'Hypertension',
        abductionTime: new Date(Date.now() - 1000 * 60 * 60 * 24).toISOString(), // 24 hours ago
        evidenceSource: 'Family Report',
      },
    },
    {
      id: '2',
      type: NodeType.EVENT,
      position: { x: 400, y: 300 },
      data: { 
        label: 'Abduction at Lekki', 
        date: new Date(Date.now() - 1000 * 60 * 60 * 24).toISOString(),
        location: 'Lekki Phase 1',
        evidenceSource: 'CCTV Footage'
      },
    },
    {
      id: '3',
      type: NodeType.EVENT,
      position: { x: 700, y: 300 },
      data: { 
        label: 'Ransom Call', 
        type: 'communication',
        date: new Date(Date.now() - 1000 * 60 * 60 * 2).toISOString(), // 2 hours ago
        amount: 50000000,
        deadline: new Date(Date.now() + 1000 * 60 * 60 * 48).toISOString(), // 48 hours from now
        evidenceSource: 'Recorded Call #001'
      },
    },
  ]);
  const [edges, setEdges, onEdgesChange] = useEdgesState<Edge>([
    { id: 'e1-2', source: '1', target: '2', label: 'Abducted at', type: 'deletable', animated: true, style: { stroke: '#ef4444', strokeWidth: 2 } },
    { id: 'e1-3', source: '1', target: '3', label: 'Subject of', type: 'deletable', animated: true, style: { stroke: '#eab308', strokeWidth: 2 } },
  ]);

  const { screenToFlowPosition, setViewport } = useReactFlow();

  const [selectedNode, setSelectedNode] = useState<Node | null>(null);
  const [selectedEdge, setSelectedEdge] = useState<Edge | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [localAnalysis, setLocalAnalysis] = useState<LocalAnalysisResult | null>(null);

  // Analysis Options State
  const [showAnalysisOptions, setShowAnalysisOptions] = useState(false);

  // Investigation Mode State
  const [manualMode, setManualMode] = useState<InvestigationType | 'AUTO'>('AUTO');
  const [investigationType, setInvestigationType] = useState<InvestigationType>(InvestigationType.GENERAL);

  const [kidnapAnalysis, setKidnapAnalysis] = useState<KidnappingAnalysis | null>(null);
  const [showFullAnalysis, setShowFullAnalysis] = useState(false);

  // VISIBILITY STATE FOR DIRECTOR MODE
  const [showDirectorMode, setShowDirectorMode] = useState(false);
  const [showResetConfirm, setShowResetConfirm] = useState(false);

  // Simulation / Toast State
  const [simulationToast, setSimulationToast] = useState<{message: string, type: 'info' | 'success'} | null>(null);

  // --- HISTORY MANAGEMENT ---
  const [past, setPast] = useState<HistoryState[]>([]);
  const [future, setFuture] = useState<HistoryState[]>([]);

  // --- PERSISTENCE & EXPORT ---

  useEffect(() => {
    const saveData = { nodes, edges };
    localStorage.setItem('intelboard_autosave', JSON.stringify(saveData));
  }, [nodes, edges]);

  useEffect(() => {
    // 1. Check URL params
    const params = new URLSearchParams(window.location.search);
    if (params.get('mode') === 'director') {
      setShowDirectorMode(true);
    }

    const saved = localStorage.getItem('intelboard_autosave');
    if (saved) {
      // Load saved state logic if needed
    }
  }, []);

  const handleExportCase = () => {
    const dataStr = JSON.stringify({ nodes, edges, investigationType }, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `case-export-${new Date().toISOString().slice(0, 10)}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    setSimulationToast({ message: 'Case File Saved Successfully', type: 'success' });
    setTimeout(() => setSimulationToast(null), 3000);
  };

  const handleDownloadPDF = () => {
    if (!localAnalysis) return;

    const doc = new jsPDF();
    const pageWidth = doc.internal.pageSize.getWidth();
    let yPos = 20;
    const margin = 20;
    const contentWidth = pageWidth - (margin * 2);

    // Helper for wrapping text
    const addWrappedText = (text: string, y: number, fontSize: number = 10, isBold: boolean = false) => {
      doc.setFontSize(fontSize);
      doc.setFont("helvetica", isBold ? "bold" : "normal");
      const lines = doc.splitTextToSize(text, contentWidth);
      doc.text(lines, margin, y);
      return y + (lines.length * (fontSize / 2)) + 4; // Return next Y position
    };

    // --- TITLE ---
    doc.setFontSize(22);
    doc.setTextColor(40, 40, 40);
    doc.text("IntelBoard Investigation Report", pageWidth / 2, yPos, { align: 'center' });
    yPos += 10;

    doc.setFontSize(10);
    doc.setTextColor(100, 100, 100);
    doc.text(`Generated: ${new Date().toLocaleString()}`, pageWidth / 2, yPos, { align: 'center' });
    yPos += 20;

    doc.setLineWidth(0.5);
    doc.setDrawColor(200, 200, 200);
    doc.line(margin, yPos, pageWidth - margin, yPos);
    yPos += 10;

    // --- RINGLEADER ---
    if (localAnalysis.ringleader) {
      doc.setFillColor(240, 245, 255); // Light blue bg
      doc.rect(margin, yPos, contentWidth, 25, 'F');

      doc.setFontSize(14);
      doc.setTextColor(0, 50, 150);
      doc.text("Primary Person of Interest", margin + 5, yPos + 8);

      doc.setFontSize(12);
      doc.setTextColor(0, 0, 0);
      doc.text(`Name: ${localAnalysis.ringleader.label}`, margin + 5, yPos + 16);
      doc.setFontSize(10);
      doc.setTextColor(80, 80, 80);
      doc.text(`Network Connections: ${localAnalysis.ringleader.connectionCount}`, margin + 5, yPos + 22);

      yPos += 35;
    }

    // --- RED FLAGS ---
    if (localAnalysis.redFlags.length > 0) {
      doc.setFontSize(16);
      doc.setTextColor(200, 0, 0);
      doc.text(`Investigation Alerts (${localAnalysis.redFlags.length})`, margin, yPos);
      yPos += 10;

      localAnalysis.redFlags.forEach((flag) => {
        if (yPos > 270) { doc.addPage(); yPos = 20; }

        doc.setFontSize(11);
        doc.setTextColor(0, 0, 0);
        doc.setFont("helvetica", "bold");
        doc.text(`• ${flag.type.replace('_', ' ')} [${flag.severity}]`, margin, yPos);
        yPos += 5;

        doc.setFont("helvetica", "normal");
        doc.setTextColor(60, 60, 60);
        yPos = addWrappedText(flag.message, yPos, 10);

        if (flag.evidence) {
           doc.setFont("helvetica", "italic");
           yPos = addWrappedText(`Suggestion: ${flag.evidence}`, yPos, 9);
        }
        yPos += 5;
      });
      yPos += 10;
    }

    // --- FINANCIAL PATTERNS ---
    if (localAnalysis.financialPatterns.length > 0) {
      if (yPos > 260) { doc.addPage(); yPos = 20; }
      doc.setFontSize(16);
      doc.setTextColor(0, 100, 0);
      doc.text("Financial Intelligence", margin, yPos);
      yPos += 10;

      localAnalysis.financialPatterns.forEach((pattern) => {
        doc.setFontSize(11);
        doc.setTextColor(0, 0, 0);
        yPos = addWrappedText(`${pattern.description}`, yPos, 10, true);
        if (pattern.amount) {
          doc.text(`Amount: N${pattern.amount.toLocaleString()}`, margin + 5, yPos - 2); // adjust slightly
          yPos += 5;
        }
        yPos += 3;
      });
       yPos += 10;
    }

    // --- GEOGRAPHICAL ---
    if (localAnalysis.geographicalClusters.length > 0) {
       if (yPos > 260) { doc.addPage(); yPos = 20; }
       doc.setFontSize(16);
       doc.setTextColor(0, 0, 150);
       doc.text("Geographical Analysis", margin, yPos);
       yPos += 10;

       localAnalysis.geographicalClusters.forEach((cluster) => {
          yPos = addWrappedText(`${cluster.location}: ${cluster.nodes.length} events`, yPos, 11, true);
          yPos = addWrappedText(`Strategy: ${cluster.suggestion}`, yPos, 10);
          yPos += 5;
       });
    }

    doc.save(`intelboard-report-${new Date().toISOString().slice(0,10)}.pdf`);
  };

  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const result = JSON.parse(event.target?.result as string);
        if (result.nodes && result.edges) {
          takeSnapshot();
          setNodes(result.nodes);
          setEdges(result.edges);
          if (result.investigationType) setManualMode(result.investigationType);
          setSimulationToast({ message: 'Case File Loaded Successfully', type: 'success' });
          setTimeout(() => setSimulationToast(null), 3000);
        } else {
          alert('Invalid case file format');
        }
      } catch (err) {
        console.error(err);
        alert('Failed to parse case file');
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  const handleResetBoardClick = () => {
    setShowResetConfirm(true);
  };

  const executeResetBoard = () => {
      takeSnapshot(); // Crucial: Save state before wiping so user can Undo
      setNodes([]);
      setEdges([]);
      setAnalysis(null);
      setLocalAnalysis(null);
      setKidnapAnalysis(null);
      setManualMode('AUTO');
      setShowResetConfirm(false);
      setSimulationToast({ message: 'Board Cleared', type: 'info' });
      setTimeout(() => setSimulationToast(null), 2000);
  };

  const takeSnapshot = useCallback(() => {
    setPast((prev) => {
      const newPast = [...prev, { nodes, edges }];
      return newPast.length > 20 ? newPast.slice(1) : newPast;
    });
    setFuture([]);
  }, [nodes, edges]);

  const undo = useCallback(() => {
    if (past.length === 0) return;
    const previous = past[past.length - 1];
    const newPast = past.slice(0, past.length - 1);
    setFuture((prev) => [{ nodes, edges }, ...prev]);
    setNodes(previous.nodes);
    setEdges(previous.edges);
    setPast(newPast);
    setSelectedNode(null);
    setSelectedEdge(null);
  }, [past, nodes, edges, setNodes, setEdges]);

  const redo = useCallback(() => {
    if (future.length === 0) return;
    const next = future[0];
    const newFuture = future.slice(1);
    setPast((prev) => [...prev, { nodes, edges }]);
    setNodes(next.nodes);
    setEdges(next.edges);
    setFuture(newFuture);
    setSelectedNode(null);
    setSelectedEdge(null);
  }, [future, nodes, edges, setNodes, setEdges]);

  // Keyboard Shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (['INPUT', 'TEXTAREA'].includes((e.target as HTMLElement).tagName)) return;

      if ((e.metaKey || e.ctrlKey) && e.key === 'z') {
        e.preventDefault();
        e.shiftKey ? redo() : undo();
      }
      if ((e.metaKey || e.ctrlKey) && e.key === 'y') {
        e.preventDefault();
        redo();
      }
      if ((e.metaKey || e.ctrlKey) && e.key === 's') {
        e.preventDefault();
        handleExportCase();
      }

      // DIRECTOR MODE TOGGLE: Ctrl + Shift + D
      if ((e.metaKey || e.ctrlKey) && e.shiftKey && e.key === 'D') {
        e.preventDefault();
        setShowDirectorMode(prev => !prev);
        setSimulationToast({ message: 'Director Mode Toggled', type: 'info' });
        setTimeout(() => setSimulationToast(null), 2000);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [undo, redo, nodes, edges]);

  // --- ANALYSIS EFFECTS ---
  useEffect(() => {
    if (nodes.length > 0) {
      const localResults = runLocalAnalysis(nodes, edges);
      setLocalAnalysis(localResults);

      const hasKidnapKeywords = nodes.some(n => {
        const data = n.data as NodeData;
        return data.role === 'victim' || 
        data.type === 'kidnapping' ||
        data.description?.toLowerCase().includes('abduct') ||
        data.label?.toLowerCase().includes('kidnap') ||
        data.label?.toLowerCase().includes('ransom');
      });

      let activeType = InvestigationType.GENERAL;
      if (manualMode !== 'AUTO') {
        activeType = manualMode;
      } else if (hasKidnapKeywords) {
        activeType = InvestigationType.KIDNAPPING;
      }
      setInvestigationType(activeType);

      if (activeType === InvestigationType.KIDNAPPING) {
        try {
            const kAnalysis = analyzeKidnappingCase(nodes, edges);
            setKidnapAnalysis(kAnalysis);
        } catch (e) {
            console.error("Kidnapping Analysis Crash Prevention:", e);
            // Fallback: Do not set null immediately if we want to preserve old state, 
            // but here we set null to avoid rendering broken dashboard
            setKidnapAnalysis(null);
        }
      } else {
        setKidnapAnalysis(null);
      }
    } else {
        // Even if empty, if mode is manually set, we keep it
        if (manualMode === InvestigationType.KIDNAPPING) {
            setInvestigationType(InvestigationType.KIDNAPPING);
            try {
                const kAnalysis = analyzeKidnappingCase(nodes, edges);
                setKidnapAnalysis(kAnalysis);
            } catch (e) {
                console.error("Kidnapping Analysis Crash Prevention (Empty):", e);
                setKidnapAnalysis(null);
            }
        } else {
            setInvestigationType(InvestigationType.GENERAL);
            setKidnapAnalysis(null);
        }
    }
  }, [nodes, edges, manualMode]);

  // --- HANDLERS ---
  const handleActionSimulation = (action: string) => {
    let message = '';
    let type: 'info' | 'success' = 'info';

    switch (action) {
      case 'activate_irt':
        message = 'Dispatching Intelligence Response Team (IRT)...';
        break;
      case 'track_phones':
        message = 'Triangulating GSM Signals...';
        break;
      case 'setup_roadblocks':
        message = 'Alerting State Commands & Highway Patrol...';
        break;
      case 'contact_family':
        message = 'Initiating Secure Line with Family Liaison...';
        break;
      default:
        message = 'Processing Action...';
    }

    setSimulationToast({ message, type: 'info' });

    setTimeout(() => {
      let successMsg = '';
      switch (action) {
        case 'activate_irt': successMsg = 'IRT Units Deployed & Active'; break;
        case 'track_phones': successMsg = 'Signal Locked: Cell ID #4922 (Approximation)'; break;
        case 'setup_roadblocks': successMsg = 'Gridlock Protocol Active in 3 Zones'; break;
        case 'contact_family': successMsg = 'Secure Channel Established'; break;
        default: successMsg = 'Action Completed';
      }
      setSimulationToast({ message: successMsg, type: 'success' });
      setTimeout(() => setSimulationToast(null), 3000);
    }, 1500);
  };

  const onConnect = useCallback(
    (params: Connection) => {
      takeSnapshot();
      setEdges((eds) => addEdge({ 
        ...params, 
        type: 'deletable', // Always use our custom edge type
        animated: true, 
        style: { stroke: '#64748b', strokeWidth: 2 } 
      } as Edge, eds));
    },
    [setEdges, takeSnapshot],
  );

  const onDragOver = useCallback((event: React.DragEvent) => {
    event.preventDefault();
    event.dataTransfer.dropEffect = 'move';
  }, []);

  const onDrop = useCallback(
    (event: React.DragEvent) => {
      event.preventDefault();
      takeSnapshot();

      const typeStr = event.dataTransfer.getData('application/reactflow');
      const isKidnapTool = event.dataTransfer.getData('kidnap') === 'true';

      let nodeType: NodeType | undefined = undefined;

      if (Object.values(NodeType).includes(typeStr as NodeType)) {
        nodeType = typeStr as NodeType;
      }

      if (!nodeType && !isKidnapTool) {
          if (['location', 'evidence'].includes(typeStr)) {
             nodeType = NodeType.EVENT;
          } else if (typeStr === 'organization') {
             nodeType = NodeType.PERSON;
          } else {
             nodeType = NodeType.EVENT;
          }
      }

      const position = screenToFlowPosition({
        x: event.clientX,
        y: event.clientY,
      });

      let initialData: any = { label: 'New Node' };

      if (isKidnapTool) {
         const toolType = typeStr; 
         if (toolType === 'victim') {
             nodeType = NodeType.PERSON;
             initialData = { label: 'Victim', role: 'victim', medicalCondition: '', abductionTime: new Date().toISOString() };
         } else if (toolType === 'ransom') {
             nodeType = NodeType.EVENT;
             initialData = { label: 'Ransom Demand', type: 'communication', amount: 5000000 };
         } else {
             nodeType = NodeType.EVENT;
             initialData = { label: toolType.charAt(0).toUpperCase() + toolType.slice(1), role: toolType };
         }
      } else {
          if (typeStr === 'location') {
              initialData = { label: 'New Location', location: 'Unknown Location', type: 'location' };
          } else if (typeStr === 'evidence') {
              initialData = { label: 'New Evidence', evidenceSource: 'TBD', type: 'evidence' };
          } else if (typeStr === 'organization') {
              initialData = { label: 'New Organization', type: 'organization' };
          } else {
             initialData = { label: `New ${nodeType === NodeType.EVENT ? 'Event' : 'Person'}`, date: '', evidenceSource: '' };
          }
      }

      const newNode: Node = {
        id: getId(),
        type: nodeType,
        position,
        data: initialData,
      };

      setNodes((nds) => nds.concat(newNode));
      setSelectedNode(newNode);
      setSelectedEdge(null);
    },
    [screenToFlowPosition, setNodes, takeSnapshot],
  );

  const onNodeDragStart = useCallback(() => {
    takeSnapshot();
  }, [takeSnapshot]);

  const onNodeClick = useCallback((_: React.MouseEvent, node: Node) => {
    setSelectedNode(node);
    setSelectedEdge(null);
  }, []);

  const onEdgeClick = useCallback((_: React.MouseEvent, edge: Edge) => {
    setSelectedEdge(edge);
    setSelectedNode(null);
  }, []);

  const onPaneClick = useCallback(() => {
    setSelectedNode(null);
    setSelectedEdge(null);
  }, []);

  const handleDeleteNode = useCallback((id: string) => {
    takeSnapshot();
    setNodes((nds) => nds.filter((n) => n.id !== id));
    setEdges((eds) => eds.filter((e) => e.source !== id && e.target !== id));
    setSelectedNode(null);
  }, [setNodes, setEdges, takeSnapshot]);

  const handleDeleteEdge = useCallback((id: string) => {
    takeSnapshot();
    setEdges((eds) => eds.filter((e) => e.id !== id));
    setSelectedEdge(null);
  }, [setEdges, takeSnapshot]);

  const handleAiAnalysis = async () => {
    if (nodes.length === 0) return;
    setIsAnalyzing(true);
    setAnalysis(null);
    setShowAnalysisOptions(false); // Close modal

    try {
      const result = await analyzeBoard(nodes, edges);
      if (result) {
         setAnalysis(result);
      } else {
         // Fallback if result is null but no error thrown
         setSimulationToast({ message: 'AI Response Empty - Try Offline Mode', type: 'info' });
         setTimeout(() => setSimulationToast(null), 4000);
      }
    } catch (e) {
      console.warn("AI Analysis Failed", e);
      setSimulationToast({ message: 'Connection Failed - Try Offline Mode', type: 'info' });
      setTimeout(() => setSimulationToast(null), 4000);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleOfflineAnalysis = () => {
    if (nodes.length === 0) return;
    setIsAnalyzing(true);
    setAnalysis(null);
    setShowAnalysisOptions(false); // Close modal

    // Add a small artificial delay to simulate "processing" so user feels something happened
    setTimeout(() => {
      const localSummary = generateLocalSummary(nodes, edges);
      setAnalysis(localSummary);
      setIsAnalyzing(false);
      setSimulationToast({ message: 'Offline Analysis Complete', type: 'success' });
      setTimeout(() => setSimulationToast(null), 3000);
    }, 800);
  };

  // Generic wrapper to show options, not run immediately
  const handleAnalyzeClick = () => {
    if (nodes.length > 0) {
      setShowAnalysisOptions(true);
    }
  };

  // Expose specific handler for Director Mode automation
  const handleDirectorAnalysis = async () => {
      // In director mode demo, we usually default to one or the other, or simulate AI.
      // We'll simulate AI for effect
      await handleAiAnalysis();
  };

  const kidnappingSidebarItems = [
    { type: 'victim', label: '👤 Victim' },
    { type: 'ransom', label: '💰 Ransom' },
    { type: 'hideout', label: '🏚️ Hideout' },
    { type: 'vehicle', label: '🚗 Vehicle' },
    { type: 'accomplice', label: '👥 Accomplice' },
    { type: 'communication', label: '📞 Comms' },
  ];

  const isOfflineReport = analysis?.summary.includes('OFFLINE ANALYSIS') || false;

  return (
    <div className="flex h-screen w-full bg-slate-950 text-slate-200 font-sans selection:bg-amber-500/30">
      <Sidebar />

      {/* DIRECTOR MODE OVERLAY - CONDITIONAL RENDER */}
      {showDirectorMode && (
        <DirectorMode 
          setNodes={setNodes}
          setEdges={setEdges}
          setManualMode={setManualMode}
          handleAnalysis={handleDirectorAnalysis}
          setSelectedNode={setSelectedNode}
          setSimulationToast={setSimulationToast}
          onCloseEditor={() => {
            setSelectedNode(null);
            setSelectedEdge(null);
          }}
        />
      )}

      {/* ANALYSIS OPTIONS MODAL */}
      {showAnalysisOptions && (
        <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-slate-900 border border-slate-700 rounded-xl p-8 shadow-2xl max-w-md w-full animate-in fade-in zoom-in-95 duration-200">
            <div className="flex justify-between items-start mb-6">
              <div>
                <h2 className="text-xl font-bold text-slate-100 flex items-center gap-2">
                  <BrainCircuit className="w-6 h-6 text-amber-500" />
                  Select Intelligence Source
                </h2>
                <p className="text-slate-400 text-sm mt-1">Choose an analysis engine to process current case data.</p>
              </div>
              <button 
                onClick={() => setShowAnalysisOptions(false)}
                className="text-slate-500 hover:text-white transition-colors"
              >
                <X className="w-5 h-5" />
              </button>
            </div>

            <div className="space-y-4">
              {/* Option 1: AI */}
              <button
                onClick={handleAiAnalysis}
                className="w-full group relative flex items-start gap-4 p-4 rounded-xl border border-amber-500/30 bg-slate-800/50 hover:bg-slate-800 hover:border-amber-500 transition-all text-left"
              >
                <div className="p-3 rounded-lg bg-amber-500/10 text-amber-500 group-hover:bg-amber-500 group-hover:text-black transition-colors">
                  <Sparkles className="w-6 h-6" />
                </div>
                <div>
                  <div className="flex items-center gap-2">
                    <h3 className="font-bold text-slate-200">Cloud Intelligence (AI)</h3>
                    <Wifi className="w-3 h-3 text-emerald-500" />
                  </div>
                  <p className="text-xs text-slate-400 mt-1 leading-relaxed">
                    Connects to Cloud AI (e.g. Gemini, ChatGPT) for deep psychological profiling and pattern matching. 
                    <span className="block text-amber-500/70 mt-1">*Requires Active API Key</span>
                  </p>
                </div>
              </button>

              {/* Option 2: Local */}
              <button
                onClick={handleOfflineAnalysis}
                className="w-full group relative flex items-start gap-4 p-4 rounded-xl border border-blue-500/30 bg-slate-800/50 hover:bg-slate-800 hover:border-blue-500 transition-all text-left"
              >
                 <div className="p-3 rounded-lg bg-blue-500/10 text-blue-500 group-hover:bg-blue-500 group-hover:text-white transition-colors">
                  <Cpu className="w-6 h-6" />
                </div>
                <div>
                   <div className="flex items-center gap-2">
                    <h3 className="font-bold text-slate-200">Offline Logic Engine</h3>
                    <WifiOff className="w-3 h-3 text-slate-500" />
                  </div>
                  <p className="text-xs text-slate-400 mt-1 leading-relaxed">
                    Runs locally on your device. Secure environment with no data transmission. Detects standard risks.
                    <span className="block text-blue-400/70 mt-1">*Works without Internet</span>
                  </p>
                </div>
              </button>
            </div>
          </div>
        </div>
      )}

      {/* RESET CONFIRMATION MODAL */}
      {showResetConfirm && (
        <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-slate-900 border border-slate-700 rounded-xl p-6 shadow-2xl max-w-sm w-full animate-in fade-in zoom-in-95 duration-200">
            <div className="flex items-center gap-3 mb-4 text-red-500">
              <div className="p-2 bg-red-900/30 rounded-full">
                <AlertCircle className="w-6 h-6" />
              </div>
              <h3 className="text-lg font-bold text-slate-100">Clear Investigation?</h3>
            </div>

            <p className="text-slate-400 text-sm mb-6 leading-relaxed">
              This will remove all nodes and edges from the board. This action can be undone using <span className="text-slate-200 font-mono text-xs bg-slate-800 px-1 py-0.5 rounded">Ctrl+Z</span>.
            </p>

            <div className="flex gap-3 justify-end">
              <button 
                onClick={() => setShowResetConfirm(false)}
                className="px-4 py-2 rounded-lg bg-slate-800 text-slate-300 hover:bg-slate-700 transition-colors text-sm font-medium"
              >
                Cancel
              </button>
              <button 
                onClick={executeResetBoard}
                className="px-4 py-2 rounded-lg bg-red-600 text-white hover:bg-red-500 transition-colors text-sm font-medium"
              >
                Clear Board
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="flex-1 h-full relative" ref={reactFlowWrapper}>
        <ReactFlow
          nodes={nodes}
          edges={edges}
          onNodesChange={onNodesChange}
          onEdgesChange={onEdgesChange}
          onConnect={onConnect}
          onDrop={onDrop}
          onDragOver={onDragOver}
          onNodeDragStart={onNodeDragStart}
          onNodeClick={onNodeClick}
          onEdgeClick={onEdgeClick}
          onPaneClick={onPaneClick}
          nodeTypes={nodeTypes}
          edgeTypes={edgeTypes}
          deleteKeyCode={['Backspace', 'Delete']}
          fitView
          className="bg-slate-950"
        >
          <Controls className="!bg-slate-800 !border-slate-700 !fill-slate-400 [&>button]:!border-slate-700 hover:[&>button]:!bg-slate-700" />
          <Background color="#1e293b" gap={20} variant={BackgroundVariant.Dots} />

          <Panel position="top-right" className="flex flex-col gap-4 mt-20 md:mt-0 items-end">
            <div className="flex gap-2">
               {/* Mode Selector */}
               <div className="flex items-center bg-slate-800 rounded-lg p-1 border border-slate-700 shadow-lg px-2 gap-2">
                 <Briefcase className={`w-4 h-4 ${investigationType === InvestigationType.KIDNAPPING ? 'text-red-500' : 'text-slate-400'}`} />
                 <select 
                    id="mode-selector"
                    value={manualMode}
                    onChange={(e) => setManualMode(e.target.value as any)}
                    className="bg-transparent text-sm font-medium text-slate-200 focus:outline-none cursor-pointer"
                 >
                   <option value="AUTO">Auto Detect</option>
                   <option value={InvestigationType.GENERAL}>General Case</option>
                   <option value={InvestigationType.KIDNAPPING}>Kidnapping</option>
                 </select>
               </div>

               {/* File Operations */}
               <div className="flex bg-slate-800 rounded-lg p-1 border border-slate-700 shadow-lg">
                <input 
                  type="file" 
                  ref={fileInputRef}
                  onChange={handleFileChange}
                  accept=".json"
                  className="hidden" 
                />
                <button
                  onClick={handleImportClick}
                  className="p-2 rounded hover:bg-slate-700 transition-colors text-slate-200"
                  title="Load Case File"
                >
                  <Upload className="w-4 h-4" />
                </button>
                <div className="w-px bg-slate-700 my-1 mx-1" />
                <button
                  onClick={handleExportCase}
                  className="p-2 rounded hover:bg-slate-700 transition-colors text-slate-200"
                  title="Save Case File (Ctrl+S)"
                >
                  <Download className="w-4 h-4" />
                </button>
                <div className="w-px bg-slate-700 my-1 mx-1" />
                <button
                  onClick={handleResetBoardClick}
                  className="p-2 rounded hover:bg-red-900/50 text-slate-200 hover:text-red-400 transition-colors"
                  title="Clear Board"
                >
                  <Trash2 className="w-4 h-4" />
                </button>
              </div>

              {/* Undo/Redo */}
              <div className="flex bg-slate-800 rounded-lg p-1 border border-slate-700 shadow-lg">
                <button
                  onClick={undo}
                  disabled={past.length === 0}
                  className={`p-2 rounded hover:bg-slate-700 transition-colors ${past.length === 0 ? 'opacity-30 cursor-not-allowed' : 'text-slate-200'}`}
                  title="Undo (Ctrl+Z)"
                >
                  <Undo2 className="w-4 h-4" />
                </button>
                <div className="w-px bg-slate-700 my-1 mx-1" />
                <button
                  onClick={redo}
                  disabled={future.length === 0}
                  className={`p-2 rounded hover:bg-slate-700 transition-colors ${future.length === 0 ? 'opacity-30 cursor-not-allowed' : 'text-slate-200'}`}
                  title="Redo (Ctrl+Y)"
                >
                  <Redo2 className="w-4 h-4" />
                </button>
              </div>

              {/* Gemini Analysis Button */}
              <button 
                id="btn-analyze"
                onClick={handleAnalyzeClick}
                disabled={isAnalyzing || nodes.length === 0}
                className={`
                  flex items-center gap-2 px-4 py-2 rounded-lg font-medium text-sm shadow-lg transition-all
                  ${isAnalyzing 
                    ? 'bg-slate-800 text-slate-400 cursor-wait' 
                    : 'bg-amber-600 hover:bg-amber-500 text-white hover:scale-105 active:scale-95'}
                `}
              >
                {isAnalyzing ? (
                  <><Loader2 className="w-4 h-4 animate-spin" /> Analyzing...</>
                ) : (
                  <><BrainCircuit className="w-4 h-4" /> Analyze Case</>
                )}
              </button>
            </div>
          </Panel>

           {/* SIMULATION TOAST */}
          {simulationToast && (
             <div className="absolute top-20 left-1/2 -translate-x-1/2 z-50 animate-slide-in-bottom">
                <div className={`
                  flex items-center gap-3 px-4 py-3 rounded-lg shadow-2xl border backdrop-blur-md
                  ${simulationToast.type === 'success' 
                    ? 'bg-emerald-900/80 border-emerald-500/50 text-emerald-100' 
                    : 'bg-blue-900/80 border-blue-500/50 text-blue-100'}
                `}>
                  {simulationToast.type === 'success' ? (
                     <CheckCircle2 className="w-5 h-5 text-emerald-400" />
                  ) : (
                     <Radio className="w-5 h-5 text-blue-400 animate-pulse" />
                  )}
                  <div className="font-medium text-sm">{simulationToast.message}</div>
                </div>
             </div>
          )}

        </ReactFlow>

        {/* Local Analysis Widget */}
        {localAnalysis && (localAnalysis.redFlags.length > 0 || localAnalysis.ringleader) && (
          <div className="absolute top-20 right-4 w-80 bg-slate-900/95 border border-slate-700 rounded-lg p-4 shadow-xl z-40 animate-slide-in-right">
            <div className="flex items-center gap-2 mb-3">
              <ShieldAlert className="w-5 h-5 text-amber-500" />
              <h3 className="font-bold text-slate-200">Local Intelligence</h3>
              <span className="ml-auto text-xs bg-slate-800 px-2 py-1 rounded">
                {localAnalysis.redFlags.filter(f => f.severity === 'HIGH').length} 🔴
              </span>
            </div>

            {localAnalysis.ringleader && (
              <div className="mb-3 p-3 bg-slate-800/50 rounded border border-blue-500/30">
                <div className="flex items-center gap-2 text-blue-400 text-sm font-semibold mb-1">
                  <Crown className="w-4 h-4" />
                  Key Person of Interest
                </div>
                <div className="text-slate-300">
                  <div className="font-medium">{localAnalysis.ringleader.label}</div>
                  <div className="text-xs text-slate-400">
                    Connected to {localAnalysis.ringleader.connectionCount} entities
                  </div>
                </div>
              </div>
            )}

            {localAnalysis.redFlags.slice(0, 3).map((flag, idx) => (
              <div key={idx} className={`mb-2 p-2 rounded border text-sm ${
                flag.severity === 'HIGH' 
                  ? 'bg-red-900/20 border-red-500/40' 
                  : 'bg-amber-900/20 border-amber-500/40'
              }`}>
                <div className="flex items-start gap-2">
                  <div className={`w-2 h-2 rounded-full mt-1.5 shrink-0 ${
                    flag.severity === 'HIGH' ? 'bg-red-500' : 'bg-amber-500'
                  }`} />
                  <div>
                    <div className="text-slate-300 leading-tight">{flag.message}</div>
                  </div>
                </div>
              </div>
            ))}

            <button 
              className="w-full text-xs text-center text-slate-400 hover:text-slate-200 py-1 bg-slate-800/50 rounded mt-1"
              onClick={() => setShowFullAnalysis(true)}
            >
              View Full Report {localAnalysis.redFlags.length > 3 ? `(+${localAnalysis.redFlags.length - 3} more)` : ''}
            </button>
          </div>
        )}

        {/* Kidnapping Dashboard Overlay - Only visible in Kidnapping Mode */}
        {investigationType === InvestigationType.KIDNAPPING && kidnapAnalysis && (
          <KidnappingDashboard 
            analysis={kidnapAnalysis}
            onAction={handleActionSimulation}
          />
        )}

        {/* Kidnapping Tools Palette - Only visible in Kidnapping Mode */}
        {investigationType === InvestigationType.KIDNAPPING && (
          <div id="kidnap-tools" className="absolute bottom-4 left-4 w-48 bg-red-900/80 backdrop-blur border border-red-500/50 rounded-lg p-3 z-40 animate-slide-in-bottom shadow-lg">
            <div className="text-xs text-red-200 font-bold mb-2 uppercase tracking-wider flex items-center gap-2">
               <AlertTriangle className="w-3 h-3" /> Kidnap Tools
            </div>
            <div className="grid grid-cols-2 gap-2">
              {kidnappingSidebarItems.map((item, idx) => (
                <div
                  id={item.type === 'ransom' ? 'tool-ransom' : `tool-${item.type}`}
                  key={idx}
                  draggable
                  onDragStart={(e) => {
                    e.dataTransfer.setData('application/reactflow', item.type);
                    e.dataTransfer.setData('kidnap', 'true');
                  }}
                  className="p-2 bg-slate-900/60 hover:bg-red-700/60 rounded text-center cursor-grab text-xs border border-red-500/30 text-slate-200 transition-colors"
                >
                  {item.label}
                </div>
              ))}
            </div>
          </div>
        )}

        <EditorPanel 
          selectedNode={selectedNode}
          selectedEdge={selectedEdge}
          setNodes={(newNodesOrUpdater) => {
             setNodes(newNodesOrUpdater);
          }}
          setEdges={(newEdgesOrUpdater) => {
            setEdges(newEdgesOrUpdater);
          }}
          onClose={() => {
            setSelectedNode(null);
            setSelectedEdge(null);
          }}
          deleteNode={handleDeleteNode}
          deleteEdge={handleDeleteEdge}
        />

        {/* Full Local Analysis Modal */}
        {showFullAnalysis && localAnalysis && (
          <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
            <div className="bg-slate-900 border border-slate-700 rounded-xl w-full max-w-4xl max-h-[85vh] overflow-y-auto p-6 shadow-2xl animate-in fade-in zoom-in-95 duration-200">
              <div className="flex justify-between items-center mb-6">
                <h2 className="text-xl font-bold text-slate-200 flex items-center gap-2">
                  <ShieldAlert className="w-6 h-6 text-amber-500" />
                  Complete Analysis Report
                </h2>
                <div className="flex items-center gap-2">
                  <button 
                    onClick={handleDownloadPDF}
                    className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-blue-600 hover:bg-blue-500 text-white text-sm font-medium transition-colors"
                  >
                    <FileDown className="w-4 h-4" />
                    Download PDF
                  </button>
                  <button 
                    onClick={() => setShowFullAnalysis(false)}
                    className="text-slate-500 hover:text-white transition-colors p-2 hover:bg-slate-800 rounded-full"
                  >
                    <X className="w-5 h-5" />
                  </button>
                </div>
              </div>

              {localAnalysis.ringleader && (
                <section className="mb-8 p-4 bg-slate-800/50 rounded-lg border border-slate-700">
                  <h3 className="text-sm font-semibold text-blue-400 mb-3 uppercase tracking-wide">Key Subject</h3>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <div className="text-sm text-slate-400">Primary Person of Interest</div>
                      <div className="text-xl font-bold text-slate-200">{localAnalysis.ringleader.label}</div>
                    </div>
                    <div>
                      <div className="text-sm text-slate-400">Network Connections</div>
                      <div className="text-xl font-bold text-slate-200">
                        {localAnalysis.ringleader.connectionCount} direct links
                      </div>
                    </div>
                  </div>
                </section>
              )}

              <section className="mb-8">
                <h3 className="text-lg font-semibold text-slate-200 mb-3 flex items-center gap-2">
                  <AlertTriangle className="w-5 h-5 text-amber-500" />
                  Investigation Alerts ({localAnalysis.redFlags.length})
                </h3>
                <div className="space-y-3">
                  {localAnalysis.redFlags.map((flag, idx) => {
                    const affectedNodeNames = flag.affectedNodeIds.map(id => {
                      const node = nodes.find(n => n.id === id);
                      return node ? (node.data as NodeData).label || id : id;
                    }).join(', ');

                    return (
                    <div key={idx} className={`p-4 rounded-lg border ${
                      flag.severity === 'HIGH' 
                        ? 'border-red-500/30 bg-red-900/10' 
                        : 'border-amber-500/30 bg-amber-900/10'
                    }`}>
                      <div className="flex items-center gap-3 mb-2">
                        <div className={`w-3 h-3 rounded-full ${
                          flag.severity === 'HIGH' ? 'bg-red-500' : 'bg-amber-500'
                        }`} />
                        <span className="font-medium text-slate-200">{flag.type.replace('_', ' ')}</span>
                        <span className={`px-2 py-0.5 rounded text-[10px] uppercase font-bold tracking-wider ${
                          flag.severity === 'HIGH' 
                            ? 'bg-red-500/20 text-red-300' 
                            : 'bg-amber-500/20 text-amber-300'
                        }`}>
                          {flag.severity}
                        </span>
                      </div>
                      <p className="text-slate-300 mb-2">{flag.message}</p>
                      {flag.evidence && (
                        <p className="text-sm text-slate-500 italic">Suggested: {flag.evidence}</p>
                      )}
                      <div className="text-xs text-slate-400 mt-2 pt-2 border-t border-slate-700/50">
                        Affects: {affectedNodeNames}
                      </div>
                    </div>
                  )})}
                </div>
              </section>

              {localAnalysis.financialPatterns.length > 0 && (
                <section className="mb-8">
                  <h3 className="text-lg font-semibold text-slate-200 mb-3">
                    Financial Patterns ({localAnalysis.financialPatterns.length})
                  </h3>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                    {localAnalysis.financialPatterns.map((pattern, idx) => (
                      <div key={idx} className="p-3 bg-slate-800/30 rounded border border-slate-700">
                        <div className="text-xs text-slate-400 mb-1">{pattern.type.replace('_', ' ')}</div>
                        <div className="text-slate-200 font-medium">{pattern.description}</div>
                        {pattern.amount && (
                          <div className="text-xs text-emerald-400 mt-1">
                            ₦{pattern.amount.toLocaleString('en-NG')}
                          </div>
                        )}
                      </div>
                    ))}
