});

// --- CUSTOM EDGE COMPONENT ---
export const DeletableEdge = ({
  id,
  sourceX,
  sourceY,
  targetX,
  targetY,
  sourcePosition,
  targetPosition,
  style = {},
  markerEnd,
  label
}: EdgeProps) => {
  const { setEdges } = useReactFlow();
  const [edgePath, labelX, labelY] = getBezierPath({
    sourceX,
    sourceY,
    sourcePosition,
    targetX,
    targetY,
    targetPosition,
  });

  const onEdgeClick = (evt: React.MouseEvent) => {
    evt.stopPropagation(); // Prevents selecting the edge when clicking delete
    setEdges((edges) => edges.filter((e) => e.id !== id));
  };

  return (
    <>
      <BaseEdge path={edgePath} markerEnd={markerEnd} style={style} />
      <EdgeLabelRenderer>
        <div
          style={{
            position: 'absolute',
            transform: `translate(-50%, -50%) translate(${labelX}px,${labelY}px)`,
            fontSize: 12,
            pointerEvents: 'all',
          }}
          className="nodrag nopan flex flex-col items-center gap-1 group"
        >
          {/* Show Label if exists */}
          {label && (
            <div className="bg-slate-900/80 text-slate-300 text-[10px] px-2 py-0.5 rounded border border-slate-700 backdrop-blur-sm whitespace-nowrap shadow-sm">
              {label as string}
            </div>
          )}

          {/* Delete Button */}
          <button
            className="w-5 h-5 bg-slate-900 border border-slate-600 rounded-full text-slate-400 hover:text-white hover:bg-red-600 hover:border-red-600 flex items-center justify-center transition-all shadow-md z-50 active:scale-95"
            onClick={onEdgeClick}
            title="Unlink (Delete Connection)"
            aria-label="Unlink"
          >
            <X className="w-3 h-3" />
          </button>
        </div>
      </EdgeLabelRenderer>
    </>
  );
};

import React, { useEffect, useState } from 'react';
import { Node, Edge } from '@xyflow/react';
import { NodeData, PersonStatus, EvidenceType } from '../types';
import { X, Save, Trash2, Link2, Type, AlertCircle, Shield, Star, UserCheck } from 'lucide-react';

interface EditorPanelProps {
  selectedNode: Node | null;
  selectedEdge: Edge | null;
  setNodes: React.Dispatch<React.SetStateAction<Node[]>>;
  setEdges: React.Dispatch<React.SetStateAction<Edge[]>>;
  onClose: () => void;
  deleteNode: (id: string) => void;
  deleteEdge: (id: string) => void;
}

export const EditorPanel: React.FC<EditorPanelProps> = ({ 
  selectedNode, 
  selectedEdge, 
  setNodes, 
  setEdges, 
  onClose, 
  deleteNode, 
  deleteEdge 
}) => {
  // Form state for Nodes
  const [nodeFormData, setNodeFormData] = useState<NodeData>({
    label: '',
    date: '',
    evidenceSource: '',
    amount: 0,
    location: '',
    aliases: '',
    personStatus: 'unknown',
    evidenceType: undefined,
    reliability: 0,
  });

  // Form state for Edges
  const [edgeFormData, setEdgeFormData] = useState({
    label: '',
    color: '#64748b'
  });

  // Sync state when selection changes
  useEffect(() => {
    if (selectedNode) {
      setNodeFormData({
        label: selectedNode.data.label as string || '',
        date: (selectedNode.data.date as string) || '',
        evidenceSource: (selectedNode.data.evidenceSource as string) || '',
        amount: (selectedNode.data.amount as number) || 0,
        location: (selectedNode.data.location as string) || '',
        aliases: (selectedNode.data.aliases as string) || '',
        personStatus: (selectedNode.data.personStatus as PersonStatus) || 'unknown',
        evidenceType: (selectedNode.data.evidenceType as EvidenceType) || undefined,
        reliability: (selectedNode.data.reliability as number) || 0,
        role: (selectedNode.data.role as string) || '',
      });
    }
  }, [selectedNode]);

  useEffect(() => {
    if (selectedEdge) {
      setEdgeFormData({
        label: (selectedEdge.label as string) || '',
        color: selectedEdge.style?.stroke as string || '#64748b',
      });
    }
  }, [selectedEdge]);

  // Handler for Node updates
  const handleNodeChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setNodeFormData(prev => ({ ...prev, [name]: value }));

    setNodes((nds) => 
      nds.map((node) => {
        if (node.id === selectedNode?.id) {
          return {
            ...node,
            data: { ...node.data, [name]: value },
          };
        }
        return node;
      })
    );
  };

  const handleReliabilityChange = (score: number) => {
    setNodeFormData(prev => ({ ...prev, reliability: score }));
    setNodes((nds) => 
      nds.map((node) => {
        if (node.id === selectedNode?.id) {
          return { ...node, data: { ...node.data, reliability: score } };
        }
        return node;
      })
    );
  };

  // Special handler for amount to ensure it is a number
  const handleAmountChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = parseFloat(e.target.value);
    setNodeFormData(prev => ({ ...prev, amount: isNaN(val) ? 0 : val }));

    setNodes((nds) => 
      nds.map((node) => {
        if (node.id === selectedNode?.id) {
          return {
            ...node,
            data: { ...node.data, amount: isNaN(val) ? 0 : val },
          };
        }
        return node;
      })
    );
  };

  // Handler for Edge updates
  const handleEdgeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;

    if (name === 'label') {
      setEdgeFormData(prev => ({ ...prev, label: value }));
      setEdges((eds) => 
        eds.map((edge) => {
          if (edge.id === selectedEdge?.id) {
            return { ...edge, label: value };
          }
          return edge;
        })
      );
    }
  };

  const handleColorChange = (color: string) => {
    setEdgeFormData(prev => ({ ...prev, color }));
    setEdges((eds) => 
      eds.map((edge) => {
        if (edge.id === selectedEdge?.id) {
          return { 
            ...edge, 
            style: { ...edge.style, stroke: color, strokeWidth: 2 },
            animated: true
          };
        }
        return edge;
      })
    );
  };

  const colors = [
    { label: 'Neutral', value: '#64748b', bg: 'bg-slate-500' }, // Slate
    { label: 'Hostile', value: '#ef4444', bg: 'bg-red-500' },   // Red
    { label: 'Related', value: '#3b82f6', bg: 'bg-blue-500' },  // Blue
    { label: 'Key Link', value: '#eab308', bg: 'bg-yellow-500' }, // Yellow
    { label: 'Verified', value: '#10b981', bg: 'bg-emerald-500' }, // Green
  ];

  if (!selectedNode && !selectedEdge) return null;

  return (
    <div className="absolute right-4 top-4 w-80 bg-slate-900 border border-slate-700 rounded-xl shadow-2xl overflow-hidden flex flex-col animate-slide-in-right z-50">
      <div className="p-4 border-b border-slate-800 flex justify-between items-center bg-slate-800/50">
        <h2 className="font-semibold text-slate-100 flex items-center gap-2">
          {selectedNode ? (
            <>Details: <span className="text-amber-500 uppercase text-xs border border-amber-500/30 px-1.5 py-0.5 rounded">{selectedNode.type === 'personNode' ? 'Person' : 'Event'}</span></>
          ) : (
            <>Connection Details</>
          )}
        </h2>
        <button onClick={onClose} className="text-slate-400 hover:text-white transition-colors">
          <X className="w-5 h-5" />
        </button>
      </div>

      <div className="p-4 space-y-4 max-h-[80vh] overflow-y-auto custom-scrollbar">
        {/* --- NODE EDITOR --- */}
        {selectedNode && (
          <>
            <div>
              <label className="block text-xs font-medium text-slate-400 mb-1.5 uppercase tracking-wide">
                {selectedNode.type === 'personNode' ? 'Name / Subject' : 'Event Title'}
              </label>
              <input
                type="text"
                name="label"
                value={nodeFormData.label}
                onChange={handleNodeChange}
                className="w-full bg-slate-950 border border-slate-700 rounded-md px-3 py-2 text-sm text-slate-100 focus:outline-none focus:border-amber-500 transition-colors placeholder:text-slate-600 font-bold"
                placeholder={selectedNode.type === 'personNode' ? "Subject Name" : "Incident Name"}
              />
            </div>

            {/* PERSON SPECIFIC FIELDS */}
            {selectedNode.type === 'personNode' && (
              <div className="bg-slate-800/50 p-3 rounded-lg border border-slate-700 space-y-3">
                <h3 className="text-xs font-bold text-slate-400 uppercase flex items-center gap-2">
                  <UserCheck className="w-3 h-3" /> Identity Profile
                </h3>

                <div>
                  <label className="block text-[10px] text-slate-500 mb-1">Status</label>
                  <select
                    name="personStatus"
                    value={nodeFormData.personStatus}
                    onChange={handleNodeChange}
                    className="w-full bg-slate-950 border border-slate-700 rounded px-2 py-1.5 text-xs text-slate-200 focus:outline-none focus:border-amber-500"
                  >
                    <option value="unknown">Unknown</option>
                    <option value="suspect">🔴 Suspect</option>
                    <option value="victim">🔵 Victim</option>
                    <option value="witness">🟡 Witness</option>
                    <option value="informant">🟢 Informant</option>
                  </select>
                </div>

                <div>
                   <label className="block text-[10px] text-slate-500 mb-1">Aliases / Monikers</label>
                   <input
                    type="text"
