export const DirectorMode: React.FC<DirectorModeProps> = ({ 
  setNodes,
  setEdges,
  setManualMode,
  handleAnalysis,
  setSelectedNode,
  setSimulationToast,
  onCloseEditor
}) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentSubtitle, setCurrentSubtitle] = useState("");
  const [mousePos, setMousePos] = useState({ x: window.innerWidth / 2, y: window.innerHeight / 2 });
  const [isMinimized, setIsMinimized] = useState(false);

  const isPlayingRef = useRef(false);
  const { screenToFlowPosition, getNodes, getEdges } = useReactFlow();

  // --- AUTOMATION ENGINE ---

  const smoothMoveTo = async (targetX: number, targetY: number, duration: number = 800) => {
    const startX = mousePos.x;
    const startY = mousePos.y;
    const startTime = performance.now();

    return new Promise<void>((resolve) => {
      const animate = (currentTime: number) => {
        if (!isPlayingRef.current) { resolve(); return; }

        const elapsed = currentTime - startTime;
        const progress = Math.min(elapsed / duration, 1);

        // Easing function (easeInOutCubic)
        const ease = progress < 0.5 
          ? 4 * progress * progress * progress 
          : 1 - Math.pow(-2 * progress + 2, 3) / 2;

        const newX = startX + (targetX - startX) * ease;
        const newY = startY + (targetY - startY) * ease;

        setMousePos({ x: newX, y: newY });

        if (progress < 1) {
          requestAnimationFrame(animate);
        } else {
          resolve();
        }
      };
      requestAnimationFrame(animate);
    });
  };

  // Helper to determine where nodes should ideally sit on the screen to avoid overlap
  const getDemoPosition = (key: string) => {
    const cx = window.innerWidth / 2;
    const cy = window.innerHeight / 2;

    if (key.includes('person')) return { x: cx - 250, y: cy - 50 };   // Left Center
    if (key.includes('location')) return { x: cx + 250, y: cy - 50 }; // Right Center
    if (key.includes('ransom')) return { x: cx, y: cy + 150 };        // Bottom Center

    // Default fallback
    return { x: cx, y: cy };
  };

  const getElementCenter = (selector: string) => {
    // Handle special virtual IDs for existing nodes based on type
    if (selector.startsWith('node-')) {
       return getDemoPosition(selector);
    }

    const el = document.getElementById(selector) || document.querySelector(selector);
    if (el) {
      const rect = el.getBoundingClientRect();
      return { 
        x: rect.left + rect.width / 2, 
        y: rect.top + rect.height / 2 
      };
    }
    return { x: window.innerWidth / 2, y: window.innerHeight / 2 };
  };

  const processAction = async (actionString: string) => {
    const parts = actionString.split(':');
    const type = parts[0];

    switch (type) {
      case 'move':
        const target = getElementCenter(parts[1]);
        await smoothMoveTo(target.x, target.y);
        break;

      case 'click':
        let clickTarget = { x: 0, y: 0 };

        // Special Coordinates for UI elements that might move or are overlays
        if (parts[1] === 'btn-analyze') clickTarget = {x: window.innerWidth - 100, y: 80};
        else if (parts[1] === 'mode-selector') clickTarget = {x: window.innerWidth - 250, y: 80};
        else if (parts[1] === 'close-editor') clickTarget = {x: window.innerWidth - 40, y: 60};
        else if (parts[1] === 'dash-activate-irt') clickTarget = {x: 100, y: 150};
        else clickTarget = getElementCenter(parts[1]);

        await smoothMoveTo(clickTarget.x, clickTarget.y);

        // Visual Ripple
        showClickRipple(clickTarget.x, clickTarget.y);

        // Logic Trigger
        if (parts[1] === 'btn-analyze') handleAnalysis();
        if (parts[1] === 'close-editor') onCloseEditor();
        if (parts[1] === 'node-person') {
             const nodes = getNodes().filter(n => n.type === NodeType.PERSON);
             if (nodes.length > 0) setSelectedNode(nodes[nodes.length - 1]);
        }
        if (parts[1] === 'dash-activate-irt') {
           setSimulationToast({ message: 'Dispatching IRT Units...', type: 'info' });
        }
        break;

      case 'drag':
        const sourceId = parts[1];

        // 1. Move to Source (Sidebar or Toolbar)
        let sourcePos = { x: 100, y: 500 }; 
        if (sourceId === 'sidebar-item-person') sourcePos = getElementCenter('#sidebar-item-person');
        if (sourceId === 'sidebar-item-location') sourcePos = getElementCenter('#sidebar-item-location');
        if (sourceId === 'tool-ransom') sourcePos = { x: 100, y: window.innerHeight - 50 }; 

        await smoothMoveTo(sourcePos.x, sourcePos.y);
        await new Promise(r => setTimeout(r, 200)); // Grab delay

        // 2. Drag to Deterministic Position (Canvas)
        const dropPos = getDemoPosition(sourceId); // Use sourceId (e.g., sidebar-item-person) to decide destination
        await smoothMoveTo(dropPos.x, dropPos.y, 1000);

        // 3. Drop (Logic)
        const flowPos = screenToFlowPosition({ x: dropPos.x, y: dropPos.y });
        let newNodeType = NodeType.EVENT;
        let data: any = { label: 'New Item' };

        if (sourceId.includes('person')) {
           newNodeType = NodeType.PERSON;
           data = { label: 'New Person', personStatus: 'unknown' };
        } else if (sourceId.includes('location')) {
           newNodeType = NodeType.EVENT;
           data = { label: 'Location Ping', location: 'Unknown' };
        } else if (sourceId.includes('ransom')) {
           newNodeType = NodeType.EVENT;
           data = { label: 'Ransom Demand', type: 'communication', amount: 50000000 };
        }

        const newNode: Node = {
            id: `demo_node_${Date.now()}`,
            type: newNodeType,
            position: flowPos,
            data: data
        };

        setNodes(nds => nds.concat(newNode));
        break;

      case 'type':
        const field = parts[1];
        const text = parts[2];
        const nodes = getNodes();

        // Fix: Target the Person node for edits, as per script intention.
        // The script is linear, so we know we want to edit the Person node we just added.
        const targetNodeToEdit = nodes.find(n => n.type === NodeType.PERSON);

        if (targetNodeToEdit) {
            setNodes(nds => nds.map(n => {
                if (n.id === targetNodeToEdit.id) {
                    return { ...n, data: { ...n.data, [field]: text } };
                }
                return n;
            }));
        }
        break;

      case 'select':
        if (parts[1] === 'mode') {
           if (parts[2] === 'kidnapping') setManualMode(InvestigationType.KIDNAPPING);
        }
        break;

      case 'connect':
        const sourceKey = parts[1]; // e.g., node-person
        const targetKey = parts[2]; // e.g., node-location

        // 1. Move visually between the two intended positions
        const startVis = getDemoPosition(sourceKey);
        const endVis = getDemoPosition(targetKey);

        await smoothMoveTo(startVis.x, startVis.y);
        showClickRipple(startVis.x, startVis.y); // Click source
        await smoothMoveTo(endVis.x, endVis.y, 1000); // Drag edge

        // 2. Logic: Find the actual nodes to connect based on their properties/types
        const currentNodes = getNodes();
        let sourceNode: Node | undefined;
        let targetNode: Node | undefined;

        // Helper to find specific nodes created during the demo
        const findNode = (key: string) => {
            if (key.includes('person')) return currentNodes.find(n => n.type === NodeType.PERSON);
            if (key.includes('location')) return currentNodes.find(n => n.type === NodeType.EVENT && (n.data as any).location);
            if (key.includes('ransom')) return currentNodes.find(n => (n.data as any).type === 'communication');
            return undefined;
        };

        sourceNode = findNode(sourceKey);
        targetNode = findNode(targetKey);

        if (sourceNode && targetNode) {
             const newEdge: Edge = {
                 id: `e_${sourceNode.id}_${targetNode.id}`,
                 source: sourceNode.id,
                 target: targetNode.id,
                 type: 'deletable', // Ensure demo uses custom edge
                 animated: true,
                 style: { stroke: '#eab308', strokeWidth: 2 }
             };
             setEdges(eds => eds.concat(newEdge));
        }
        break;

      case 'wait':
        break;
    }
  };

  const showClickRipple = (x: number, y: number) => {
      const ripple = document.createElement('div');
      ripple.className = 'fixed z-[9999] rounded-full bg-amber-500/50 pointer-events-none transform -translate-x-1/2 -translate-y-1/2 transition-all duration-500 ease-out';
      ripple.style.left = `${x}px`;
      ripple.style.top = `${y}px`;
      ripple.style.width = '0px';
      ripple.style.height = '0px';
      document.body.appendChild(ripple);

      requestAnimationFrame(() => {
          ripple.style.width = '50px';
          ripple.style.height = '50px';
          ripple.style.opacity = '0';
      });

      setTimeout(() => ripple.remove(), 500);
  };

  const startDirectorMode = async () => {
    setIsPlaying(true);
    isPlayingRef.current = true;

    // Reset View for clean start
    setNodes([]); 
    setEdges([]);
    setManualMode(InvestigationType.GENERAL);

    for (const step of DEMO_SCRIPT) {
      if (!isPlayingRef.current) break;

      setCurrentSubtitle(step.text);

      // Execute Action
      if (step.action) await processAction(step.action);

      // Wait for duration
      const chunks = step.duration / 100;
      for (let i = 0; i < chunks; i++) {
        if (!isPlayingRef.current) break;
        await new Promise(r => setTimeout(r, 100));
      }
    }

    setIsPlaying(false);
    isPlayingRef.current = false;
    setCurrentSubtitle("");
  };

  const stopDirectorMode = () => {
    setIsPlaying(false);
    isPlayingRef.current = false;
    setCurrentSubtitle("");
  };

  if (isMinimized) {
    return (
      <div className="fixed bottom-4 right-20 z-50 animate-slide-in-bottom">
        <button 
          onClick={() => setIsMinimized(false)}
          className="bg-slate-800 text-amber-500 p-3 rounded-full shadow-2xl border border-amber-500/50 hover:scale-110 transition-transform"
        >
          <Video className="w-6 h-6" />
        </button>
      </div>
    );
  }

  return (
    <>
      {/* VIRTUAL MOUSE */}
      {isPlaying && (
        <div 
          style={{ 
            position: 'fixed',
            left: mousePos.x, 
            top: mousePos.y,
            pointerEvents: 'none',
            zIndex: 9999,
            transition: 'transform 0.1s',
          }}
        >
          <MousePointer2 className="w-8 h-8 text-black fill-amber-500 -ml-1 -mt-1 drop-shadow-xl" />
        </div>
      )}

      {/* SUBTITLES */}
      {isPlaying && currentSubtitle && (
        <div className="fixed bottom-24 left-0 right-0 flex justify-center z-[9000] pointer-events-none">
          <div className="bg-slate-950/80 backdrop-blur border border-amber-500/30 text-slate-100 px-8 py-4 rounded-xl shadow-2xl text-xl font-medium animate-in slide-in-from-bottom-5 fade-in duration-300 max-w-3xl text-center">
            {currentSubtitle}
          </div>
        </div>
      )}

      {/* CONTROL PANEL */}
      <div className="fixed bottom-4 right-20 z-50 bg-slate-900/90 backdrop-blur border border-slate-700 rounded-xl shadow-2xl w-64 overflow-hidden animate-slide-in-right">
        <div className="flex items-center justify-between px-4 py-3 bg-slate-800/50 border-b border-slate-700">
          <div className="flex items-center gap-2">
            <Video className="w-4 h-4 text-amber-500" />
            <span className="text-xs font-bold text-slate-200 uppercase tracking-wider">Director Mode</span>
          </div>
          <button onClick={() => setIsMinimized(true)} className="text-slate-400 hover:text-white">
            <Minimize2 className="w-4 h-4" />
          </button>
        </div>

        <div className="p-4">
          {!isPlaying ? (
            <button 
              onClick={startDirectorMode}
              className="w-full flex items-center justify-center gap-2 py-3 rounded-lg bg-gradient-to-r from-amber-600 to-amber-500 text-white font-bold shadow-lg hover:brightness-110 transition-all active:scale-95"
            >
              <Play className="w-4 h-4 fill-current" />
              <span>Play Demo Reel</span>
            </button>
          ) : (
            <button 
              onClick={stopDirectorMode}
              className="w-full flex items-center justify-center gap-2 py-3 rounded-lg bg-red-600 text-white font-bold shadow-lg hover:bg-red-500 transition-all animate-pulse"
            >
              <Square className="w-4 h-4 fill-current" />
              <span>Stop Demo</span>
            </button>
          )}

          <div className="mt-3 text-center">
             <span className="text-[10px] text-slate-500 uppercase font-bold">
               {isPlaying ? "Script Running..." : "Ready to Start"}
             </span>
          </div>
        </div>
      </div>
    </>
  );
};

