});

export const PersonNode = memo(({ data, selected }: { data: NodeData; selected?: boolean }) => {

  const getStatusStyles = (status?: PersonStatus, type?: string) => {
    // Handle Organization Override
    if (type === 'organization') {
        return { color: 'bg-slate-700', border: 'border-slate-500', icon: Building2, label: 'ORGANIZATION' };
    }

    switch (status) {
      case 'suspect': return { color: 'bg-red-600', border: 'border-red-500/50', icon: Skull, label: 'SUSPECT' };
      case 'victim': return { color: 'bg-blue-600', border: 'border-blue-500/50', icon: Shield, label: 'VICTIM' };
      case 'witness': return { color: 'bg-amber-600', border: 'border-amber-500/50', icon: Eye, label: 'WITNESS' };
      case 'informant': return { color: 'bg-emerald-600', border: 'border-emerald-500/50', icon: Radio, label: 'INFORMANT' };
      default: return { color: 'bg-slate-600', border: 'border-slate-700', icon: User, label: 'PERSON' };
    }
  };

  const styles = getStatusStyles(data.personStatus, data.type);
  const StatusIcon = styles.icon;

  const Toolbar = () => (
    <div className="flex items-center gap-3">
       {/* Tiny thumbnail in toolbar */}
       {data.image && <img src={data.image} alt="Thumb" className="w-8 h-8 rounded bg-slate-800 object-cover" />}
       <div className="flex flex-col">
         <span className="text-[10px] text-slate-400 uppercase">Role</span>
         <span className={`text-sm font-bold ${data.personStatus === 'suspect' ? 'text-red-400' : 'text-slate-200'}`}>
            {styles.label}
         </span>
       </div>
       <div className="w-px h-6 bg-slate-800" />
       <div className="flex flex-col">
         <span className="text-[10px] text-slate-400 uppercase">Aliases</span>
         <span className="text-sm font-bold text-slate-200">{data.aliases ? data.aliases.split(',').length : 0} Known</span>
      </div>
    </div>
  );

  return (
    <BaseNodeWrapper 
      selected={selected} 
      headerColor={styles.color}
      borderColor={styles.border}
      title={styles.label} 
      icon={StatusIcon}
      toolbarContent={<Toolbar />}
    >
      <div className="flex flex-col gap-2">
        <div className="flex items-start gap-3">
          {/* IMAGE DISPLAY */}
          {data.image ? (
            <img 
              src={data.image} 
              alt={data.label} 
              className="w-12 h-12 rounded bg-slate-800 object-cover border border-slate-600" 
            />
          ) : (
            <div className="w-12 h-12 rounded bg-slate-800 flex items-center justify-center text-slate-600 border border-slate-700 shrink-0">
               {data.type === 'organization' ? <Building2 className="w-6 h-6" /> : <User className="w-6 h-6" />}
            </div>
          )}

          <div>
            <div className="text-sm font-bold text-slate-100 break-words leading-tight">
              {data.label || 'Unknown'}
            </div>
            {data.aliases && (
              <div className="text-xs text-slate-400 italic mt-0.5">
                aka "{data.aliases}"
              </div>
            )}
          </div>
        </div>

        {data.role && data.role.toUpperCase() !== styles.label && (
          <div className="text-[10px] uppercase tracking-wide bg-slate-800 px-1.5 py-0.5 rounded w-fit text-slate-400">
            {data.role}
          </div>
        )}

        {data.date && (
           <div className="flex items-center gap-1.5 text-xs text-amber-300 mt-1">
             <AlertCircle className="w-3 h-3" />
             <span>Last Sighted: {data.date.replace('T', ' ')}</span>
           </div>
        )}

        {data.evidenceSource && (
          <div className="flex items-start gap-1.5 text-[10px] text-slate-500 mt-1 pt-2 border-t border-slate-800/50">
            <FileText className="w-3 h-3 mt-0.5 shrink-0" />
            <span className="italic truncate">{data.evidenceSource}</span>
          </div>
        )}
      </div>
    </BaseNodeWrapper>
  );
});

// --- CUSTOM EDGE COMPONENT ---
export const DeletableEdge = ({
  id,
  sourceX,
  sourceY,
  targetX,
  targetY,
  sourcePosition,
  targetPosition,
  style = {},
  markerEnd,
  label
}: EdgeProps) => {
  const { setEdges } = useReactFlow();
  const [edgePath, labelX, labelY] = getBezierPath({
    sourceX,
    sourceY,
    sourcePosition,
    targetX,
    targetY,
    targetPosition,
  });

  const onEdgeClick = (evt: React.MouseEvent) => {
    evt.stopPropagation(); // Prevents selecting the edge when clicking delete
    setEdges((edges) => edges.filter((e) => e.id !== id));
  };

  return (
    <>
      <BaseEdge path={edgePath} markerEnd={markerEnd} style={style} />
      <EdgeLabelRenderer>
        <div
          style={{
            position: 'absolute',
            transform: `translate(-50%, -50%) translate(${labelX}px,${labelY}px)`,
            fontSize: 12,
            pointerEvents: 'all',
          }}
          className="nodrag nopan flex flex-col items-center gap-1 group"
        >
          {/* Show Label if exists */}
          {label && (
            <div className="bg-slate-900/80 text-slate-300 text-[10px] px-2 py-0.5 rounded border border-slate-700 backdrop-blur-sm whitespace-nowrap shadow-sm">
              {label as string}
            </div>
          )}

          {/* Delete Button */}
          <button
            className="w-5 h-5 bg-slate-900 border border-slate-600 rounded-full text-slate-400 hover:text-white hover:bg-red-600 hover:border-red-600 flex items-center justify-center transition-all shadow-md z-50 active:scale-95"
            onClick={onEdgeClick}
            title="Unlink (Delete Connection)"
            aria-label="Unlink"
          >
            <X className="w-3 h-3" />
          </button>
        </div>
      </EdgeLabelRenderer>
    </>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { Node, Edge } from '@xyflow/react';
import { NodeData, PersonStatus, EvidenceType, NodeType } from '../types';
import { X, Save, Trash2, Link2, Type, AlertCircle, Shield, Star, UserCheck, ImagePlus, Map, Video, Mic, Paperclip, Layout } from 'lucide-react';

interface EditorPanelProps {
  selectedNode: Node | null;
  selectedEdge: Edge | null;
  setNodes: React.Dispatch<React.SetStateAction<Node[]>>;
  setEdges: React.Dispatch<React.SetStateAction<Edge[]>>;
  onClose: () => void;
  deleteNode: (id: string) => void;
  deleteEdge: (id: string) => void;
}

export const EditorPanel: React.FC<EditorPanelProps> = ({ 
  selectedNode, 
  selectedEdge, 
  setNodes, 
  setEdges, 
  onClose, 
  deleteNode, 
  deleteEdge 
}) => {
  const imageInputRef = useRef<HTMLInputElement>(null);

  // Form state for Nodes
  const [nodeFormData, setNodeFormData] = useState<NodeData>({
    label: '',
    date: '',
    evidenceSource: '',
    amount: 0,
    location: '',
    aliases: '',
    personStatus: 'unknown',
    evidenceType: undefined,
    reliability: 0,
    coordinates: { lat: 0, lng: 0 },
    image: '',
    attachments: [],
    noteColor: '#fef3c7',
    type: 'event' // default for EventNodes
  });

  // Form state for Edges
  const [edgeFormData, setEdgeFormData] = useState({
    label: '',
    color: '#64748b'
  });

  // Sync state when selection changes
  useEffect(() => {
    if (selectedNode) {
      setNodeFormData({
        label: selectedNode.data.label as string || '',
        date: (selectedNode.data.date as string) || '',
        evidenceSource: (selectedNode.data.evidenceSource as string) || '',
        amount: (selectedNode.data.amount as number) || 0,
        location: (selectedNode.data.location as string) || '',
        aliases: (selectedNode.data.aliases as string) || '',
        personStatus: (selectedNode.data.personStatus as PersonStatus) || 'unknown',
        evidenceType: (selectedNode.data.evidenceType as EvidenceType) || undefined,
        reliability: (selectedNode.data.reliability as number) || 0,
        role: (selectedNode.data.role as string) || '',
        coordinates: (selectedNode.data.coordinates as any) || { lat: 0, lng: 0 },
        image: (selectedNode.data.image as string) || '',
        attachments: (selectedNode.data.attachments as any[]) || [],
        noteColor: (selectedNode.data.noteColor as string) || '#fef3c7',
        type: (selectedNode.data.type as string) || 'event'
      });
    }
  }, [selectedNode]);

  useEffect(() => {
    if (selectedEdge) {
      setEdgeFormData({
        label: (selectedEdge.label as string) || '',
        color: selectedEdge.style?.stroke as string || '#64748b',
      });
    }
  }, [selectedEdge]);

  // Generic Update Wrapper
  const updateNode = (field: string, value: any) => {
    setNodeFormData(prev => ({ ...prev, [field]: value }));
    setNodes((nds) => 
      nds.map((node) => {
        if (node.id === selectedNode?.id) {
          return {
            ...node,
            data: { ...node.data, [field]: value },
          };
        }
        return node;
      })
    );
  };

  const handleNodeChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    updateNode(e.target.name, e.target.value);
  };

  const handleCoordinatesChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    const val = parseFloat(value);
    const newCoords = { ...nodeFormData.coordinates, [name]: isNaN(val) ? 0 : val } as any;
    updateNode('coordinates', newCoords);
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        updateNode('image', reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  // Mock function for media attachments since we don't have backend storage for videos
  const addMockAttachment = (type: 'video' | 'audio') => {
    const newAttachment = {
      id: Date.now().toString(),
      type,
      name: `New ${type} Record`,
      url: '#' // Placeholder
    };
    const newAttachments = [...(nodeFormData.attachments || []), newAttachment];
    updateNode('attachments', newAttachments);
  };

  const handleEdgeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    if (name === 'label') {
      setEdgeFormData(prev => ({ ...prev, label: value }));
      setEdges((eds) => 
        eds.map((edge) => {
          if (edge.id === selectedEdge?.id) {
            return { ...edge, label: value };
          }
          return edge;
        })
      );
    }
  };

  const handleColorChange = (color: string) => {
    setEdgeFormData(prev => ({ ...prev, color }));
    setEdges((eds) => 
      eds.map((edge) => {
        if (edge.id === selectedEdge?.id) {
          return { 
            ...edge, 
            style: { ...edge.style, stroke: color, strokeWidth: 2 },
            animated: true
          };
        }
        return edge;
      })
    );
  };

  if (!selectedNode && !selectedEdge) return null;

