            </div>

            <div>
              <label className="block text-xs font-medium text-slate-400 mb-2 uppercase tracking-wide flex items-center gap-2">
                <Link2 className="w-3 h-3" /> Connection Type
              </label>
              <div className="flex gap-2">
                {['#64748b', '#ef4444', '#3b82f6', '#eab308', '#10b981'].map((c) => (
                  <button
                    key={c}
                    onClick={() => handleColorChange(c)}
                    className={`w-8 h-8 rounded-full hover:scale-110 transition-transform ring-2 ${
                      edgeFormData.color === c ? 'ring-white' : 'ring-transparent'
                    }`}
                    style={{ backgroundColor: c }}
                  />
                ))}
              </div>
            </div>
          </>
        )}

        <div className="pt-4 mt-2 border-t border-slate-800 flex justify-between">
           <button 
             onClick={() => {
               if (selectedNode) deleteNode(selectedNode.id);
               if (selectedEdge) deleteEdge(selectedEdge.id);
             }}
             className="flex items-center gap-2 px-3 py-2 rounded-md bg-red-900/20 text-red-400 text-sm hover:bg-red-900/40 transition-colors border border-red-900/50"
           >
            <Trash2 className="w-4 h-4" />
            Delete
           </button>

           <button 
             onClick={onClose}
             className="flex items-center gap-2 px-4 py-2 rounded-md bg-slate-800 text-slate-200 text-sm hover:bg-slate-700 transition-colors"
           >
            <Save className="w-4 h-4" />
            Done
           </button>
        </div>
      </div>
    </div>
  );
};

import React, { useCallback, useRef, useState, useEffect } from 'react';
import {
  ReactFlow,
  ReactFlowProvider,
  addEdge,
  useNodesState,
  useEdgesState,
  Controls,
  Background,
  Connection,
  Edge,
  Node,
  BackgroundVariant,
  useReactFlow,
  Panel,
} from '@xyflow/react';
import { jsPDF } from "jspdf";

import { Sidebar } from './components/Sidebar';
import { EditorPanel } from './components/EditorPanel';
import { DirectorMode } from './components/DirectorMode';
import { EventNode, PersonNode, NoteNode, DeletableEdge } from './components/CustomNodes';
import { NodeType, AnalysisResult, InvestigationType, NodeData } from './types';
import { analyzeKidnappingCase, KidnappingAnalysis } from './services/kidnappingAnalysis';
import { runLocalAnalysis, LocalAnalysisResult, generateLocalSummary } from './services/localAnalysis';
import { KidnappingDashboard } from './components/KidnappingDashboard';
import { 
  BrainCircuit, 
  Loader2, 
  Sparkles, 
  AlertTriangle, 
  Link2, 
  ShieldAlert, 
  Crown, 
  MapPin, 
  Undo2, 
  Redo2, 
  Briefcase, 
  CheckCircle2, 
  Radio, 
  Download, 
  Upload, 
  Cpu, 
  Trash2,
  AlertCircle,
  X,
  FileDown,
  Wifi,
  WifiOff
} from 'lucide-react';

// Define custom node types outside component to prevent re-creation
const nodeTypes = {
  [NodeType.EVENT]: EventNode,
  [NodeType.PERSON]: PersonNode,
  [NodeType.NOTE]: NoteNode,
};

// Define custom edge types
const edgeTypes = {
  deletable: DeletableEdge,
};

let id = 100;
const getId = () => `dndnode_${id++}`;

// Interface for History
interface HistoryState {
  nodes: Node[];
  edges: Edge[];
}

const InvestigationCanvas = () => {
  const reactFlowWrapper = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // INITIAL STATE: Preset kidnapping scenario
  const [nodes, setNodes, onNodesChange] = useNodesState<Node>([
    {
      id: '1',
      type: NodeType.PERSON,
      position: { x: 400, y: 100 },
      data: { 
        label: 'Dr. Amara Okeke', 
        role: 'victim',
        age: 45,
        occupation: 'Oil Executive',
        medicalCondition: 'Hypertension',
        abductionTime: new Date(Date.now() - 1000 * 60 * 60 * 24).toISOString(), // 24 hours ago
        evidenceSource: 'Family Report',
      },
    },
    {
      id: '2',
      type: NodeType.EVENT,
      position: { x: 400, y: 300 },
      data: { 
        label: 'Abduction at Lekki', 
        type: 'event',
        date: new Date(Date.now() - 1000 * 60 * 60 * 24).toISOString(),
        location: 'Lekki Phase 1',
        evidenceSource: 'CCTV Footage'
      },
    },
    {
      id: '3',
      type: NodeType.EVENT,
      position: { x: 700, y: 300 },
      data: { 
        label: 'Ransom Call', 
        type: 'communication',
        date: new Date(Date.now() - 1000 * 60 * 60 * 2).toISOString(), // 2 hours ago
        amount: 50000000,
        deadline: new Date(Date.now() + 1000 * 60 * 60 * 48).toISOString(), // 48 hours from now
        evidenceSource: 'Recorded Call #001'
      },
    },
  ]);
  const [edges, setEdges, onEdgesChange] = useEdgesState<Edge>([
    { id: 'e1-2', source: '1', target: '2', label: 'Abducted at', type: 'deletable', animated: true, style: { stroke: '#ef4444', strokeWidth: 2 } },
    { id: 'e1-3', source: '1', target: '3', label: 'Subject of', type: 'deletable', animated: true, style: { stroke: '#eab308', strokeWidth: 2 } },
  ]);

  const { screenToFlowPosition, setViewport } = useReactFlow();

  const [selectedNode, setSelectedNode] = useState<Node | null>(null);
  const [selectedEdge, setSelectedEdge] = useState<Edge | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [localAnalysis, setLocalAnalysis] = useState<LocalAnalysisResult | null>(null);

  // Analysis Options State
  const [showAnalysisOptions, setShowAnalysisOptions] = useState(false);

  // Investigation Mode State
  const [manualMode, setManualMode] = useState<InvestigationType | 'AUTO'>('AUTO');
  const [investigationType, setInvestigationType] = useState<InvestigationType>(InvestigationType.GENERAL);

  const [kidnapAnalysis, setKidnapAnalysis] = useState<KidnappingAnalysis | null>(null);
  const [showFullAnalysis, setShowFullAnalysis] = useState(false);

  // VISIBILITY STATE FOR DIRECTOR MODE
  const [showDirectorMode, setShowDirectorMode] = useState(false);
  const [showResetConfirm, setShowResetConfirm] = useState(false);

  // Simulation / Toast State
  const [simulationToast, setSimulationToast] = useState<{message: string, type: 'info' | 'success'} | null>(null);

  // --- HISTORY MANAGEMENT ---
  const [past, setPast] = useState<HistoryState[]>([]);
  const [future, setFuture] = useState<HistoryState[]>([]);

  // --- PERSISTENCE & EXPORT ---

  useEffect(() => {
    const saveData = { nodes, edges };
    localStorage.setItem('intelboard_autosave', JSON.stringify(saveData));
  }, [nodes, edges]);

  useEffect(() => {
    // 1. Check URL params
    const params = new URLSearchParams(window.location.search);
    if (params.get('mode') === 'director') {
      setShowDirectorMode(true);
    }
  }, []);

  const handleExportCase = () => {
    const dataStr = JSON.stringify({ nodes, edges, investigationType }, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `case-export-${new Date().toISOString().slice(0, 10)}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    setSimulationToast({ message: 'Case File Saved Successfully', type: 'success' });
    setTimeout(() => setSimulationToast(null), 3000);
  };

  const handleDownloadPDF = () => {
    // 1. Ensure we have the absolute latest analysis from current node state
    const currentAnalysis = runLocalAnalysis(nodes, edges);
    setLocalAnalysis(currentAnalysis);

    const doc = new jsPDF();
    const pageWidth = doc.internal.pageSize.getWidth();
    let yPos = 20;
    const margin = 20;
    const contentWidth = pageWidth - (margin * 2);

    // Helper for wrapping text
    const addWrappedText = (text: string, y: number, fontSize: number = 10, isBold: boolean = false) => {
      doc.setFontSize(fontSize);
      doc.setFont("helvetica", isBold ? "bold" : "normal");
      const lines = doc.splitTextToSize(text, contentWidth);
      doc.text(lines, margin, y);
      return y + (lines.length * (fontSize / 2)) + 4; // Return next Y position
    };

    // --- TITLE ---
    doc.setFontSize(22);
    doc.setTextColor(40, 40, 40);
    doc.text("IntelBoard Investigation Report", pageWidth / 2, yPos, { align: 'center' });
    yPos += 10;

    doc.setFontSize(10);
    doc.setTextColor(100, 100, 100);
    doc.text(`Generated: ${new Date().toLocaleString()}`, pageWidth / 2, yPos, { align: 'center' });
    yPos += 20;

    doc.setLineWidth(0.5);
    doc.setDrawColor(200, 200, 200);
    doc.line(margin, yPos, pageWidth - margin, yPos);
    yPos += 10;

    // --- RINGLEADER ---
    if (currentAnalysis.ringleader) {
      doc.setFillColor(240, 245, 255); // Light blue bg
      doc.rect(margin, yPos, contentWidth, 35, 'F'); // Increased height for image

      doc.setFontSize(14);
      doc.setTextColor(0, 50, 150);
      doc.text("Primary Person of Interest", margin + 5, yPos + 8);

      // Attempt to find node image
      const rlNode = nodes.find(n => n.id === currentAnalysis.ringleader?.id);
      let textOffsetX = margin + 5;

      if (rlNode && (rlNode.data as any).image) {
        try {
          doc.addImage((rlNode.data as any).image, "JPEG", margin + 5, yPos + 12, 20, 20);
          textOffsetX += 25; // Shift text right
        } catch (e) {
          console.warn("Could not add image to PDF", e);
        }
      }

      doc.setFontSize(12);
      doc.setTextColor(0, 0, 0);
      doc.text(`Name: ${currentAnalysis.ringleader.label}`, textOffsetX, yPos + 16);
      doc.setFontSize(10);
      doc.setTextColor(80, 80, 80);
      doc.text(`Network Connections: ${currentAnalysis.ringleader.connectionCount}`, textOffsetX, yPos + 22);

      yPos += 45;
    }

    // --- RED FLAGS ---
    if (currentAnalysis.redFlags.length > 0) {
      doc.setFontSize(16);
      doc.setTextColor(200, 0, 0);
      doc.text(`Investigation Alerts (${currentAnalysis.redFlags.length})`, margin, yPos);
      yPos += 10;

      currentAnalysis.redFlags.forEach((flag) => {
        if (yPos > 270) { doc.addPage(); yPos = 20; }

        doc.setFontSize(11);
        doc.setTextColor(0, 0, 0);
        doc.setFont("helvetica", "bold");
        doc.text(`• ${flag.type.replace('_', ' ')} [${flag.severity}]`, margin, yPos);
        yPos += 5;

        doc.setFont("helvetica", "normal");
        doc.setTextColor(60, 60, 60);
        yPos = addWrappedText(flag.message, yPos, 10);

        if (flag.evidence) {
           doc.setFont("helvetica", "italic");
           yPos = addWrappedText(`Suggestion: ${flag.evidence}`, yPos, 9);
        }
        yPos += 5;
      });
      yPos += 10;
    }

    // --- GEOGRAPHICAL (With Links) ---
    if (currentAnalysis.geographicalClusters.length > 0) {
       if (yPos > 260) { doc.addPage(); yPos = 20; }
       doc.setFontSize(16);
       doc.setTextColor(0, 0, 150);
       doc.text("Geographical Analysis", margin, yPos);
       yPos += 10;

       currentAnalysis.geographicalClusters.forEach((cluster) => {
          doc.setFontSize(11);
          doc.setFont("helvetica", "bold");
          doc.text(`${cluster.location}: ${cluster.nodes.length} events`, margin, yPos);

          // Add Maps Link if applicable
          const query = encodeURIComponent(cluster.location);
          const linkUrl = `https://www.google.com/maps/search/?api=1&query=${query}`;

          doc.setTextColor(0, 0, 255);
          doc.setFontSize(9);
          doc.textWithLink("(Open Map)", margin + 120, yPos, { url: linkUrl });
          doc.setTextColor(0, 0, 0); // reset

          yPos += 5;

          doc.setFont("helvetica", "normal");
          yPos = addWrappedText(`Strategy: ${cluster.suggestion}`, yPos, 10);
          yPos += 5;
       });
    }

    // --- FINANCIAL PATTERNS ---
    if (currentAnalysis.financialPatterns.length > 0) {
      if (yPos > 260) { doc.addPage(); yPos = 20; }
      doc.setFontSize(16);
      doc.setTextColor(0, 100, 0);
      doc.text("Financial Intelligence", margin, yPos);
      yPos += 10;

      currentAnalysis.financialPatterns.forEach((pattern) => {
        doc.setFontSize(11);
        doc.setTextColor(0, 0, 0);
        yPos = addWrappedText(`${pattern.description}`, yPos, 10, true);
        if (pattern.amount) {
          doc.text(`Amount: N${pattern.amount.toLocaleString()}`, margin + 5, yPos - 2); // adjust slightly
          yPos += 5;
        }
        yPos += 3;
      });
       yPos += 10;
    }

    doc.save(`intelboard-report-${new Date().toISOString().slice(0,10)}.pdf`);
  };

  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const result = JSON.parse(event.target?.result as string);
        if (result.nodes && result.edges) {
          takeSnapshot();
          setNodes(result.nodes);
          setEdges(result.edges);
          if (result.investigationType) setManualMode(result.investigationType);
          setSimulationToast({ message: 'Case File Loaded Successfully', type: 'success' });
          setTimeout(() => setSimulationToast(null), 3000);
        } else {
          alert('Invalid case file format');
        }
      } catch (err) {
        console.error(err);
        alert('Failed to parse case file');
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  const handleResetBoardClick = () => {
    setShowResetConfirm(true);
  };

  const executeResetBoard = () => {
      takeSnapshot(); // Crucial: Save state before wiping so user can Undo
      setNodes([]);
      setEdges([]);
      setAnalysis(null);
      setLocalAnalysis(null);
      setKidnapAnalysis(null);
      setManualMode('AUTO');
      setShowResetConfirm(false);
      setSimulationToast({ message: 'Board Cleared', type: 'info' });
      setTimeout(() => setSimulationToast(null), 2000);
  };

  const takeSnapshot = useCallback(() => {
    setPast((prev) => {
      const newPast = [...prev, { nodes, edges }];
      return newPast.length > 20 ? newPast.slice(1) : newPast;
    });
    setFuture([]);
  }, [nodes, edges]);

  const undo = useCallback(() => {
    if (past.length === 0) return;
    const previous = past[past.length - 1];
    const newPast = past.slice(0, past.length - 1);
    setFuture((prev) => [{ nodes, edges }, ...prev]);
    setNodes(previous.nodes);
    setEdges(previous.edges);
    setPast(newPast);
    setSelectedNode(null);
    setSelectedEdge(null);
  }, [past, nodes, edges, setNodes, setEdges]);

  const redo = useCallback(() => {
    if (future.length === 0) return;
    const next = future[0];
    const newFuture = future.slice(1);
    setPast((prev) => [...prev, { nodes, edges }]);
    setNodes(next.nodes);
    setEdges(next.edges);
    setFuture(newFuture);
    setSelectedNode(null);
    setSelectedEdge(null);
  }, [future, nodes, edges, setNodes, setEdges]);

  // Keyboard Shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (['INPUT', 'TEXTAREA'].includes((e.target as HTMLElement).tagName)) return;

      if ((e.metaKey || e.ctrlKey) && e.key === 'z') {
        e.preventDefault();
        e.shiftKey ? redo() : undo();
      }
      if ((e.metaKey || e.ctrlKey) && e.key === 'y') {
        e.preventDefault();
        redo();
      }
      if ((e.metaKey || e.ctrlKey) && e.key === 's') {
        e.preventDefault();
        handleExportCase();
      }

      // DIRECTOR MODE TOGGLE: Ctrl + Shift + D
      if ((e.metaKey || e.ctrlKey) && e.shiftKey && e.key === 'D') {
        e.preventDefault();
        setShowDirectorMode(prev => !prev);
        setSimulationToast({ message: 'Director Mode Toggled', type: 'info' });
        setTimeout(() => setSimulationToast(null), 2000);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [undo, redo, nodes, edges]);

  // --- ANALYSIS EFFECTS ---
  useEffect(() => {
    if (nodes.length > 0) {
      const localResults = runLocalAnalysis(nodes, edges);
      setLocalAnalysis(localResults);

      const hasKidnapKeywords = nodes.some(n => {
        const data = n.data as NodeData;
        return data.role === 'victim' || 
        data.type === 'kidnapping' ||
        data.description?.toLowerCase().includes('abduct') ||
        data.label?.toLowerCase().includes('kidnap') ||
        data.label?.toLowerCase().includes('ransom');
      });

      let activeType = InvestigationType.GENERAL;
      if (manualMode !== 'AUTO') {
        activeType = manualMode;
      } else if (hasKidnapKeywords) {
        activeType = InvestigationType.KIDNAPPING;
      }
      setInvestigationType(activeType);

      if (activeType === InvestigationType.KIDNAPPING) {
        try {
            const kAnalysis = analyzeKidnappingCase(nodes, edges);
            setKidnapAnalysis(kAnalysis);
        } catch (e) {
            console.error("Kidnapping Analysis Crash Prevention:", e);
            // Fallback: Do not set null immediately if we want to preserve old state, 
            // but here we set null to avoid rendering broken dashboard
            setKidnapAnalysis(null);
        }
      } else {
        setKidnapAnalysis(null);
      }
    } else {
        // Even if empty, if mode is manually set, we keep it
        if (manualMode === InvestigationType.KIDNAPPING) {
            setInvestigationType(InvestigationType.KIDNAPPING);
            try {
                const kAnalysis = analyzeKidnappingCase(nodes, edges);
                setKidnapAnalysis(kAnalysis);
            } catch (e) {
                console.error("Kidnapping Analysis Crash Prevention (Empty):", e);
                setKidnapAnalysis(null);
            }
        } else {
            setInvestigationType(InvestigationType.GENERAL);
            setKidnapAnalysis(null);
        }
    }
  }, [nodes, edges, manualMode]);

  // --- HANDLERS ---
  const handleActionSimulation = (action: string) => {
    let message = '';
    let type: 'info' | 'success' = 'info';

    switch (action) {
      case 'activate_irt':
        message = 'Dispatching Intelligence Response Team (IRT)...';
        break;
      case 'track_phones':
        message = 'Triangulating GSM Signals...';
        break;
      case 'setup_roadblocks':
        message = 'Alerting State Commands & Highway Patrol...';
        break;
      case 'contact_family':
        message = 'Initiating Secure Line with Family Liaison...';
        break;
      default:
        message = 'Processing Action...';
    }

    setSimulationToast({ message, type: 'info' });

    setTimeout(() => {
      let successMsg = '';
      switch (action) {
        case 'activate_irt': successMsg = 'IRT Units Deployed & Active'; break;
        case 'track_phones': successMsg = 'Signal Locked: Cell ID #4922 (Approximation)'; break;
        case 'setup_roadblocks': successMsg = 'Gridlock Protocol Active in 3 Zones'; break;
        case 'contact_family': successMsg = 'Secure Channel Established'; break;
        default: successMsg = 'Action Completed';
      }
      setSimulationToast({ message: successMsg, type: 'success' });
      setTimeout(() => setSimulationToast(null), 3000);
    }, 1500);
  };

  const onConnect = useCallback(
    (params: Connection) => {
      takeSnapshot();
      setEdges((eds) => addEdge({ 
        ...params, 
        type: 'deletable', // Always use our custom edge type
        animated: true, 
        style: { stroke: '#64748b', strokeWidth: 2 } 
      } as Edge, eds));
    },
    [setEdges, takeSnapshot],
  );

  const onDragOver = useCallback((event: React.DragEvent) => {
    event.preventDefault();
    event.dataTransfer.dropEffect = 'move';
  }, []);

  const onDrop = useCallback(
    (event: React.DragEvent) => {
      event.preventDefault();
      takeSnapshot();

      const typeStr = event.dataTransfer.getData('application/reactflow');
      const isKidnapTool = event.dataTransfer.getData('kidnap') === 'true';

      let nodeType: NodeType | undefined = undefined;

      if (Object.values(NodeType).includes(typeStr as NodeType)) {
        nodeType = typeStr as NodeType;
      }

      if (!nodeType && !isKidnapTool) {
          if (['location', 'evidence'].includes(typeStr)) {
             nodeType = NodeType.EVENT;
          } else if (typeStr === 'organization') {
             nodeType = NodeType.PERSON;
          } else {
             nodeType = NodeType.EVENT;
          }
      }

      const position = screenToFlowPosition({
        x: event.clientX,
        y: event.clientY,
      });

      let initialData: any = { label: 'New Node' };

      if (isKidnapTool) {
         const toolType = typeStr; 
         if (toolType === 'victim') {
             nodeType = NodeType.PERSON;
             initialData = { label: 'Victim', role: 'victim', medicalCondition: '', abductionTime: new Date().toISOString() };
         } else if (toolType === 'ransom') {
             nodeType = NodeType.EVENT;
             initialData = { label: 'Ransom Demand', type: 'communication', amount: 5000000 };
         } else {
             nodeType = NodeType.EVENT;
             initialData = { label: toolType.charAt(0).toUpperCase() + toolType.slice(1), role: toolType };
         }
      } else {
          // CATEGORY HANDLING FOR INITIAL DROP
          if (typeStr === 'location') {
              initialData = { label: 'New Location', location: 'Unknown Location', type: 'location' };
          } else if (typeStr === 'evidence') {
              initialData = { label: 'New Evidence', evidenceSource: 'TBD', type: 'evidence', evidenceType: 'physical' };
          } else if (typeStr === 'organization') {
              initialData = { label: 'New Organization', type: 'organization' };
          } else if (nodeType === NodeType.NOTE) {
              initialData = { label: 'New Note', noteColor: '#fef3c7' };
          } else {
             // Default Event or Person
             initialData = { 
               label: `New ${nodeType === NodeType.EVENT ? 'Event' : 'Person'}`, 
               type: nodeType === NodeType.EVENT ? 'event' : undefined,
               date: '', 
               evidenceSource: '' 
             };
             if(nodeType === NodeType.PERSON) initialData.personStatus = 'unknown';
          }
      }

      const newNode: Node = {
        id: getId(),
        type: nodeType,
        position,
        data: initialData,
      };

      setNodes((nds) => nds.concat(newNode));
      setSelectedNode(newNode);
      setSelectedEdge(null);
    },
    [screenToFlowPosition, setNodes, takeSnapshot],
  );

  const onNodeDragStart = useCallback(() => {
    takeSnapshot();
  }, [takeSnapshot]);

  const onNodeClick = useCallback((_: React.MouseEvent, node: Node) => {
    setSelectedNode(node);
    setSelectedEdge(null);
  }, []);

  const onEdgeClick = useCallback((_: React.MouseEvent, edge: Edge) => {
    setSelectedEdge(edge);
    setSelectedNode(null);
  }, []);

  const onPaneClick = useCallback(() => {
    setSelectedNode(null);
    setSelectedEdge(null);
  }, []);

  const handleDeleteNode = useCallback((id: string) => {
    takeSnapshot();
    setNodes((nds) => nds.filter((n) => n.id !== id));
    setEdges((eds) => eds.filter((e) => e.source !== id && e.target !== id));
    setSelectedNode(null);
  }, [setNodes, setEdges, takeSnapshot]);

  const handleDeleteEdge = useCallback((id: string) => {
    takeSnapshot();
    setEdges((eds) => eds.filter((e) => e.id !== id));
    setSelectedEdge(null);
  }, [setEdges, takeSnapshot]);

  const handleOfflineAnalysis = () => {
    if (nodes.length === 0) return;
    setIsAnalyzing(true);
    setAnalysis(null);
    setShowAnalysisOptions(false); // Close modal

    // Add a small artificial delay to simulate "processing" so user feels something happened
    setTimeout(() => {
      const localSummary = generateLocalSummary(nodes, edges);
      setAnalysis(localSummary);
      setIsAnalyzing(false);
      setSimulationToast({ message: 'Offline Analysis Complete', type: 'success' });
      setTimeout(() => setSimulationToast(null), 3000);
    }, 800);
  };

  // Generic wrapper - now goes straight to Offline
  const handleAnalyzeClick = () => {
    if (nodes.length > 0) {
      handleOfflineAnalysis();
    }
  };

  // Expose specific handler for Director Mode automation - now goes straight to Offline
  const handleDirectorAnalysis = async () => {
      handleOfflineAnalysis();
  };

  const kidnappingSidebarItems = [
    { type: 'victim', label: '👤 Victim' },
    { type: 'ransom', label: '💰 Ransom' },
    { type: 'hideout', label: '🏚️ Hideout' },
    { type: 'vehicle', label: '🚗 Vehicle' },
