export default App;

export enum NodeType {
  EVENT = 'eventNode',
  PERSON = 'personNode',
  NOTE = 'noteNode',
}

export enum InvestigationType {
  KIDNAPPING = 'kidnapping',
  FINANCIAL_CRIME = 'financial_crime',
  TERRORISM = 'terrorism',
  CORRUPTION = 'corruption',
  GENERAL = 'general'
}

export enum KidnapStatus {
  ACTIVE = 'active',
  RESOLVED = 'resolved',
  FATAL = 'fatal'
}

export type PersonStatus = 'suspect' | 'witness' | 'victim' | 'informant' | 'unknown';
export type EvidenceType = 'physical' | 'digital' | 'testimonial' | 'circumstantial' | 'forensic';

export interface Coordinates {
  lat: number;
  lng: number;
}

export interface MediaAttachment {
  id: string;
  type: 'image' | 'video' | 'audio';
  name: string;
  url: string; // Base64 or external link
}

export interface NodeData {
  label: string;
  date?: string;
  evidenceSource?: string;
  notes?: string;
  details?: string;

  // Enhanced Intelligence Fields
  aliases?: string;
  personStatus?: PersonStatus;
  evidenceType?: EvidenceType;
  reliability?: number; // 1-5 scale

  // Media & GIS
  image?: string; // Base64 string for profile picture
  attachments?: MediaAttachment[];
  coordinates?: Coordinates;

  // Note specific
  noteColor?: string;

  // Flexible fields for analysis
  role?: string;
  identifier?: string;
  amount?: number | string;
  location?: string;
  description?: string;
  type?: string;
  medium?: string; // For communication nodes
  deadline?: string;
  suspectedGroup?: string;
  equipment?: string;
  priorCases?: number;
  medicalCondition?: string;
  abductionTime?: string;
  familyWealth?: string;
  insurance?: string;
  [key: string]: any;
}

// 5-LAYER ENGINE OUTPUT STRUCTURE
export interface AnalysisResult {
  // Layer 5 Output: The Narrative
  summary: string;

  // Layer 2 Output: The Rules
  gaps: string[];
  redFlags: Array<{
    severity: 'HIGH' | 'MEDIUM' | 'LOW';
    message: string;
    type: string;
  }>;

  // Layer 4 Output: The Clusters/Connections
  connections: string[];
  clusters: Array<{
    id: number;
    label: string;
    members: string[];
  }>;

  // Layer 3 Output: The Trends
  temporalTrend: {
    direction: 'INCREASING' | 'DECREASING' | 'STABLE' | 'BURST';
    velocity: string; // e.g., "3 events per day"
  };

  // Layer 1 Output: Stats
  stats: {
    totalEntities: number;
    unverifiedSources: number;
    missingTimestamps: number;
  };
}

import { Node, Edge } from '@xyflow/react';
import { NodeType, NodeData, AnalysisResult } from '../types';

/**
 * OFFLINE INTELLIGENCE ENGINE (OIE) v2.0
 * 
 * Architecture:
 * Layer 1: Data Conditioning & Statistics (Sanitization)
 * Layer 2: Rule / Heuristic Engine (Reasoning)
 * Layer 3: Pattern & Trend Analysis (Analytics)
 * Layer 4: Graph Clustering (Classical ML)
 * Layer 5: Knowledge-Based Report Generator (Output)
 */

// --- INTERNAL INTERFACES ---
interface ConditionedData {
  nodes: Node[];
  edges: Edge[];
  chronologicalEvents: Node[];
  entitiesById: Map<string, Node>;
  stats: {
    totalNodes: number;
    totalEdges: number;
    missingDates: number;
    totalAmount: number;
  };
}

interface TrendData {
  direction: 'INCREASING' | 'DECREASING' | 'STABLE' | 'BURST';
  eventsPerDay: number;
  timeSpanHours: number;
}

interface ClusterData {
  id: number;
  nodes: Node[];
  dominantType: string;
}

// ============================================================================
// MAIN PIPELINE CONTROLLER
// ============================================================================

export const runLocalAnalysis = (nodes: Node[], edges: Edge[]): any => {
    // 1. Data Conditioning
    const conditioned = conditionData(nodes, edges);

    // 2. Rule & Heuristic Engine
    const heuristics = runHeuristics(conditioned);

    // 3. Pattern & Trend Analysis
    const trends = analyzeTrends(conditioned);

    // 4. Classical ML (Graph Clustering)
    const clusters = runGraphClustering(conditioned);

    // 5. Knowledge-Based Report Generator
    return generateReport(conditioned, heuristics, trends, clusters);
};

// Wrapper for existing UI compatibility
export const generateLocalSummary = (nodes: Node[], edges: Edge[]): AnalysisResult => {
    const rawReport = runLocalAnalysis(nodes, edges);
    return rawReport;
};


// ============================================================================
// LAYER 1: DATA CONDITIONING & STATISTICS
// ============================================================================
function conditionData(nodes: Node[], edges: Edge[]): ConditionedData {
    const entitiesById = new Map<string, Node>();
    let missingDates = 0;
    let totalAmount = 0;

    // Sanitize Nodes
    nodes.forEach(n => {
        entitiesById.set(n.id, n);
        const d = n.data as NodeData;

        // Normalize amounts
        if (d.amount) {
            const val = typeof d.amount === 'string' ? parseFloat(d.amount) : d.amount;
            if (!isNaN(val)) totalAmount += val;
        }

        // Track data quality
        if (n.type === NodeType.EVENT && !d.date) missingDates++;
    });

    // Sort Events Chronologically
    const chronologicalEvents = nodes
        .filter(n => n.type === NodeType.EVENT && (n.data as NodeData).date)
        .sort((a, b) => {
            const da = new Date((a.data as NodeData).date!).getTime();
            const db = new Date((b.data as NodeData).date!).getTime();
            return da - db;
        });

    return {
        nodes,
        edges,
        chronologicalEvents,
        entitiesById,
        stats: {
            totalNodes: nodes.length,
            totalEdges: edges.length,
            missingDates,
            totalAmount
        }
    };
}


// ============================================================================
// LAYER 2: RULE / HEURISTIC ENGINE
// ============================================================================
function runHeuristics(data: ConditionedData) {
    const redFlags: any[] = [];
    const gaps: string[] = [];

    // Rule A: Isolated Subjects (The "Dead End" Heuristic)
    data.nodes.filter(n => n.type === NodeType.PERSON).forEach(p => {
        const isConnected = data.edges.some(e => e.source === p.id || e.target === p.id);
        if (!isConnected) {
            redFlags.push({
                severity: 'MEDIUM',
                type: 'ISOLATED_SUBJECT',
                message: `Subject '${(p.data as NodeData).label}' is isolated (0 connections).`,
            });
            gaps.push(`Establish connection for '${(p.data as NodeData).label}' or verify relevance.`);
        }
    });

    // Rule B: High-Value Financial Anomaly
    if (data.stats.totalAmount > 10000000) { // 10M threshold
        redFlags.push({
            severity: 'HIGH',
            type: 'FINANCIAL_ANOMALY',
            message: `Cumulative transaction value (N${data.stats.totalAmount.toLocaleString()}) exceeds high-risk threshold.`
        });
    }

    // Rule C: Impossible Travel (Velocity Check)
    for (let i = 0; i < data.chronologicalEvents.length - 1; i++) {
        const e1 = data.chronologicalEvents[i];
        const e2 = data.chronologicalEvents[i+1];
        const d1 = e1.data as NodeData;
        const d2 = e2.data as NodeData;

        if (d1.location && d2.location && d1.location !== d2.location) {
            const t1 = new Date(d1.date!).getTime();
            const t2 = new Date(d2.date!).getTime();
            const diffHours = (t2 - t1) / (1000 * 60 * 60);

            // Simple heuristic: If different locations < 2 hours apart
            if (diffHours < 2) {
                 redFlags.push({
                    severity: 'HIGH',
                    type: 'IMPOSSIBLE_TRAVEL',
                    message: `Geographic anomaly: Travel between ${d1.location} and ${d2.location} recorded in ${diffHours.toFixed(1)} hours.`
                });
            }
        }
    }

    // Rule D: Data Integrity Gaps
    if (data.stats.missingDates > 0) {
        gaps.push(`${data.stats.missingDates} events are missing timestamps, preventing timeline reconstruction.`);
    }

    return { redFlags, gaps };
}


// ============================================================================
// LAYER 3: PATTERN & TREND ANALYSIS
// ============================================================================
function analyzeTrends(data: ConditionedData): TrendData {
    if (data.chronologicalEvents.length < 2) {
        return { direction: 'STABLE', eventsPerDay: 0, timeSpanHours: 0 };
    }

    const first = new Date((data.chronologicalEvents[0].data as NodeData).date!).getTime();
    const last = new Date((data.chronologicalEvents[data.chronologicalEvents.length - 1].data as NodeData).date!).getTime();
    const spanDays = (last - first) / (1000 * 60 * 60 * 24);

    // Frequency
    const eventsPerDay = data.chronologicalEvents.length / (spanDays || 1);

    // Burst Detection (Are 50% of events happening in the last 20% of the timeline?)
    let direction: TrendData['direction'] = 'STABLE';

    const midPoint = first + ((last - first) / 2);
    const firstHalfCount = data.chronologicalEvents.filter(n => new Date((n.data as NodeData).date!).getTime() < midPoint).length;
    const secondHalfCount = data.chronologicalEvents.length - firstHalfCount;

    if (secondHalfCount > firstHalfCount * 1.5) direction = 'INCREASING';
    else if (firstHalfCount > secondHalfCount * 1.5) direction = 'DECREASING';

    if (eventsPerDay > 5) direction = 'BURST';

    return {
        direction,
        eventsPerDay,
        timeSpanHours: spanDays * 24
    };
}


// ============================================================================
// LAYER 4: CLASSICAL ML (GRAPH CLUSTERING)
// ============================================================================
// Implementation of Connected Components (BFS)
function runGraphClustering(data: ConditionedData): ClusterData[] {
    const visited = new Set<string>();
    const clusters: ClusterData[] = [];
    let clusterId = 1;

    // Adjacency List for O(1) lookups
    const adj = new Map<string, string[]>();
    data.nodes.forEach(n => adj.set(n.id, []));
    data.edges.forEach(e => {
        adj.get(e.source)?.push(e.target);
        adj.get(e.target)?.push(e.source);
    });

    data.nodes.forEach(node => {
        if (!visited.has(node.id)) {
            const clusterNodes: Node[] = [];
            const queue = [node.id];
            visited.add(node.id);

            while (queue.length > 0) {
                const currId = queue.shift()!;
                const currNode = data.entitiesById.get(currId);
                if (currNode) clusterNodes.push(currNode);

                const neighbors = adj.get(currId) || [];
                neighbors.forEach(neighborId => {
                    if (!visited.has(neighborId)) {
                        visited.add(neighborId);
                        queue.push(neighborId);
                    }
                });
            }

            // Heuristic to name the cluster (Dominant type)
            const personCount = clusterNodes.filter(n => n.type === NodeType.PERSON).length;
            const eventCount = clusterNodes.filter(n => n.type === NodeType.EVENT).length;

            clusters.push({
                id: clusterId++,
                nodes: clusterNodes,
                dominantType: personCount > eventCount ? 'Network' : 'Timeline Sequence'
            });
        }
    });

    return clusters.filter(c => c.nodes.length > 1); // Filter out singletons
}


// ============================================================================
// LAYER 5: KNOWLEDGE-BASED REPORT GENERATOR
// ============================================================================
function generateReport(
    data: ConditionedData, 
    heuristics: { redFlags: any[], gaps: string[] },
    trends: TrendData,
    clusters: ClusterData[]
): AnalysisResult {

    // 1. Construct Narrative Summary
    let summary = `OFFLINE INTELLIGENCE REPORT. `;
    summary += `Analysis of ${data.stats.totalNodes} entities indicates activity is ${trends.direction} with a velocity of ~${trends.eventsPerDay.toFixed(1)} events/day. `;

    if (clusters.length > 1) {
        summary += `The board is fragmented into ${clusters.length} distinct disjoint clusters, suggesting compartmentalized cells or unrelated events. `;
    } else {
        summary += `All entities are interconnected in a single cohesive network. `;
    }

    if (heuristics.redFlags.some(f => f.severity === 'HIGH')) {
        summary += `CRITICAL WARNINGS have been flagged requiring immediate review. `;
    }

    // 2. Format Connections/Clusters for display
    const formattedConnections = clusters.map(c => {
        const labels = c.nodes.slice(0, 3).map(n => (n.data as NodeData).label).join(', ');
        const remainder = c.nodes.length > 3 ? ` and ${c.nodes.length - 3} others` : '';
        return `Cluster ${c.id} (${c.dominantType}): Includes ${labels}${remainder}.`;
    });

    // 3. Assemble Final Object
    return {
        summary,
        gaps: heuristics.gaps,
        redFlags: heuristics.redFlags,
        connections: formattedConnections,
        clusters: clusters.map(c => ({
            id: c.id,
            label: `Group ${c.id}`,
            members: c.nodes.map(n => (n.data as NodeData).label)
        })),
        temporalTrend: {
            direction: trends.direction,
            velocity: `${trends.eventsPerDay.toFixed(1)}/day`
        },
        stats: {
            totalEntities: data.stats.totalNodes,
            unverifiedSources: 0, // Placeholder for future logic
            missingTimestamps: data.stats.missingDates
        }
    };
}

