  // --- HISTORY MANAGEMENT ---
  const [past, setPast] = useState<HistoryState[]>([]);
  const [future, setFuture] = useState<HistoryState[]>([]);

  // --- PERSISTENCE & EXPORT ---
  useEffect(() => {
    const saveData = { nodes, edges };
    localStorage.setItem('intelboard_autosave', JSON.stringify(saveData));
  }, [nodes, edges]);

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    if (params.get('mode') === 'director') {
      setShowDirectorMode(true);
    }
  }, []);

  const handleExportCase = () => {
    const dataStr = JSON.stringify({ nodes, edges, investigationType }, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `case-export-${new Date().toISOString().slice(0, 10)}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    setSimulationToast({ message: 'Case File Saved Successfully', type: 'success' });
    setTimeout(() => setSimulationToast(null), 3000);
  };

  const handleDownloadPDF = () => {
    const currentAnalysis = generateLocalSummary(nodes, edges);

    const doc = new jsPDF();
    const pageWidth = doc.internal.pageSize.getWidth();
    let yPos = 20;
    const margin = 20;
    const contentWidth = pageWidth - (margin * 2);

    // Helper for wrapping text
    const addWrappedText = (text: string, y: number, fontSize: number = 10, isBold: boolean = false) => {
      doc.setFontSize(fontSize);
      doc.setFont("helvetica", isBold ? "bold" : "normal");
      const lines = doc.splitTextToSize(text, contentWidth);
      doc.text(lines, margin, y);
      return y + (lines.length * (fontSize / 2)) + 4; // Return next Y position
    };

    doc.setFontSize(22);
    doc.setTextColor(40, 40, 40);
    doc.text("IntelBoard Investigation Report", pageWidth / 2, yPos, { align: 'center' });
    yPos += 10;
    doc.setFontSize(10);
    doc.setTextColor(100, 100, 100);
    doc.text(`Generated: ${new Date().toLocaleString()}`, pageWidth / 2, yPos, { align: 'center' });
    yPos += 20;
    doc.setLineWidth(0.5);
    doc.setDrawColor(200, 200, 200);
    doc.line(margin, yPos, pageWidth - margin, yPos);
    yPos += 10;

    doc.setFillColor(245, 247, 250);
    doc.rect(margin, yPos, contentWidth, 30, 'F');
    doc.setTextColor(40, 40, 40);
    doc.setFontSize(12);
    doc.text("Executive Summary", margin + 5, yPos + 8);
    doc.setFontSize(10);
    doc.setTextColor(60, 60, 60);
    doc.text(doc.splitTextToSize(currentAnalysis.summary, contentWidth - 10), margin + 5, yPos + 15);
    yPos += 40;

    if (currentAnalysis.gaps && currentAnalysis.gaps.length > 0) {
      doc.setFontSize(14);
      doc.setTextColor(200, 100, 0); 
      doc.text(`Investigative Gaps & Recommendations`, margin, yPos);
      yPos += 10;
      currentAnalysis.gaps.forEach((gap) => {
         if (yPos > 270) { doc.addPage(); yPos = 20; }
         doc.setFontSize(10);
         doc.setTextColor(50, 50, 50);
         doc.circle(margin + 2, yPos - 1, 1, 'F');
         yPos = addWrappedText(gap, yPos, 10);
         yPos += 2;
      });
      yPos += 10;
    }

    if (currentAnalysis.redFlags.length > 0) {
      if (yPos > 260) { doc.addPage(); yPos = 20; }
      doc.setFontSize(14);
      doc.setTextColor(200, 0, 0); 
      doc.text(`Critical Warnings`, margin, yPos);
      yPos += 10;
      currentAnalysis.redFlags.forEach((flag) => {
        if (yPos > 270) { doc.addPage(); yPos = 20; }
        doc.setFontSize(11);
        doc.setTextColor(0, 0, 0);
        doc.setFont("helvetica", "bold");
        doc.text(`• ${flag.type.replace(/_/g, ' ')} [${flag.severity}]`, margin, yPos);
        yPos += 5;
        doc.setFont("helvetica", "normal");
        doc.setTextColor(60, 60, 60);
        yPos = addWrappedText(flag.message, yPos, 10);
        yPos += 5;
      });
      yPos += 10;
    }

    if (currentAnalysis.financialPatterns && currentAnalysis.financialPatterns.length > 0) {
       if (yPos > 260) { doc.addPage(); yPos = 20; }
       doc.setFontSize(14);
       doc.setTextColor(0, 100, 0);
       doc.text("Financial Intelligence", margin, yPos);
       yPos += 10;
       currentAnalysis.financialPatterns.forEach(fin => {
          doc.setFontSize(11);
          doc.setTextColor(0,0,0);
          yPos = addWrappedText(`${fin.description}`, yPos, 10);
          if(fin.amount) {
            doc.setFont("helvetica", "bold");
            doc.text(`Value: N${fin.amount.toLocaleString()}`, margin + 5, yPos - 2);
            doc.setFont("helvetica", "normal");
            yPos += 5;
          }
          yPos += 3;
       });
       yPos += 10;
    }

    if (currentAnalysis.clusters && currentAnalysis.clusters.length > 0) {
       if (yPos > 260) { doc.addPage(); yPos = 20; }
       doc.setFontSize(14);
       doc.setTextColor(0, 0, 0); 
       doc.text("Linked Entities & Groups", margin, yPos);
       yPos += 10;
       currentAnalysis.clusters.forEach((cluster) => {
          doc.setFontSize(11);
          doc.setFont("helvetica", "bold");
          doc.text(`Group ${cluster.id}: ${cluster.label}`, margin, yPos);
