                                   title="Delete"
                                 >
                                   <Trash2 className="w-4 h-4" />
                                 </button>
                              </div>
                           </div>
                         ))
                       )}
                    </div>
                 </div>

              </div>
           </div>
        </div>
      )}

      {/* REPORT INPUT MODAL */}
      {showReportInput && (
