  // NEW: Handle Text to Board
  const handleGenerateBoard = async () => {
    if (!reportText.trim()) return;
    setIsGeneratingBoard(true);
    try {
       const result = await parseNarrativeToBoard(reportText);

       if (result && result.nodes) {
         takeSnapshot();

         const newNodes: Node[] = [];
         const newEdges: Edge[] = [];
         const nodeMap = new Map<string, string>(); // Label -> ID

         // Helper to generate a unique ID
         const genId = () => `ai_node_${Date.now()}_${Math.random().toString(36).substr(2, 5)}`;

         // 1. Create Nodes (Grid Layout)
         result.nodes.forEach((n: any, idx: number) => {
             const newId = genId();
             nodeMap.set(n.label, newId);

             // Simple grid layout logic
             const cols = 4;
             const spacingX = 250;
             const spacingY = 150;
             const x = 100 + (idx % cols) * spacingX;
             const y = 100 + Math.floor(idx / cols) * spacingY;

             newNodes.push({
               id: newId,
               type: n.type,
               position: { x, y },
               data: {
                 label: n.label,
                 description: n.description || '',
                 date: n.date || '',
                 role: n.role || '',
                 personStatus: n.status || 'unknown',
                 location: n.location || '',
                 evidenceSource: 'AI Extracted Report'
               }
             });
         });

         // 2. Create Edges
         if (result.edges) {
           result.edges.forEach((e: any, idx: number) => {
              const srcId = nodeMap.get(e.source_label);
              const tgtId = nodeMap.get(e.target_label);

              if (srcId && tgtId) {
                newEdges.push({
                   id: `ai_edge_${idx}`,
                   source: srcId,
                   target: tgtId,
                   label: e.relation || 'related',
                   type: 'deletable',
                   animated: true,
                   style: { stroke: '#64748b', strokeWidth: 2 } 
                });
              }
           });
         }

         if(newNodes.length > 0) {
            setNodes(newNodes);
            setEdges(newEdges);
            setShowReportInput(false);
            setReportText("");
            setSimulationToast({ message: 'Board Generated from Report', type: 'success' });
            setTimeout(() => setSimulationToast(null), 3000);
         }
       }
    } catch (e) {
      console.error(e);
      alert("Failed to process report. Ensure API Key is valid.");
    } finally {
      setIsGeneratingBoard(false);
    }
  };

