export const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isCheckingAuth, setIsCheckingAuth] = useState(true);

  useEffect(() => {
    const session = localStorage.getItem('intelboard_session');
    if (session === 'active') {
      setIsAuthenticated(true);
    }
    setIsCheckingAuth(false);
  }, []);

  const login = () => {
    localStorage.setItem('intelboard_session', 'active');
    setIsAuthenticated(true);
  };

  const logout = () => {
    localStorage.removeItem('intelboard_session');
    setIsAuthenticated(false);
  };

  if (isCheckingAuth) {
    return <div className="h-screen w-full bg-slate-950 flex items-center justify-center">
      <Loader2 className="w-8 h-8 text-blue-500 animate-spin" />
