  };

  const executeResetBoard = () => {
      takeSnapshot();
      setNodes([]);
      setEdges([]);
      setAnalysis(null);
      setShowAnalysisPanel(false);
      setKidnapAnalysis(null);
      setManualMode('AUTO');
